const demoUsers: QuickLoginUser[] = [
  {
    role: "Admin",
    email: "admin@ayii.edu",
    password: "Admin@2025",
    icon: Shield,
    color: "text-red-600",
    bgColor: "bg-red-50",
    hoverColor: "hover:bg-red-100",
  },
  {
    role: "Lecturer",
    email: "lecturer@ayii.edu",
    password: "Lecturer@2025",
    icon: UserCheck,
    color: "text-red-600",
    bgColor: "bg-red-50",
    hoverColor: "hover:bg-red-100",
  },
  {
    role: "Student",
    email: "student@ayii.edu",
    password: "Student@2025",
    icon: GraduationCap,
    color: "text-green-600",
    bgColor: "bg-green-50",
    hoverColor: "hover:bg-green-100",
  },
];

export default function SignInPage() {
  const [isLoading, setIsLoading] = useState(false);
  const [showPassword, setShowPassword] = useState(false);
  const [currentImageIndex, setCurrentImageIndex] = useState(0);
  const router = useRouter();
  const signIn = useSignIn();

  const form = useForm<LoginFormValues>({
    resolver: zodResolver(loginSchema),
    defaultValues: {
      email: "",
      password: "",
      rememberMe: false,
    },
  });

  // Carousel auto-rotation
  useEffect(() => {
    const interval = setInterval(() => {
      setCurrentImageIndex((prev) => (prev + 1) % defaultCarouselImages.length);
    }, 4000);
    return () => clearInterval(interval);
  }, []);

  const handleQuickLogin = (user: QuickLoginUser) => {
    form.setValue("email", user.email);
    form.setValue("password", user.password);
    toast.success("Demo Credentials Filled", {
      description: `Filled ${user.role} login credentials`,
    });
  };

  async function onSubmit(data: LoginFormValues) {
    try {
      setIsLoading(true);
      await signIn.mutateAsync({
        identifier: data.email,
        password: data.password,
      });
      toast.success("Login Successful", {
        description: "Welcome back!",
      });
    } catch (error: any) {
      toast.error("Login Failed", {
        description: error.message || "Please check your credentials",
      });
    } finally {
      setIsLoading(false);
    }
