  const handleForgotPassword = () => {
    router.push("/auth/forgot-password");
  };

  const handleBackToHome = () => {
    router.push("/");
  };

  return (
    <div className="min-h-screen flex flex-col lg:flex-row">
      {/* Left Side - Dynamic Image Carousel */}
      <div className="hidden lg:flex lg:flex-1 relative overflow-hidden">
        {/* Carousel Images */}
        {defaultCarouselImages.map((image, index) => (
          <div
            key={index}
            className={`absolute inset-0 transition-opacity duration-1000 ease-in-out ${
              index === currentImageIndex ? "opacity-100" : "opacity-0"
            }`}
          >
            <img
              src={image.url}
              alt={image.alt}
              className="w-full h-full object-cover"
              style={{
                filter: "brightness(1.1) contrast(1.05)",
                minHeight: "100%",
                minWidth: "100%",
              }}
            />
          </div>
        ))}

        {/* Gradient Overlay */}
        <div className="absolute inset-0 bg-gradient-to-t from-[#283593]/80 via-[#283593]/15 to-transparent"></div>

        <h2 className="text-4xl font-medium mb-4 drop-shadow-2xl text-start text-white max-w-lg absolute bottom-20 left-20">
          Empowering Students
          <br />
          Through Knowledge
        </h2>

        {/* Content Overlay */}
        <div className="absolute inset-0 flex items-end justify-center p-8">
          <div className="text-start text-white max-w-lg">
            <div className="flex justify-center space-x-2">
              {defaultCarouselImages.map((_, index) => (
                <div
                  key={index}
                  className={`w-5 h-1 rounded-full transition-all duration-300 ${
                    index === currentImageIndex
                      ? "bg-white shadow-lg"
                      : "bg-white/50"
                  }`}
                />
              ))}
            </div>
          </div>
        </div>
      </div>

      {/* Right Side - Login Form */}
      <div className="flex-1 bg-white flex items-center justify-center p-4 sm:p-6 lg:p-8 relative overflow-hidden">
        {/* Decorative Elements */}
        <div className="hidden sm:block">
          <div className="absolute top-20 left-20 text-[#283593]/40 animate-pulse">
            <Star
              className="h-6 w-6 animate-bounce"
              style={{ animationDelay: "0s", animationDuration: "3s" }}
            />
          </div>
          <div className="absolute top-32 right-24 text-[#283593]/40 animate-pulse">
            <BookOpen
              className="h-8 w-8 animate-bounce"
              style={{ animationDelay: "0.5s", animationDuration: "2.5s" }}
            />
          </div>
          <div className="absolute bottom-40 left-16 text-[#283593]/40 animate-pulse">
            <Users
              className="h-7 w-7 animate-bounce"
              style={{ animationDelay: "1s", animationDuration: "3.5s" }}
            />
          </div>
          <div className="absolute bottom-24 right-20 text-[#283593]/40 animate-pulse">
            <Award
              className="h-6 w-6 animate-bounce"
              style={{ animationDelay: "1.5s", animationDuration: "2s" }}
            />
          </div>
          <div className="absolute top-1/2 left-12 text-[#283593]/40 animate-pulse">
            <GraduationCap
              className="h-5 w-5 animate-bounce"
              style={{ animationDelay: "2s", animationDuration: "4s" }}
            />
          </div>
        </div>

        {/* Back to Home Link */}
        <div className="absolute top-4 right-4 sm:top-6 sm:right-6 lg:top-8 lg:right-8">
          <Button
            variant="ghost"
            className="text-gray-600 hover:text-[#283593]/70 hover:bg-gray-100 transition-colors duration-200 text-xs sm:text-sm"
            onClick={handleBackToHome}
          >
            <ArrowLeft className="h-4 w-4 mr-1 sm:mr-2" />
            <span className="hidden sm:inline">Back to Home</span>
            <span className="sm:hidden">Back</span>
          </Button>
        </div>

        <div className="w-full max-w-sm sm:max-w-md pt-2 lg:pt-0">
          {/* Logo and Header */}
          <div className="mb-4 sm:mb-6">
            <div className="flex items-center mb-4 justify-center sm:justify-start">
              <div className="bg-[#283593] p-3 rounded-xl shadow-lg">
                <GraduationCap className="h-8 w-8 text-white" />
              </div>
            </div>
            <h1 className="text-3xl sm:text-3xl font-bold text-gray-800 mb-1 sm:mb-2 text-center sm:text-left">
              AYii University <span className="text-[#283593]">Portal</span>
            </h1>
            <p className="text-sm text-center sm:text-left bg-gradient-to-r from-[#283593] via-[#f76f26] to-[#283593] bg-clip-text text-transparent">
              Sign in to your account
            </p>
          </div>

          {/* Login Form */}
          <div className="space-y-3 sm:space-y-3">
            <Form {...form}>
              <form
                onSubmit={form.handleSubmit(onSubmit)}
                className="space-y-3 sm:space-y-4"
              >
                <FormField
                  control={form.control}
                  name="email"
                  render={({ field }) => (
                    <FormItem>
                      <FormControl>
                        <div className="relative">
                          <Input
                            type="email"
                            placeholder="Email address"
                            className="h-11 sm:h-12 bg-gray-50 border-gray-200 text-gray-800 placeholder:text-gray-500 focus:border-[#283593] focus:ring-[#283593] rounded-lg transition-colors duration-200 text-sm pr-12"
                            {...field}
                          />
                          <Mail className="absolute right-3 sm:right-4 top-1/2 transform -translate-y-1/2 h-4 w-4 sm:h-5 sm:w-5 text-gray-400" />
                        </div>
                      </FormControl>
                      <FormMessage className="text-red-500 text-xs sm:text-sm" />
                    </FormItem>
                  )}
                />

                <FormField
                  control={form.control}
                  name="password"
                  render={({ field }) => (
                    <FormItem>
                      <FormControl>
                        <div className="relative">
                          <Input
                            type={showPassword ? "text" : "password"}
                            placeholder="Password"
                            className="h-11 sm:h-12 bg-gray-50 border-gray-200 text-gray-800 placeholder:text-gray-500 focus:border-[#283593] focus:ring-[#283593] rounded-lg pr-16 sm:pr-20 transition-colors duration-200 text-sm"
                            {...field}
                          />
                          <Lock className="absolute right-10 sm:right-12 top-1/2 transform -translate-y-1/2 h-4 w-4 sm:h-5 sm:w-5 text-gray-400" />
                          <Button
                            type="button"
                            variant="ghost"
                            size="sm"
                            className="absolute right-1 sm:right-2 top-1/2 transform -translate-y-1/2 h-7 w-7 sm:h-8 sm:w-8 p-0 hover:bg-gray-200 text-gray-400 hover:text-gray-600"
                            onClick={() => setShowPassword(!showPassword)}
                          >
                            {showPassword ? (
                              <EyeOff className="h-3 w-3 sm:h-4 sm:w-4" />
                            ) : (
                              <Eye className="h-3 w-3 sm:h-4 sm:w-4" />
                            )}
                          </Button>
                        </div>
                      </FormControl>
                      <FormMessage className="text-red-500 text-xs sm:text-sm" />
                    </FormItem>
                  )}
                />

                {/* Remember Me and Forgot Password */}
                <div className="flex flex-col space-y-2 sm:flex-row sm:items-center sm:justify-between sm:space-y-0">
                  <FormField
                    control={form.control}
                    name="rememberMe"
                    render={({ field }) => (
                      <FormItem className="flex flex-row items-start space-x-2 sm:space-x-3 space-y-0">
                        <FormControl>
                          <Checkbox
                            checked={field.value}
                            onCheckedChange={field.onChange}
                            className="border-gray-300 data-[state=checked]:bg-[#283593] data-[state=checked]:border-[#283593] mt-0.5"
                          />
                        </FormControl>
                        <div className="space-y-1 leading-none">
                          <FormLabel className="text-gray-600 text-xs sm:text-sm font-normal cursor-pointer">
                            Remember me
                          </FormLabel>
                        </div>
                      </FormItem>
                    )}
                  />

                  <Button
                    type="button"
                    variant="link"
                    className="text-[#283593] hover:text-[#283593]/55 p-0 h-auto font-normal text-xs sm:text-sm justify-start sm:justify-center ml-0"
                    onClick={handleForgotPassword}
                  >
                    Forgot password?
                  </Button>
                </div>

                <Button
                  type="submit"
                  className="w-full h-10 sm:h-12 bg-gradient-to-r from-[#283593] via-black to-[#283593] hover:bg-[#283593]/85 text-white font-semibold rounded-sm shadow-lg transition-all duration-200 text-sm sm:text-sm"
                  disabled={isLoading}
                >
                  {isLoading ? (
                    <div className="flex items-center space-x-2">
                      <div className="w-4 h-4 border-2 border-white/30 border-t-white rounded-full animate-spin"></div>
                      <span>Signing in...</span>
                    </div>
                  ) : (
                    "Sign In"
                  )}
                </Button>
              </form>
            </Form>

            {/* Quick Login Buttons */}
            <div className="pt-2">
              <p className="text-center text-gray-500 text-xs sm:text-sm mb-3">
                Quick Demo Login
              </p>
              <div className="grid grid-cols-3 gap-2 sm:gap-3">
                {demoUsers.map((user, index) => {
                  const IconComponent = user.icon;
                  return (
                    <Button
                      key={index}
                      type="button"
                      variant="outline"
                      className={`h-14 sm:h-14 flex flex-col items-center justify-center p-2 rounded-lg border-2 transition-all duration-200 ${user.bgColor} ${user.hoverColor} border-gray-200 hover:border-gray-300 hover:shadow-md`}
                      onClick={() => handleQuickLogin(user)}
                    >
                      <IconComponent
                        className={`h-4 w-4 sm:h-5 sm:w-5 ${user.color} mb-1`}
                      />
                      <span className={`text-xs font-medium ${user.color}`}>
                        {user.role}
                      </span>
                    </Button>
                  );
                })}
              </div>
            </div>
          </div>

          {/* Footer */}
          <div className="mt-4 sm:mt-6 text-center">
            <p className="text-gray-400 text-xs">
              © 2026 AYii University. All rights reserved.
            </p>
          </div>
        </div>
      </div>

      {/* Mobile Background */}
      <div className="lg:hidden absolute inset-0 -z-10">
        <div className="absolute inset-0 bg-gradient-to-br from-[#283593]/5 via-green-50 to-[#283593]/10"></div>
      </div>
    </div>
  );
}

import { NextRequest, NextResponse } from "next/server";
import { requireAuth, validateBody } from "@/lib/api-helpers";
import { prisma } from "@/lib/prisma";
import { UserRole } from "@/lib/generated/prisma";
import { z } from "zod";

const updateLecturerSchema = z.object({
  name: z.string().min(2).optional(),
  email: z.string().email().optional(),
  department: z.string().min(1).optional(),
  specialization: z.string().optional(),
  image: z.string().optional(),
});

export async function PATCH(
  req: NextRequest,
  { params }: { params: Promise<{ id: string }> },
) {
  const { error, session } = await requireAuth([UserRole.ADMIN]);
  if (error) return error;
  const admin = session!.user as any;
  const { id } = await params;

  const validated = await validateBody(req, updateLecturerSchema);
  if ("validationError" in validated) return validated.validationError;
  const { data } = validated;

  const target = await prisma.user.findUnique({ 
    where: { id },
    select: { role: true, email: true } 
  });
  
  if (!target)
    return NextResponse.json({ error: "User not found" }, { status: 404 });
    
  if (target.role !== UserRole.LECTURER)
    return NextResponse.json({ error: "Only lecturer profiles can be updated via this route" }, { status: 403 });

  if (data.email && data.email !== target.email) {
    const emailExists = await prisma.user.findUnique({ where: { email: data.email } });
    if (emailExists) return NextResponse.json({ error: "Email already in use" }, { status: 409 });
  }

  const updated = await prisma.user.update({
    where: { id },
    data,
    select: {
      id: true,
      name: true,
      email: true,
      department: true,
      employeeId: true,
      image: true,
    }
  });

  await prisma.auditLog.create({
    data: {
      adminId: admin.id,
      targetUserId: id,
      action: "UPDATE_LECTURER_PROFILE",
      metadata: { fields: Object.keys(data) },
    },
  });

  return NextResponse.json(updated);
}

export async function DELETE(
  req: NextRequest,
  { params }: { params: Promise<{ id: string }> },
) {
  const { error, session } = await requireAuth([UserRole.ADMIN]);
  if (error) return error;
  const admin = session!.user as any;
  const { id } = await params;

  const target = await prisma.user.findUnique({ 
    where: { id },
    select: { role: true } 
  });

  if (!target)
    return NextResponse.json({ error: "User not found" }, { status: 404 });

  if (target.role !== UserRole.LECTURER)
    return NextResponse.json({ error: "Only lecturer accounts can be deleted via this route" }, { status: 403 });

  await prisma.user.delete({ where: { id } });

  await prisma.auditLog.create({
    data: {
      adminId: admin.id,
      targetUserId: id,
      action: "DELETE_LECTURER",
    },
  });

  return NextResponse.json({ message: "Lecturer deleted successfully" });
}

import { NextRequest, NextResponse } from "next/server";
import {
  requireAuth,
  validateBody,
  generateTempPassword,
} from "@/lib/api-helpers";
import { prisma } from "@/lib/prisma";
import { UserRole } from "@/lib/generated/prisma";
import { sendWelcomeLecturer } from "@/lib/email";
import { hash } from "bcryptjs";
import { z } from "zod";

export async function GET(req: NextRequest) {
  const { error } = await requireAuth([UserRole.ADMIN]);
  if (error) return error;

  const { searchParams } = req.nextUrl;
  const page = Math.max(1, Number(searchParams.get("page") ?? 1));
  const limit = Math.min(50, Number(searchParams.get("limit") ?? 20));
  const search = searchParams.get("search") ?? "";

  const where = {
    role: UserRole.LECTURER,
    ...(search.length >= 3
      ? {
          OR: [
