import { NextRequest, NextResponse } from "next/server";
import { requireAuth, validateBody } from "@/lib/api-helpers";
import { prisma } from "@/lib/prisma";
import { UserRole, UserStatus } from "@/lib/generated/prisma";
import { sendAccountSuspended } from "@/lib/email";
import { createNotification } from "@/lib/notify";
import { z } from "zod";

const schema = z.object({
  action: z.enum(["SUSPEND", "REINSTATE"]),
  reason: z.string().optional(),
});

export async function PATCH(
  req: NextRequest,
  { params }: { params: Promise<{ id: string }> },
) {
  const { error, session } = await requireAuth([UserRole.ADMIN]);
  if (error) return error;
  const admin = session!.user as any;
  const { id } = await params;

  const validated = await validateBody(req, schema);
  if ("validationError" in validated) return validated.validationError;
  const { data } = validated;

  const target = await prisma.user.findUnique({ where: { id } });
  if (!target)
    return NextResponse.json({ error: "User not found" }, { status: 404 });

  const isSuspending = data.action === "SUSPEND";

  await prisma.user.update({
    where: { id },
    data: {
      status: isSuspending ? UserStatus.SUSPENDED : UserStatus.ACTIVE,
      suspensionReason: isSuspending ? (data.reason ?? null) : null,
    },
  });

  await prisma.auditLog.create({
    data: {
      adminId: admin.id,
      targetUserId: id,
      action: isSuspending ? "SUSPEND_USER" : "REINSTATE_USER",
      reason: data.reason,
    },
  });

  if (isSuspending) {
    // Force disconnect via Socket.IO
    const io = (global as any).__socketIO;
    if (io)
      io.to(`user:${id}`).emit("account:suspended", { reason: data.reason });

    // Send email
    sendAccountSuspended({
      to: target.email,
      name: target.name ?? "User",
      reason: data.reason ?? "Policy violation",
    }).catch(console.error);

    await createNotification(
      id,
      "ACCOUNT_STATUS",
      "Account Suspended",
      `Your account has been suspended. Reason: ${data.reason ?? "Contact administration."}`,
    );
  } else {
    await createNotification(
      id,
      "ACCOUNT_STATUS",
      "Account Reinstated",
      "Your account has been reinstated. You can log in again.",
    );
  }

  return NextResponse.json({
    message: `Account ${isSuspending ? "suspended" : "reinstated"}`,
  });
}

import { NextRequest, NextResponse } from "next/server";
import { requireAuth, generateTempPassword } from "@/lib/api-helpers";
import { prisma } from "@/lib/prisma";
import { UserRole } from "@/lib/generated/prisma";
import { sendWelcomeStudent } from "@/lib/email";
import { hash } from "bcryptjs";
import { parse } from "papaparse";
import { z } from "zod";

const rowSchema = z.object({
  name: z.string().min(2),
  email: z.string().email(),
  registrationNumber: z.string().min(3),
  department: z.string().min(1),
  program: z.string().optional(),
});

export async function POST(req: NextRequest) {
  const { error, session } = await requireAuth([UserRole.ADMIN]);
  if (error) return error;
  const admin = session!.user as any;

  const formData = await req.formData();
  const file = formData.get("csv") as File;
  if (!file)
    return NextResponse.json({ error: "CSV file required" }, { status: 400 });

  const text = await file.text();
  const { data: rows, errors: parseErrors } = parse(text, {
    header: true,
    skipEmptyLines: true,
    transformHeader: (h) => h.trim().toLowerCase().replace(/\s+/g, ""),
  });

  if (parseErrors.length > 0) {
    return NextResponse.json(
      { error: "CSV parse error", details: parseErrors },
      { status: 422 },
    );
  }

  // Validate all rows
  const rowErrors: { row: number; field: string; message: string }[] = [];
  const validRows: z.infer<typeof rowSchema>[] = [];

  (rows as any[]).forEach((row, i) => {
    const result = rowSchema.safeParse(row);
    if (!result.success) {
      Object.entries(result.error.flatten().fieldErrors).forEach(
        ([field, msgs]) => {
          rowErrors.push({ row: i + 2, field, message: (msgs as string[])[0] });
        },
      );
    } else {
      validRows.push(result.data);
    }
  });

  if (rowErrors.length > 0) {
    return NextResponse.json(
      { error: "Validation failed", rowErrors },
      { status: 422 },
    );
  }

  // Check bulk uniqueness
  const emails = validRows.map((r) => r.email);
  const regNums = validRows.map((r) => r.registrationNumber);

  const [existingEmails, existingRegNums] = await Promise.all([
    prisma.user.findMany({
      where: { email: { in: emails } },
      select: { email: true },
    }),
    prisma.user.findMany({
      where: { registrationNumber: { in: regNums } },
      select: { registrationNumber: true },
    }),
  ]);

  const emailSet = new Set(existingEmails.map((u) => u.email));
  const regSet = new Set(existingRegNums.map((u) => u.registrationNumber));
  const conflicts: { row: number; field: string; value: string }[] = [];

  validRows.forEach((row, i) => {
    if (emailSet.has(row.email))
      conflicts.push({ row: i + 2, field: "email", value: row.email });
    if (regSet.has(row.registrationNumber))
      conflicts.push({
        row: i + 2,
        field: "registrationNumber",
        value: row.registrationNumber,
      });
  });

  if (conflicts.length > 0) {
    return NextResponse.json(
      { error: "Duplicate conflicts", conflicts },
      { status: 409 },
    );
  }

  // Create all students
  const created: {
    id: string;
    name: string;
    email: string;
    registrationNumber: string;
  }[] = [];

  for (const row of validRows) {
    const tempPassword = generateTempPassword();
    const passwordHash = await hash(tempPassword, 12);

    const student = await prisma.user.create({
      data: {
        ...row,
        role: UserRole.STUDENT,
        isTemporaryPassword: true,
        emailVerified: false,
        accounts: {
          create: {
            accountId: row.email,
            providerId: "credential",
            password: passwordHash,
          },
        },
      },
      select: { id: true, name: true, email: true, registrationNumber: true },
    });

    created.push({
      id: student.id,
      name: student.name!,
      email: student.email,
      registrationNumber: student.registrationNumber!,
    });

    // Queue email (fire-and-forget)
    sendWelcomeStudent({
      to: student.email,
      name: student.name!,
      registrationNumber: row.registrationNumber,
      temporaryPassword: tempPassword,
    }).catch(console.error);
  }

  // Audit log
  await prisma.auditLog.create({
    data: {
      adminId: admin.id,
      action: "BULK_CREATE_STUDENTS",
      metadata: { count: created.length },
    },
  });

  return NextResponse.json(
    { created: created.length, students: created },
    { status: 201 },
  );
}

import { NextRequest, NextResponse } from "next/server";
import {
  requireAuth,
  validateBody,
  generateTempPassword,
} from "@/lib/api-helpers";
import { prisma } from "@/lib/prisma";
import { UserRole } from "@/lib/generated/prisma";
import { sendWelcomeStudent } from "@/lib/email";
import { hash } from "bcryptjs";
import { z } from "zod";

// GET: paginated students list with search
export async function GET(req: NextRequest) {
  const { error, session } = await requireAuth([UserRole.ADMIN]);
  if (error) return error;

  const { searchParams } = req.nextUrl;
  const page = Math.max(1, Number(searchParams.get("page") ?? 1));
  const limit = Math.min(50, Number(searchParams.get("limit") ?? 20));
  const search = searchParams.get("search") ?? "";
  const status = searchParams.get("status") ?? undefined;

  const where = {
    role: UserRole.STUDENT,
    ...(status ? { status: status as any } : {}),
    ...(search.length >= 3
      ? {
          OR: [
            { name: { contains: search, mode: "insensitive" as const } },
            { email: { contains: search, mode: "insensitive" as const } },
            {
              registrationNumber: {
                contains: search,
                mode: "insensitive" as const,
              },
            },
          ],
        }
      : {}),
  };

  const [total, students] = await Promise.all([
    prisma.user.count({ where }),
    prisma.user.findMany({
      where,
      select: {
        id: true,
        name: true,
        email: true,
        registrationNumber: true,
        department: true,
        program: true,
        status: true,
        suspensionReason: true,
        createdAt: true,
        _count: { select: { enrollments: true } },
      },
      orderBy: { createdAt: "desc" },
      skip: (page - 1) * limit,
      take: limit,
    }),
  ]);

  return NextResponse.json({
    data: students,
    meta: { total, page, limit, totalPages: Math.ceil(total / limit) },
  });
}

// POST: create single student
const createStudentSchema = z.object({
  name: z.string().min(2),
  email: z.string().email(),
  registrationNumber: z.string().optional(), // Now optional for auto-generation
  department: z.string().min(1),
  program: z.string().optional(),
});

export async function POST(req: NextRequest) {
  const { error, session } = await requireAuth([UserRole.ADMIN]);
  if (error) return error;
  const admin = session!.user as any;

  const validated = await validateBody(req, createStudentSchema);
  if ("validationError" in validated) return validated.validationError;
  const { data } = validated;

  let registrationNumber = data.registrationNumber;

  // Auto-generate if not provided or doesn't have AYII prefix
  if (!registrationNumber || !registrationNumber.startsWith("AYII/")) {
    const year = new Date().getFullYear();
    const count = await prisma.user.count({
      where: {
        registrationNumber: { startsWith: `AYII/${year}/` },
        role: UserRole.STUDENT
      }
    });
    // Format: AYII/2026/0001
    registrationNumber = `AYII/${year}/${(count + 1).toString().padStart(4, '0')}`;
  }

  // Check uniqueness
  const [emailExists, regExists] = await Promise.all([
    prisma.user.findUnique({ where: { email: data.email } }),
    prisma.user.findUnique({
      where: { registrationNumber: registrationNumber },
    }),
  ]);
  if (emailExists)
    return NextResponse.json(
      { error: "Email already in use" },
      { status: 409 },
    );
  if (regExists)
    return NextResponse.json(
      { error: "Registration number already in use" },
      { status: 409 },
    );

  const finalData = { ...data, registrationNumber: registrationNumber! };

  const tempPassword = generateTempPassword();
  const passwordHash = await hash(tempPassword, 12);

  // Create user + credential account
  const student = await prisma.user.create({
    data: {
      ...finalData,
      role: UserRole.STUDENT,
      isTemporaryPassword: true,
      emailVerified: false,
      accounts: {
        create: {
          accountId: finalData.email,
          providerId: "credential",
          password: passwordHash,
        },
      },
    },
    select: {
      id: true,
      name: true,
      email: true,
      registrationNumber: true,
      department: true,
      createdAt: true,
    },
  });

  // Audit log
  await prisma.auditLog.create({
    data: {
      adminId: admin.id,
      targetUserId: student.id,
      action: "CREATE_STUDENT",
    },
  });

  // Send welcome email (non-blocking)
  sendWelcomeStudent({
    to: student.email,
    name: student.name ?? "Student",
    registrationNumber: student.registrationNumber!,
    temporaryPassword: tempPassword,
  }).catch(console.error);

  return NextResponse.json(student, { status: 201 });
}

import { NextRequest, NextResponse } from "next/server";
import { prisma } from "@/lib/prisma";
import { requireAuth, validateBody } from "@/lib/api-helpers";
import { UserRole, AdmissionStatus } from "@/lib/generated/prisma";
import { z } from "zod";
import bcrypt from "bcryptjs";
import { v4 as uuidv4 } from "uuid";

const reviewSchema = z.object({
  status: z.enum([AdmissionStatus.APPROVED, AdmissionStatus.REJECTED]),
  rejectionReason: z.string().optional(),
});

export async function PATCH(
  req: NextRequest,
  { params }: { params: Promise<{ id: string }> }
) {
  const { error, session } = await requireAuth([UserRole.ADMIN]);
  if (error) return error;
  
  const { id } = await params;
  const validated = await validateBody(req, reviewSchema);
  if ("validationError" in validated) return validated.validationError;
  const { status, rejectionReason } = validated.data;

  try {
    const application = await prisma.admissionApplication.findUnique({
      where: { id },
      include: { course: true }
    });

    if (!application) return NextResponse.json({ error: "Application not found" }, { status: 404 });

    if (status === AdmissionStatus.APPROVED) {
      // 1. Generate random temporary password
      const tempPassword = Math.random().toString(36).slice(-8).toUpperCase();
      const hashedPassword = await bcrypt.hash(tempPassword, 10);
      
      // 2. Generate registration number (e.g., 2026/UG/ADM/001)
      const year = new Date().getFullYear();
      const count = await prisma.user.count({ where: { role: UserRole.STUDENT } });
      const regNo = `${year}/UG/ADM/${(count + 1).toString().padStart(3, '0')}`;

      // 3. Create User & Student Profile in a transaction
      await prisma.$transaction(async (tx) => {
        const user = await tx.user.create({
          data: {
            email: application.email,
            name: application.fullName,
            role: UserRole.STUDENT,
            registrationNumber: regNo,
            isTemporaryPassword: true,
            status: "ACTIVE",
            accounts: {
              create: {
                accountId: uuidv4(),
                providerId: "credentials",
                password: hashedPassword,
              }
            }
          }
        });

        // 4. Automatically enroll in the selected course
        await tx.enrollment.create({
          data: {
            studentId: user.id,
            courseId: application.courseId,
          }
        });

        // 5. Update application
        await tx.admissionApplication.update({
          where: { id },
          data: {
            status: AdmissionStatus.APPROVED,
            approvedAt: new Date(),
          }
        });
      });

      // TODO: In a real app, send actual email here
      console.log(`Sending approval email to ${application.email} with password: ${tempPassword}`);
      
      return NextResponse.json({ message: "Application approved and student created", tempPassword });
    } else {
      // Handle Rejection
      await prisma.admissionApplication.update({
        where: { id },
        data: {
          status: AdmissionStatus.REJECTED,
          rejectionReason,
        }
      });

      return NextResponse.json({ message: "Application rejected" });
    }
  } catch (error: any) {
    if (error.code === 'P2002') {
       return NextResponse.json({ error: "A student with this email already exists" }, { status: 400 });
    }
    console.error("Review error:", error);
    return NextResponse.json({ error: "Internal Server Error" }, { status: 500 });
  }
}

