import { NextRequest, NextResponse } from "next/server";
import { requireAuth } from "@/lib/api-helpers";
import { prisma } from "@/lib/prisma";
import { CourseStatus } from "@/lib/generated/prisma";

export async function GET(req: NextRequest) {
  const { error, session } = await requireAuth();
  if (error) return error;
  const user = session!.user as any;

  const { searchParams } = req.nextUrl;
  const page = Math.max(1, Number(searchParams.get("page") ?? 1));
  const limit = Math.min(50, Number(searchParams.get("limit") ?? 12));
  const search = searchParams.get("search") ?? "";
  const department = searchParams.get("department") ?? undefined;

  const where = {
    status: CourseStatus.ACTIVE,
    ...(department ? { department } : {}),
    ...(search.length >= 3
      ? {
          OR: [
            { title: { contains: search, mode: "insensitive" as const } },
            { unitCode: { contains: search, mode: "insensitive" as const } },
            { department: { contains: search, mode: "insensitive" as const } },
          ],
        }
      : {}),
  };

  const [total, courses] = await Promise.all([
    prisma.course.count({ where }),
    prisma.course.findMany({
      where,
      include: {
        lecturer: { select: { name: true } },
        _count: { select: { enrollments: true } },
        enrollments: {
          where: { studentId: user.id },
          select: { id: true },
        },
      },
      orderBy: { createdAt: "desc" },
      skip: (page - 1) * limit,
      take: limit,
    }),
  ]);

  const data = courses.map((c) => ({
    ...c,
    isEnrolled: c.enrollments.length > 0,
    enrollments: undefined,
  }));

  return NextResponse.json({
    data,
    meta: { total, page, limit, totalPages: Math.ceil(total / limit) },
  });
}

import { NextRequest, NextResponse } from "next/server";
import { requireAuth } from "@/lib/api-helpers";
import { prisma } from "@/lib/prisma";
import { UserRole } from "@/lib/generated/prisma";

export async function GET(
  _: NextRequest,
  { params }: { params: Promise<{ assignmentId: string }> }
) {
  const { error, session } = await requireAuth([UserRole.LECTURER, UserRole.ADMIN]);
  if (error) return error;
  const user = session!.user as any;
  const { assignmentId } = await params;

  const assignment = await prisma.assignment.findUnique({
    where: { id: assignmentId },
  });

  if (!assignment) {
    return NextResponse.json({ error: "Assignment not found" }, { status: 404 });
  }

  // If lecturer, verify they own the course
  if (user.role === UserRole.LECTURER) {
    const course = await prisma.course.findUnique({
      where: { id: assignment.courseId },
    });
    if (course?.lecturerId !== user.id) {
      return NextResponse.json({ error: "Forbidden" }, { status: 403 });
    }
  }

  const submissions = await prisma.submission.findMany({
    where: { assignmentId },
    include: {
      student: {
        select: {
          id: true,
          name: true,
          email: true,
          image: true,
          registrationNumber: true,
        },
      },
    },
    orderBy: { submittedAt: "desc" },
  });

  return NextResponse.json(submissions);
}

import { NextRequest, NextResponse } from "next/server";
import { requireAuth, validateBody } from "@/lib/api-helpers";
import { prisma } from "@/lib/prisma";
import { UserRole } from "@/lib/generated/prisma";
import { z } from "zod";

const schema = z.object({
  title: z.string().min(3),
  instructions: z.string().optional(),
  dueDate: z.string().datetime(),
  fileKey: z.string().optional(),
});

export async function PATCH(
  req: NextRequest,
  { params }: { params: Promise<{ courseId: string; assignmentId: string }> },
) {
  const { error, session } = await requireAuth([UserRole.LECTURER, UserRole.ADMIN]);
  if (error) return error;
  const user = session!.user as any;
  const { courseId, assignmentId } = await params;

  // Verify ownership or admin role
  const assignment = await prisma.assignment.findUnique({
    where: { id: assignmentId },
    include: { course: true },
  });

  if (!assignment)
    return NextResponse.json({ error: "Assignment not found" }, { status: 404 });

  if (user.role === UserRole.LECTURER && assignment.course.lecturerId !== user.id) {
    return NextResponse.json({ error: "Forbidden" }, { status: 403 });
  }

  const validated = await validateBody(req, schema);
  if ("validationError" in validated) return validated.validationError;
  const { data } = validated;

  const updated = await prisma.assignment.update({
    where: { id: assignmentId },
    data: {
      ...data,
      dueDate: new Date(data.dueDate),
    },
  });

  return NextResponse.json(updated);
}

export async function DELETE(
  _: NextRequest,
  { params }: { params: Promise<{ courseId: string; assignmentId: string }> },
) {
  const { error, session } = await requireAuth([UserRole.LECTURER, UserRole.ADMIN]);
  if (error) return error;
  const user = session!.user as any;
  const { courseId, assignmentId } = await params;

  const assignment = await prisma.assignment.findUnique({
    where: { id: assignmentId },
    include: { course: true },
  });

  if (!assignment)
    return NextResponse.json({ error: "Assignment not found" }, { status: 404 });

  if (user.role === UserRole.LECTURER && assignment.course.lecturerId !== user.id) {
    return NextResponse.json({ error: "Forbidden" }, { status: 403 });
  }

  await prisma.assignment.delete({
    where: { id: assignmentId },
  });

  return NextResponse.json({ success: true });
}

import { NextRequest, NextResponse } from "next/server";
import { requireAuth, validateBody } from "@/lib/api-helpers";
import { prisma } from "@/lib/prisma";
import { UserRole } from "@/lib/generated/prisma";
import { createBulkNotifications } from "@/lib/notify";
import { z } from "zod";

const schema = z.object({
  title: z.string().min(3),
  instructions: z.string().optional(),
  dueDate: z.string().datetime(),
  fileKey: z.string().optional(),
});

export async function POST(
  req: NextRequest,
  { params }: { params: Promise<{ courseId: string }> },
) {
  const { error, session } = await requireAuth([UserRole.LECTURER, UserRole.ADMIN]);
  if (error) return error;
  const user = session!.user as any;
  const { courseId } = await params;

  // Verify ownership or admin role
  const course = await prisma.course.findUnique({
    where: { id: courseId },
    include: { enrollments: { select: { studentId: true } } },
  });
  if (!course)
    return NextResponse.json({ error: "Course not found" }, { status: 404 });

  if (user.role === UserRole.LECTURER && course.lecturerId !== user.id) {
    return NextResponse.json({ error: "Forbidden" }, { status: 403 });
  }

  const validated = await validateBody(req, schema);
  if ("validationError" in validated) return validated.validationError;
  const { data } = validated;

  const assignment = await prisma.assignment.create({
    data: {
      ...data,
      dueDate: new Date(data.dueDate),
      courseId,
      createdById: user.id,
    },
  });

  // Notify all enrolled students
  const studentIds = course.enrollments.map((e) => e.studentId);
  if (studentIds.length > 0) {
    createBulkNotifications(
      studentIds,
      "ASSIGNMENT_POSTED",
      `New Assignment: ${data.title}`,
      `A new assignment has been posted in ${course.title}. Due: ${new Date(data.dueDate).toLocaleDateString()}`,
      { assignmentId: assignment.id, courseId },
    ).catch(console.error);

    // Emit Socket.IO event to course room
    const io = (global as any).__socketIO;
    if (io) {
      io.to(`course:${courseId}`).emit("assignment:posted", {
        assignmentId: assignment.id,
        courseId,
        courseTitle: course.title,
        title: data.title,
        dueDate: data.dueDate,
      });
    }
  }

  return NextResponse.json(assignment, { status: 201 });
}

export async function GET(
  _: NextRequest,
  { params }: { params: Promise<{ courseId: string }> },
) {
  const { error, session } = await requireAuth([
    UserRole.LECTURER,
    UserRole.ADMIN,
    UserRole.STUDENT,
  ]);
  if (error) return error;
  const user = session!.user as any;
  const { courseId } = await params;

  const course = await prisma.course.findUnique({
    where: { id: courseId },
    include: {
      enrollments: {
        where: { studentId: user.id },
      },
    },
  });
  if (!course)
    return NextResponse.json({ error: "Course not found" }, { status: 404 });

  if (user.role === UserRole.LECTURER && course.lecturerId !== user.id) {
    return NextResponse.json({ error: "Forbidden" }, { status: 403 });
  }

  if (user.role === UserRole.STUDENT && course.enrollments.length === 0) {
    return NextResponse.json(
      { error: "You are not enrolled in this course" },
      { status: 403 },
    );
  }

  const assignments = await prisma.assignment.findMany({
    where: { courseId },
    include: {
      _count: {
        select: {
          submissions: user.role === UserRole.STUDENT 
            ? { where: { studentId: user.id } } 
            : true,
        },
      },
    },
    orderBy: { createdAt: "desc" },
  });

  return NextResponse.json(assignments);
}

import { NextRequest, NextResponse } from "next/server";
import { requireAuth, validateBody } from "@/lib/api-helpers";
import { prisma } from "@/lib/prisma";
import { UserRole } from "@/lib/generated/prisma";
import { z } from "zod";

export async function GET(
  _: NextRequest,
  { params }: { params: Promise<{ courseId: string }> },
) {
  const { error, session } = await requireAuth([UserRole.LECTURER, UserRole.ADMIN]);
  if (error) return error;
  const user = session!.user as any;
  const { courseId } = await params;

  const course = await prisma.course.findUnique({
    where: { id: courseId },
    include: {
      lecturer: { select: { id: true, name: true, email: true, image: true } },
      _count: { select: { enrollments: true, assignments: true } },
      liveLectures: { where: { status: "LIVE" }, select: { id: true, meetingUrl: true } },
    },
  });

  if (!course)
    return NextResponse.json({ error: "Course not found" }, { status: 404 });

  // Security: check if lecturer owns it, or if it's an admin
  if (user.role === UserRole.LECTURER && course.lecturerId !== user.id) {
    return NextResponse.json({ error: "Forbidden" }, { status: 403 });
  }

  return NextResponse.json(course);
}

const updateSchema = z.object({
  title: z.string().min(3).optional(),
  description: z.string().optional(),
  department: z.string().min(1).optional(),
});

export async function PATCH(
  req: NextRequest,
  { params }: { params: Promise<{ courseId: string }> },
) {
  const { error, session } = await requireAuth([UserRole.LECTURER, UserRole.ADMIN]);
  if (error) return error;
  const user = session!.user as any;
  const { courseId } = await params;

  const course = await prisma.course.findUnique({
    where: { id: courseId },
  });

  if (!course)
    return NextResponse.json({ error: "Course not found" }, { status: 404 });

  // Ownership check
  if (user.role === UserRole.LECTURER && course.lecturerId !== user.id) {
    return NextResponse.json({ error: "Forbidden" }, { status: 403 });
  }

  const validated = await validateBody(req, updateSchema);
  if ("validationError" in validated) return validated.validationError;
  const { data } = validated;

  const updated = await prisma.course.update({
    where: { id: courseId },
    data,
    include: {
      _count: { select: { enrollments: true, assignments: true } },
    },
  });

  return NextResponse.json(updated);
}

export async function DELETE(
  _: NextRequest,
  { params }: { params: Promise<{ courseId: string }> },
) {
  const { error, session } = await requireAuth([UserRole.ADMIN]);
  if (error) return error;
  const { courseId } = await params;

  try {
    await prisma.course.delete({ where: { id: courseId } });
    return NextResponse.json({ success: true });
  } catch (error) {
    return NextResponse.json({ error: "Failed to delete course" }, { status: 500 });
  }
}

import { NextRequest, NextResponse } from "next/server";
import { requireAuth, validateBody } from "@/lib/api-helpers";
import { prisma } from "@/lib/prisma";
import { UserRole } from "@/lib/generated/prisma";
import { z } from "zod";

export async function GET(_: NextRequest) {
  const { error, session } = await requireAuth([UserRole.LECTURER]);
  if (error) return error;
  const user = session!.user as any;

  const courses = await prisma.course.findMany({
    where: { lecturerId: user.id },
    include: {
      _count: { select: { enrollments: true, assignments: true } },
      liveLectures: { where: { status: "LIVE" }, select: { id: true } },
    },
    orderBy: { createdAt: "desc" },
  });

  return NextResponse.json(courses);
}

const createCourseSchema = z.object({
  title: z.string().min(3),
  description: z.string().optional(),
  unitCode: z.string().min(2).toUpperCase(),
  department: z.string().min(1),
  lecturerId: z.string().optional(),
});

export async function POST(req: NextRequest) {
  const { error, session } = await requireAuth([UserRole.LECTURER, UserRole.ADMIN]);
  if (error) return error;
  const user = session!.user as any;

  const validated = await validateBody(req, createCourseSchema);
  if ("validationError" in validated) return validated.validationError;
  const { data } = validated;

  const existing = await prisma.course.findUnique({
    where: { unitCode: data.unitCode },
  });
  if (existing)
    return NextResponse.json(
      { error: "Unit code already exists" },
      { status: 409 },
    );

  // If ADMIN, use provided lecturerId or fallback to user.id (unlikely)
  // If LECTURER, usually use user.id unless they are creating for someone else (not typical)
  const targetLecturerId = data.lecturerId || user.id;

  // Verify target lecturer exists and is a LECTURER
  if (user.role === UserRole.ADMIN && data.lecturerId) {
    const target = await prisma.user.findFirst({
        where: { id: data.lecturerId, role: UserRole.LECTURER }
    });
    if (!target) return NextResponse.json({ error: "Invalid lecturer ID" }, { status: 422 });
  }

  const course = await prisma.course.create({
    data: { 
        title: data.title,
        unitCode: data.unitCode,
        department: data.department,
        description: data.description,
        lecturerId: targetLecturerId 
    },
    include: { _count: { select: { enrollments: true, assignments: true } } },
  });

  return NextResponse.json(course, { status: 201 });
}

import { NextRequest, NextResponse } from "next/server";
import { requireAuth, validateBody } from "@/lib/api-helpers";
import { prisma } from "@/lib/prisma";
import { UserRole } from "@/lib/generated/prisma";
import { z } from "zod";

const schema = z.object({
  grade: z.string().min(1),
  feedback: z.string().optional(),
});

export async function PATCH(
  req: NextRequest,
  { params }: { params: Promise<{ submissionId: string }> }
) {
  const { error, session } = await requireAuth([UserRole.LECTURER, UserRole.ADMIN]);
  if (error) return error;
  const user = session!.user as any;
  const { submissionId } = await params;

  const submission = await prisma.submission.findUnique({
    where: { id: submissionId },
    include: {
      assignment: {
        include: {
          course: true,
        },
      },
    },
  });

  if (!submission) {
    return NextResponse.json({ error: "Submission not found" }, { status: 404 });
  }

  // Verify ownership if lecturer
  if (
    user.role === UserRole.LECTURER &&
    submission.assignment.course.lecturerId !== user.id
  ) {
    return NextResponse.json({ error: "Forbidden" }, { status: 403 });
  }

  const validated = await validateBody(req, schema);
  if ("validationError" in validated) return validated.validationError;
  const { grade, feedback } = validated.data;

  const updated = await prisma.submission.update({
    where: { id: submissionId },
    data: { grade, feedback },
  });

  return NextResponse.json(updated);
}

import { NextRequest, NextResponse } from "next/server";
import { prisma } from "@/lib/prisma";
import { requireAuth, validateBody } from "@/lib/api-helpers";
import { UserRole, LiveLectureStatus } from "@/lib/generated/prisma";
import { z } from "zod";

const lectureSchema = z.object({
  courseId: z.string(),
  meetingUrl: z.string().url(),
});

export async function POST(req: NextRequest) {
  const { error, session } = await requireAuth([UserRole.LECTURER]);
  if (error) return error;

  const validated = await validateBody(req, lectureSchema);
  if ("validationError" in validated) return validated.validationError;

  const { courseId, meetingUrl } = validated.data;
  const lecturerId = session.user.id;

  try {
    // Verify lecturer teaches this course
    const course = await prisma.course.findFirst({
      where: { id: courseId, lecturerId },
    });

    if (!course) {
      return NextResponse.json({ error: "You do not teach this course" }, { status: 403 });
    }

    // End any existing live lectures for this course by this lecturer
    await prisma.liveLecture.updateMany({
      where: { courseId, lecturerId, status: LiveLectureStatus.LIVE },
      data: { status: LiveLectureStatus.ENDED, endedAt: new Date() },
    });

    const lecture = await prisma.liveLecture.create({
      data: {
        courseId,
        lecturerId,
        meetingUrl,
        status: LiveLectureStatus.LIVE,
      },
      include: {
        course: {
          select: { title: true, unitCode: true }
        }
      }
    });

    return NextResponse.json(lecture);
  } catch (err) {
    console.error("Failed to start lecture:", err);
    return NextResponse.json({ error: "Internal Server Error" }, { status: 500 });
  }
}

export async function GET(req: NextRequest) {
  const { error, session } = await requireAuth();
  if (error) return error;

  const user = session.user as any;

  try {
    let lectures;
    if (user.role === UserRole.LECTURER) {
      lectures = await prisma.liveLecture.findMany({
        where: { lecturerId: user.id },
        orderBy: { startedAt: "desc" },
        include: {
          course: { select: { title: true, unitCode: true } }
        }
      });
    } else if (user.role === UserRole.STUDENT) {
      // Fetch lectures for courses the student is enrolled in
      lectures = await prisma.liveLecture.findMany({
        where: {
          status: LiveLectureStatus.LIVE,
          course: {
            enrollments: {
              some: { studentId: user.id }
            }
          }
        },
        orderBy: { startedAt: "desc" },
        include: {
          course: { select: { title: true, unitCode: true } },
          lecturer: { select: { name: true } }
        }
      });
    } else {
      lectures = await prisma.liveLecture.findMany({
        orderBy: { startedAt: "desc" },
        include: {
          course: { select: { title: true, unitCode: true } },
          lecturer: { select: { name: true } }
        }
      });
    }

    return NextResponse.json(lectures);
  } catch (err) {
    console.error("Failed to fetch lectures:", err);
    return NextResponse.json({ error: "Internal Server Error" }, { status: 500 });
  }
}

import { NextRequest, NextResponse } from "next/server";
import { requireAuth, validateBody } from "@/lib/api-helpers";
import { prisma } from "@/lib/prisma";
import { UserRole } from "@/lib/generated/prisma";
import { z } from "zod";

const createBookSchema = z.object({
  title: z.string().min(1),
  author: z.string().min(1),
  category: z.string().min(1),
  description: z.string().optional(),
  coverImage: z.string().optional(),
  fileKey: z.string().min(1),
});

export async function GET(req: NextRequest) {
  const { error } = await requireAuth();
  if (error) return error;

  const { searchParams } = req.nextUrl;
  const page = Math.max(1, Number(searchParams.get("page") ?? 1));
  const limit = 20;
  const search = searchParams.get("search") ?? "";
  const category = searchParams.get("category") ?? undefined;

  const where = {
    ...(category ? { category } : {}),
    ...(search.length >= 2
      ? {
          OR: [
            { title: { contains: search, mode: "insensitive" as const } },
            { author: { contains: search, mode: "insensitive" as const } },
            { category: { contains: search, mode: "insensitive" as const } },
            { description: { contains: search, mode: "insensitive" as const } },
          ],
        }
      : {}),
  };

  const [total, books] = await Promise.all([
    prisma.book.count({ where }),
    prisma.book.findMany({
      where,
      orderBy: { createdAt: "desc" },
      skip: (page - 1) * limit,
      take: limit,
    }),
  ]);

  return NextResponse.json({
    data: books,
    meta: { total, page, limit, totalPages: Math.ceil(total / limit) },
  });
}

export async function POST(req: NextRequest) {
  const { error, session } = await requireAuth([UserRole.ADMIN]);
  if (error) return error;
  const user = session!.user as any;

  const validated = await validateBody(req, createBookSchema);
  if ("validationError" in validated) return validated.validationError;

  const book = await prisma.book.create({
    data: { ...validated.data, uploadedById: user.id },
  });

  return NextResponse.json(book, { status: 201 });
}

