import { NextRequest, NextResponse } from "next/server";
import { requireAuth } from "@/lib/api-helpers";
import { prisma } from "@/lib/prisma";

export async function GET(
  req: NextRequest,
  { params }: { params: Promise<{ partnerId: string }> },
) {
  const { error, session } = await requireAuth();
  if (error) return error;
  const user = session!.user as any;

  const { partnerId } = await params;
  const searchParams = req.nextUrl.searchParams;
  const page = parseInt(searchParams.get("page") || "1");
  const limit = parseInt(searchParams.get("limit") || "50");
  const skip = (page - 1) * limit;

  // Verify partner exists
  const partner = await prisma.user.findUnique({
    where: { id: partnerId },
  });

  if (!partner) {
    return NextResponse.json({ error: "User not found" }, { status: 404 });
  }

  // Get messages between current user and partner
  const [messages, total] = await Promise.all([
    prisma.message.findMany({
      where: {
        OR: [
          { senderId: user.id, receiverId: partnerId },
          { senderId: partnerId, receiverId: user.id },
        ],
      },
      orderBy: { sentAt: "desc" },
      skip,
      take: limit,
      include: {
        sender: {
          select: { id: true, name: true, image: true, role: true },
        },
      },
    }),
    prisma.message.count({
      where: {
        OR: [
          { senderId: user.id, receiverId: partnerId },
          { senderId: partnerId, receiverId: user.id },
        ],
      },
    }),
  ]);

  // Mark messages from partner as read
  await prisma.message.updateMany({
    where: {
      senderId: partnerId,
      receiverId: user.id,
      isRead: false,
    },
    data: { isRead: true },
  });

  // Emit socket event to partner that messages were read
  const io = (global as any).__socketIO;
  if (io) {
    io.to(`user:${partnerId}`).emit("messages:read", {
      readerId: user.id,
    });
  }

  const totalPages = Math.ceil(total / limit);

  return NextResponse.json({
    data: messages.reverse(), // Reverse to show oldest first
    meta: {
      page,
      limit,
      total,
      totalPages,
    },
  });
}

import { NextResponse } from "next/server";
import { requireAuth } from "@/lib/api-helpers";
import { prisma } from "@/lib/prisma";

export async function GET() {
  const { error, session } = await requireAuth();
  if (error) return error;
  const user = session!.user as any;

  // Get all conversations with last message and unread count
  const conversations = await prisma.$queryRaw<any[]>`
    WITH RankedMessages AS (
      SELECT 
        m.*,
        CASE 
          WHEN m."senderId" = ${user.id} THEN m."receiverId"
          ELSE m."senderId"
        END as "partnerId",
        ROW_NUMBER() OVER (
          PARTITION BY 
            CASE 
              WHEN m."senderId" = ${user.id} THEN m."receiverId"
              ELSE m."senderId"
            END
          ORDER BY m."sentAt" DESC
        ) as rn
      FROM "message" m
      WHERE m."senderId" = ${user.id} OR m."receiverId" = ${user.id}
    ),
    UnreadCounts AS (
      SELECT 
        "senderId" as "partnerId",
        COUNT(*) as "unreadCount"
      FROM "message"
      WHERE "receiverId" = ${user.id} AND "isRead" = false
      GROUP BY "senderId"
    )
    SELECT 
      rm."partnerId",
      rm.id as "lastMessageId",
      rm."senderId" as "lastMessageSenderId",
      rm.content as "lastMessageContent",
      rm."sentAt" as "lastMessageSentAt",
      COALESCE(uc."unreadCount", 0)::int as "unreadCount",
      u.id as "userId",
      u.name as "userName",
      u.email as "userEmail",
      u.image as "userImage",
      u.role as "userRole"
    FROM RankedMessages rm
    LEFT JOIN UnreadCounts uc ON uc."partnerId" = rm."partnerId"
    INNER JOIN "user" u ON u.id = rm."partnerId"
    WHERE rm.rn = 1
    ORDER BY rm."sentAt" DESC
  `;

  const formatted = conversations.map((conv) => ({
    partner: {
      id: conv.partnerId,
      name: conv.userName,
      email: conv.userEmail,
      image: conv.userImage,
      role: conv.userRole,
    },
    lastMessage: {
      id: conv.lastMessageId,
      senderId: conv.lastMessageSenderId,
      content: conv.lastMessageContent,
      sentAt: conv.lastMessageSentAt,
    },
    unreadCount: conv.unreadCount,
  }));

  return NextResponse.json(formatted);
}

import { NextRequest, NextResponse } from "next/server";
import { requireAuth, validateBody } from "@/lib/api-helpers";
import { prisma } from "@/lib/prisma";
import { createNotification } from "@/lib/notify";
import { z } from "zod";

const schema = z.object({
  receiverId: z.string().cuid(),
  content: z.string().min(1).max(5000),
});

export async function POST(req: NextRequest) {
  const { error, session } = await requireAuth();
  if (error) return error;
  const user = session!.user as any;

  const validated = await validateBody(req, schema);
  if ("validationError" in validated) return validated.validationError;
  const { data } = validated;

  if (data.receiverId === user.id) {
    return NextResponse.json(
      { error: "Cannot message yourself" },
      { status: 400 },
    );
  }

  const receiver = await prisma.user.findUnique({
    where: { id: data.receiverId },
  });
  if (!receiver)
    return NextResponse.json({ error: "Recipient not found" }, { status: 404 });

  const message = await prisma.message.create({
    data: {
      senderId: user.id,
      receiverId: data.receiverId,
      content: data.content,
    },
    include: {
      sender: { select: { id: true, name: true, image: true, role: true } },
    },
  });

  // Emit via Socket.IO
  const io = (global as any).__socketIO;
  if (io) {
    io.to(`user:${data.receiverId}`).emit("message:new", {
      ...message,
      conversationPartnerId: user.id,
    });
  }

  // Notification
  createNotification(
    data.receiverId,
    "MESSAGE",
    `New message from ${user.name}`,
    data.content.substring(0, 100),
    { senderId: user.id, messageId: message.id },
  ).catch(console.error);

  return NextResponse.json(message, { status: 201 });
}

