});

const academicSchema = z.object({
  previousSchool: z.string().min(3, "Institution name is required"),
  highestQualification: z.string().min(2, "Qualification description is required"),
  resultsSummary: z.string().min(10, "Please provide a more detailed summary"),
});

const documentSchema = z.object({
  academicDocs: z.array(z.string()).min(1, "At least one academic artifact is required"),
});

const steps = [
  { title: "Personal", icon: User, description: "Contact information" },
  { title: "Academic", icon: BookOpen, description: "Educational history" },
  { title: "Documents", icon: FileText, description: "Academic proof" },
  { title: "Verification", icon: ShieldCheck, description: "Review & Submit" }
];

export default function ApplicationFormPage() {
  const { courseId } = useParams();
  const router = useRouter();
  const [currentStep, setCurrentStep] = useState(0);
  const [loading, setLoading] = useState(false);
  const [course, setCourse] = useState<any>(null);
  const [errors, setErrors] = useState<Record<string, string>>({});
  
  const [formData, setFormData] = useState({
    fullName: "",
    email: "",
    phone: "",
    previousSchool: "",
    highestQualification: "",
    resultsSummary: "",
    academicDocs: [] as string[]
  });

  useEffect(() => {
    fetch(`/api/courses/public`)
      .then(res => res.json())
      .then(data => {
        const found = data.find((c: any) => c.id === courseId);
        if (found) setCourse(found);
      });
  }, [courseId]);

  const validateStep = (stepIdx: number) => {
    try {
      if (stepIdx === 0) personalSchema.parse(formData);
      if (stepIdx === 1) academicSchema.parse(formData);
      if (stepIdx === 2) documentSchema.parse(formData);
      setErrors({});
      return true;
    } catch (err) {
      if (err instanceof z.ZodError) {
        const newErrors: Record<string, string> = {};
        err.issues.forEach((e: z.ZodIssue) => {
          if (e.path[0]) newErrors[e.path[0] as string] = e.message;
        });
        setErrors(newErrors);
        toast.error("Validation failed. Please review your entries.");
      }
      return false;
    }
  };

  const handleNext = () => {
    if (validateStep(currentStep)) {
      if (currentStep < steps.length - 1) {
        setCurrentStep(curr => curr + 1);
        window.scrollTo(0, 0);
      }
    }
  };

  const handleBack = () => {
    if (currentStep > 0) {
      setCurrentStep(curr => curr - 1);
      window.scrollTo(0, 0);
    }
  };

  const handleSubmit = async () => {
    try {
      setLoading(true);
      const res = await fetch("/api/admissions", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          courseId,
          ...formData,
          academicRecords: {
            school: formData.previousSchool,
            qualification: formData.highestQualification,
            summary: formData.resultsSummary
          }
        })
      });

      if (!res.ok) throw new Error("Synchronization failed");

      toast.success("Institutional Enrollment Synchronized");
      router.push("/courses");
    } catch (error) {
      toast.error("Process Interrupted. Please try again.");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="min-h-screen bg-[#fcfdfe]">
      <Header />
      
      <main className="pb-32">
        {/* Dynamic Hero Section */}
        <section className="relative overflow-hidden bg-gradient-to-b from-black via-black to-gray-950 pt-32 pb-48 text-white">
          <div className="absolute inset-0 opacity-20 [mask-image:radial-gradient(ellipse_at_center,transparent_20%,black)] bg-[url('https://www.transparenttextures.com/patterns/carbon-fibre.png')]"></div>
          <div className="container relative z-10 mx-auto px-6 lg:px-12 text-center">
            <motion.div
              initial={{ opacity: 0, y: 20 }}
              animate={{ opacity: 1, y: 0 }}
              transition={{ duration: 0.6 }}
            >
              <Badge className="mb-6 bg-primary/20 text-primary border-primary/30 text-[10px] font-black uppercase tracking-[0.3em] px-5 py-1.5 backdrop-blur-xl">
                Institutional Admissions Portal 2026/27
              </Badge>
              <h1 className="text-5xl lg:text-7xl font-black tracking-tighter mb-8 leading-[0.9]">
                Initiate Your <br />
                <span className="text-transparent bg-clip-text bg-gradient-to-r from-primary via-red-400 to-primary/80 animate-gradient-x">Academic Ascent</span>
              </h1>
              <div className="flex flex-col items-center gap-4">
                <div className="flex items-center gap-3 bg-white/5 backdrop-blur-xl border border-white/10 px-6 py-2.5 rounded-2xl">
                   <div className="h-2 w-2 rounded-full bg-green-500 animate-pulse" />
                   <p className="text-[12px] font-black uppercase tracking-widest text-gray-300">
                     Synchronizing For: <span className="text-white">{course?.title || "Academic Unit Selection"}</span>
                   </p>
                </div>
              </div>
            </motion.div>
          </div>
        </section>

        <div className="container mx-auto px-6 lg:px-12 -mt-24 relative z-20 max-w-5xl">
          {/* Glassmorphism Stepper */}
          <div className="bg-white/70 backdrop-blur-3xl border border-white/40 shadow-2xl shadow-gray-200/50 rounded-[2.5rem] p-8 mb-12">
            <div className="relative flex justify-between">
              {/* Progress Line */}
              <div className="absolute top-5 left-8 right-8 h-[2px] bg-gray-100 -z-10" />
              <motion.div 
                className="absolute top-5 left-8 h-[2px] bg-primary -z-10 shadow-[0_0_15px_rgba(37,99,235,0.4)]" 
                animate={{ width: `calc(${currentStep * 33.33}% - 0px)` }}
                transition={{ duration: 0.8, ease: "circOut" }}
              />
              
              {steps.map((step, idx) => (
                <div key={idx} className="flex flex-col items-center gap-3 group relative">
                  <motion.div 
                    onClick={() => idx < currentStep && setCurrentStep(idx)}
                    className={cn(
                      "h-10 w-10 rounded-2xl flex items-center justify-center transition-all duration-500 border-2 z-20 cursor-pointer overflow-hidden relative",
                      idx <= currentStep ? "border-primary text-white shadow-xl" : "bg-white text-gray-300 border-gray-100"
                    )}
                    animate={{
                      backgroundColor: idx === currentStep ? "#000" : (idx < currentStep ? "#10b981" : "#fff"),
                      scale: idx === currentStep ? 1.15 : 1,
                      borderColor: idx <= currentStep ? "transparent" : "#f3f4f6"
                    }}
                  >
                    {idx < currentStep ? <Check className="h-5 w-5" /> : <step.icon className="h-4 w-4" />}
                  </motion.div>
                  <div className="text-center">
                    <p className={cn(
                      "text-[10px] font-black uppercase tracking-[0.2em] transition-colors duration-500",
                      idx === currentStep ? "text-black" : "text-gray-400"
                    )}>
                      {step.title}
                    </p>
                  </div>
                </div>
              ))}
            </div>
          </div>

          <Card className="border-none shadow-[0_40px_100px_-20px_rgba(0,0,0,0.12)] bg-white rounded-[3rem] overflow-hidden">
            <CardContent className="p-0">
              <AnimatePresence mode="wait">
                <motion.div
                  key={currentStep}
                  initial={{ opacity: 0, x: 20 }}
                  animate={{ opacity: 1, x: 0 }}
                  exit={{ opacity: 0, x: -20 }}
                  transition={{ duration: 0.4, ease: "circOut" }}
                  className="p-10 lg:p-16"
                >
                  {currentStep === 0 && (
                    <div className="space-y-12">
                      <div className="flex items-center gap-4">
                        <div className="h-14 w-14 rounded-3xl bg-primary/5 flex items-center justify-center border border-primary/10">
                          <User className="h-6 w-6 text-primary" />
                        </div>
                        <div>
                          <h2 className="text-2xl font-black text-black tracking-tight">Identity Synthesis</h2>
                          <p className="text-[11px] font-bold text-gray-400 uppercase tracking-widest">Digital Registry Protocol</p>
                        </div>
                      </div>
                      
                      <div className="grid md:grid-cols-2 gap-10">
                        <div className="space-y-3">
                          <Label className="text-[11px] font-black uppercase text-gray-500 tracking-widest ml-1">Full Identity Name</Label>
                          <Input 
                            className={cn(
                              "h-14 px-6 border-gray-100 focus:ring-4 focus:ring-primary/5 focus:border-primary/30 rounded-2xl text-[13px] font-medium transition-all bg-gray-50/30",
                              errors.fullName && "border-red-500 bg-red-50/30"
                            )}
                            placeholder="Primary Candidate Identifier..."
                            value={formData.fullName}
                            onChange={e => setFormData({...formData, fullName: e.target.value})}
                          />
                          {errors.fullName && <p className="text-[10px] font-bold text-red-500 uppercase tracking-widest ml-1">{errors.fullName}</p>}
                        </div>
                        <div className="space-y-3">
                          <Label className="text-[11px] font-black uppercase text-gray-500 tracking-widest ml-1">Communication Path (Email)</Label>
                          <Input 
                            className={cn(
                              "h-14 px-6 border-gray-100 focus:ring-4 focus:ring-primary/5 focus:border-primary/30 rounded-2xl text-[13px] font-medium transition-all bg-gray-50/30",
                              errors.email && "border-red-500 bg-red-50/30"
                            )}
                            placeholder="Institutional Correspondence Address..."
                            value={formData.email}
                            onChange={e => setFormData({...formData, email: e.target.value})}
                          />
                          {errors.email && <p className="text-[10px] font-bold text-red-500 uppercase tracking-widest ml-1">{errors.email}</p>}
                        </div>
                        <div className="space-y-3 md:col-span-2">
                          <Label className="text-[11px] font-black uppercase text-gray-500 tracking-widest ml-1">Telecommunication Uplink (Phone)</Label>
                          <Input 
                            className={cn(
                              "h-14 px-6 border-gray-100 focus:ring-4 focus:ring-primary/5 focus:border-primary/30 rounded-2xl text-[13px] font-medium transition-all bg-gray-50/30",
                              errors.phone && "border-red-500 bg-red-50/30"
                            )}
                            placeholder="International Access Code + Number..."
                            value={formData.phone}
                            onChange={e => setFormData({...formData, phone: e.target.value})}
                          />
                          {errors.phone && <p className="text-[10px] font-bold text-red-500 uppercase tracking-widest ml-1">{errors.phone}</p>}
                        </div>
                      </div>
                    </div>
                  )}

                  {currentStep === 1 && (
                    <div className="space-y-12">
                      <div className="flex items-center gap-4">
                        <div className="h-14 w-14 rounded-3xl bg-primary/5 flex items-center justify-center border border-primary/10">
                          <BookOpen className="h-6 w-6 text-primary" />
                        </div>
                        <div>
                          <h2 className="text-2xl font-black text-black tracking-tight">Academic Base</h2>
                          <p className="text-[11px] font-bold text-gray-400 uppercase tracking-widest">Heritage Qualification Verification</p>
                        </div>
                      </div>

                      <div className="space-y-10">
                        <div className="space-y-3">
                          <Label className="text-[11px] font-black uppercase text-gray-500 tracking-widest ml-1">Preceding Academic Center</Label>
                          <Input 
                            className={cn(
                              "h-14 px-6 border-gray-100 focus:ring-4 focus:ring-primary/5 focus:border-primary/30 rounded-2xl text-[13px] font-medium transition-all bg-gray-50/30",
                              errors.previousSchool && "border-red-500 bg-red-50/30"
                            )}
                            placeholder="Search Secondary Institution Directory..."
                            value={formData.previousSchool}
                            onChange={e => setFormData({...formData, previousSchool: e.target.value})}
                          />
                          {errors.previousSchool && <p className="text-[10px] font-bold text-red-500 uppercase tracking-widest ml-1">{errors.previousSchool}</p>}
                        </div>
                        <div className="space-y-3">
                          <Label className="text-[11px] font-black uppercase text-gray-500 tracking-widest ml-1">Apex Certification Level</Label>
                          <Input 
                            className={cn(
                              "h-14 px-6 border-gray-100 focus:ring-4 focus:ring-primary/5 focus:border-primary/30 rounded-2xl text-[13px] font-medium transition-all bg-gray-50/30",
                              errors.highestQualification && "border-red-500 bg-red-50/30"
                            )}
                            placeholder="e.g. KCSE / Cambridge International..."
                            value={formData.highestQualification}
                            onChange={e => setFormData({...formData, highestQualification: e.target.value})}
                          />
                          {errors.highestQualification && <p className="text-[10px] font-bold text-red-500 uppercase tracking-widest ml-1">{errors.highestQualification}</p>}
                        </div>
                        <div className="space-y-3">
                          <Label className="text-[11px] font-black uppercase text-gray-500 tracking-widest ml-1">Performance Performance Metrics</Label>
                          <Textarea 
                            className={cn(
                              "min-h-[160px] border-gray-100 focus:ring-4 focus:ring-primary/5 focus:border-primary/30 rounded-3xl text-[13px] font-medium transition-all p-6 resize-none bg-gray-50/30",
                              errors.resultsSummary && "border-red-500 bg-red-50/30"
                            )}
                            placeholder="Detailed breakdown of academic assets and accomplishments..."
                            value={formData.resultsSummary}
                            onChange={e => setFormData({...formData, resultsSummary: e.target.value})}
                          />
                          {errors.resultsSummary && <p className="text-[10px] font-bold text-red-500 uppercase tracking-widest ml-1">{errors.resultsSummary}</p>}
                        </div>
                      </div>
                    </div>
                  )}

                  {currentStep === 2 && (
                    <div className="space-y-12">
                      <div className="flex items-center gap-4">
                        <div className="h-14 w-14 rounded-3xl bg-primary/5 flex items-center justify-center border border-primary/10">
                          <FileText className="h-6 w-6 text-primary" />
                        </div>
                        <div>
                          <h2 className="text-2xl font-black text-black tracking-tight">Institutional Artifacts</h2>
                          <p className="text-[11px] font-bold text-gray-400 uppercase tracking-widest">Document Shield Synchronization</p>
                        </div>
                      </div>

                      <div className="space-y-10">
                         <div className="bg-primary/5 p-8 rounded-[2rem] border border-primary/10 flex items-start gap-6 relative overflow-hidden">
                           <div className="absolute top-0 right-0 p-4 opacity-5">
                             <Sparkles className="h-24 w-24 text-primary" />
                           </div>
                           <AlertCircle className="h-6 w-6 text-primary mt-1 shrink-0" />
                           <div>
                             <p className="text-[13px] text-primary font-black uppercase tracking-widest mb-2">High-Fidelity Requirement</p>
                             <p className="text-xs text-gray-600 font-medium leading-relaxed max-w-lg">
                               Please synchronize high-resolution captures of identification and academic qualifications. Supported: PDF / JPEG / PNG (Limit: 10MB per object).
                             </p>
                           </div>
                         </div>
                         
                         <div className="grid gap-6">
                            <Label className="text-[11px] font-black uppercase text-gray-400 tracking-[0.2em] text-center mb-4">Uplink Artifacts To Institutional Cloud</Label>
                            <R2ImageUpload 
                              value={""}
                              onChange={(url, file: any) => {
                                if (file?.key) {
                                  setFormData(prev => ({...prev, academicDocs: [...prev.academicDocs, file.key]}));
                                }
                              }}
                              identifier={`admission-${courseId}-${Date.now()}`}
                              category={FileCategory.DOCUMENT}
                              variant="default"
                            />
                            
                            {errors.academicDocs && <p className="text-[10px] font-bold text-red-500 uppercase tracking-widest text-center">{errors.academicDocs}</p>}

                            {formData.academicDocs.length > 0 && (
                              <div className="grid grid-cols-2 lg:grid-cols-4 gap-4 mt-8">
                                {formData.academicDocs.map((doc, i) => (
                                  <motion.div 
                                    initial={{ scale: 0.8, opacity: 0 }}
                                    animate={{ scale: 1, opacity: 1 }}
                                    key={i} 
                                    className="bg-white border border-gray-100 p-4 rounded-2xl flex items-center gap-3 shadow-lg shadow-gray-100/20 group"
                                  >
                                    <div className="h-8 w-8 rounded-lg bg-green-50 flex items-center justify-center">
                                      <Check className="h-4 w-4 text-green-500" />
                                    </div>
                                    <span className="text-[9px] font-black text-gray-500 uppercase">Asset_{i+1}</span>
                                  </motion.div>
                                ))}
                              </div>
                            )}
                         </div>
                      </div>
                    </div>
                  )}

                  {currentStep === 3 && (
                    <div className="space-y-12 text-center">
                      <div className="relative inline-block">
                         <motion.div 
                           initial={{ scale: 0 }}
                           animate={{ scale: 1 }}
                           className="mx-auto h-24 w-24 rounded-[2rem] bg-black flex items-center justify-center mb-8 shadow-2xl shadow-gray-400/40"
                         >
                           <ShieldCheck className="h-10 w-10 text-white" />
                         </motion.div>
                         <motion.div 
                           animate={{ scale: [1, 1.2, 1], opacity: [0.5, 0.2, 0.5] }}
                           transition={{ repeat: Infinity, duration: 2 }}
                           className="absolute inset-0 bg-primary/20 rounded-[2rem] -z-10"
                         />
                      </div>
                      
                      <div>
                        <h2 className="text-3xl font-black text-black mb-3 tracking-tighter">Final Synthesis Audit</h2>
                        <p className="text-[13px] font-bold text-gray-400 uppercase tracking-widest max-w-md mx-auto">
                          Perform a rigorous audit of your parameters before institutional synchronization.
                        </p>
                      </div>
                      
                      <div className="grid gap-6 max-w-xl mx-auto text-left p-10 bg-gray-50/50 rounded-[2.5rem] border border-gray-100">
                        <div className="flex justify-between items-center group cursor-default">
                          <span className="text-[10px] font-black text-gray-400 uppercase tracking-[0.2em] group-hover:text-primary transition-colors">Digital Identity</span>
                          <span className="text-[13px] font-black text-black uppercase">{formData.fullName}</span>
                        </div>
                        <div className="flex justify-between items-center group cursor-default">
                          <span className="text-[10px] font-black text-gray-400 uppercase tracking-[0.2em] group-hover:text-primary transition-colors">Communication Route</span>
                          <span className="text-[13px] font-black text-black">{formData.email}</span>
                        </div>
                        <div className="flex justify-between items-center group cursor-default">
                          <span className="text-[10px] font-black text-gray-400 uppercase tracking-[0.2em] group-hover:text-primary transition-colors">Institutional Choice</span>
                          <span className="text-[13px] font-black text-primary uppercase">{course?.title}</span>
                        </div>
                        <div className="flex justify-between items-center group cursor-default">
                          <span className="text-[10px] font-black text-gray-400 uppercase tracking-[0.2em] group-hover:text-primary transition-colors">Artifact Integrity</span>
                          <Badge className="bg-green-500 hover:bg-green-600 text-white border-0 text-[10px] font-black uppercase px-4 py-1 rounded-lg">
                            {formData.academicDocs.length} Assets Verified
                          </Badge>
                        </div>
                      </div>
                    </div>
                  )}
                  
                  <div className="flex items-center justify-between mt-20 pt-12 border-t border-gray-50">
                    <Button 
                      variant="ghost" 
                      onClick={handleBack}
                      disabled={currentStep === 0 || loading}
                      className="text-[11px] font-black uppercase tracking-[0.2em] text-gray-400 hover:text-black gap-3 h-14 px-10 rounded-2xl transition-all hover:bg-gray-50"
                    >
                      <ArrowLeft className="h-4 w-4" /> Previous Protocol
                    </Button>
                    
                    {currentStep < steps.length - 1 ? (
                      <Button 
                        onClick={handleNext}
                        className="bg-black hover:bg-primary text-white text-[11px] font-black uppercase tracking-[0.2em] gap-3 h-14 px-12 rounded-2xl shadow-xl shadow-gray-200 transition-all hover:scale-[1.02] active:scale-95 group"
                      >
                        Advance Component <ArrowRight className="h-4 w-4 group-hover:translate-x-1 transition-transform" />
                      </Button>
                    ) : (
                      <Button 
                        disabled={loading}
                        onClick={handleSubmit}
                        className="bg-primary hover:bg-primary/90 text-white text-[11px] font-black uppercase tracking-[0.3em] gap-4 h-14 px-16 rounded-2xl shadow-2xl shadow-primary/30 transition-all hover:scale-[1.05] active:scale-95"
                      >
                        {loading ? <Loader2 className="h-5 w-5 animate-spin" /> : <Sparkles className="h-5 w-5" />}
                        Finalize Synchronization
                      </Button>
                    )}
                  </div>
                </motion.div>
              </AnimatePresence>
            </CardContent>
          </Card>
        </div>
      </main>
      <Footer />
    </div>
  );
}

"use client";

import React, { useEffect, useState } from "react";
import { 
  BookOpen, 
  Search, 
  MapPin, 
  Clock, 
  Users, 
  ArrowRight, 
  GraduationCap,
  Star,
  ChevronRight,
  Loader2
} from "lucide-react";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Card, CardContent, CardFooter, CardHeader, CardTitle } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Avatar, AvatarFallback, AvatarImage } from "@/components/ui/avatar";
import Link from "next/link";
import { cn } from "@/lib/utils";
import Header from "@/components/frontend/Header";
import Footer from "@/components/frontend/Footer";

export default function PublicCoursesPage() {
  const [courses, setCourses] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);
  const [searchTerm, setSearchTerm] = useState("");

  useEffect(() => {
    fetch("/api/courses/public")
      .then(res => res.json())
      .then(data => {
        setCourses(data);
        setLoading(false);
      })
      .catch(err => {
        console.error(err);
        setLoading(false);
      });
  }, []);

  const filteredCourses = courses.filter(course => 
    course.title.toLowerCase().includes(searchTerm.toLowerCase()) ||
    course.unitCode.toLowerCase().includes(searchTerm.toLowerCase()) ||
    course.department.toLowerCase().includes(searchTerm.toLowerCase())
  );

  if (loading) {
    return (
      <div className="flex h-screen items-center justify-center bg-[#fcfdfe]">
        <div className="flex flex-col items-center gap-4">
          <Loader2 className="h-10 w-10 animate-spin text-primary" />
          <p className="text-[11px] font-black uppercase tracking-[0.2em] text-gray-400">Synchronizing Institutional Assets...</p>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-[#fcfdfe]">
      <Header />
      <main>
        <section className="relative overflow-hidden bg-gradient-to-b from-black via-black to-gray-950 py-24 text-white lg:py-32">
          <div className="absolute inset-0 opacity-20 [mask-image:radial-gradient(ellipse_at_center,transparent_20%,black)] bg-[url('https://www.transparenttextures.com/patterns/carbon-fibre.png')]"></div>
          <div className="container relative z-10 mx-auto px-6 lg:px-12 text-center">
            <Badge className="mb-6 bg-primary/20 text-primary border-primary/30 text-[10px] font-black uppercase tracking-[0.3em] px-5 py-1.5 backdrop-blur-xl">
              Institutional Course Directory 2026
            </Badge>
            <h1 className="text-5xl lg:text-7xl font-black tracking-tighter mb-8 leading-[0.9]">
              Architecting The <br />
              <span className="text-transparent bg-clip-text bg-gradient-to-r from-primary via-red-400 to-primary/80 animate-gradient-x">Future of Learning</span>
            </h1>
            <p className="max-w-2xl mx-auto text-[13px] font-bold text-gray-400 uppercase tracking-widest leading-relaxed mb-12">
              Explore our curated selection of high-performance academic units designed to elevate professional capacity and technical mastery.
            </p>
            
            <div className="max-w-xl mx-auto relative group">
              <Search className="absolute left-5 top-1/2 -translate-y-1/2 h-5 w-5 text-gray-500 group-focus-within:text-primary transition-colors" />
              <Input 
                placeholder="Query Department, Unit Code or Course Title..." 
                className="h-14 pl-14 pr-6 bg-white/5 border-white/10 text-white rounded-2xl focus-visible:ring-primary/20 focus-visible:border-primary/30 text-[13px] font-medium backdrop-blur-xl transition-all"
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
              />
            </div>
          </div>
        </section>

        {/* Course Grid */}
        <div className="container mx-auto px-6 lg:px-12 -mt-10 relative z-20">
          <div className="grid gap-8 md:grid-cols-2 lg:grid-cols-3">
            {filteredCourses.map((course) => (
              <Card key={course.id} className="border-none shadow-2xl shadow-gray-200/40 bg-white rounded-[2rem] overflow-hidden hover:ring-2 hover:ring-primary/10 transition-all group flex flex-col">
                <CardHeader className="p-0 relative h-56 overflow-hidden">
                  <div className="absolute inset-0 bg-gradient-to-t from-black via-black/20 to-transparent z-10"></div>
                  <img 
                    src={`https://images.unsplash.com/photo-1523050335392-93851179ae09?q=80&w=800&auto=format&fit=crop&sig=${course.id}`} 
                    alt={course.title}
                    className="absolute inset-0 w-full h-full object-cover group-hover:scale-105 transition-transform duration-1000"
                  />
                  <div className="absolute top-6 left-6 z-20">
                    <Badge className="bg-white/10 text-white border-white/20 text-[10px] font-black uppercase tracking-[0.2em] px-4 py-1.5 backdrop-blur-xl">
                      {course.unitCode}
                    </Badge>
                  </div>
                  <div className="absolute bottom-6 left-6 z-20 right-6">
                     <h2 className="text-xl font-black text-white tracking-tight leading-[1.1] mb-1">{course.title}</h2>
                     <p className="text-[10px] font-bold text-red-300 uppercase tracking-widest leading-none">{course.department}</p>
                  </div>
                </CardHeader>
                
                <CardContent className="p-8 flex-1">
                  <div className="flex items-center gap-3 mb-6">
                    <Avatar className="h-8 w-8 rounded-xl border border-gray-100 shadow-sm">
                      <AvatarImage src={course.lecturer?.image || ""} />
                      <AvatarFallback className="bg-primary/5 text-primary text-[10px] font-black">
                        {course.lecturer?.name?.[0] || 'L'}
                      </AvatarFallback>
                    </Avatar>
                    <div>
                      <p className="text-[9px] font-black text-gray-400 uppercase tracking-widest leading-none mb-1">Director of Studies</p>
                      <p className="text-[11px] font-black text-black">{course.lecturer?.name || "Senior Faculty"}</p>
                    </div>
                  </div>

                  <p className="text-[13px] font-bold text-gray-500 mb-8 line-clamp-2 leading-relaxed h-10">
                    {course.description || "Comprehensive academic exploration of institutional fundamentals and strategic paradigms."}
                  </p>

                  <div className="grid grid-cols-2 gap-4">
                    <div className="flex items-center gap-3 px-4 py-3 bg-gray-50 rounded-2xl border border-gray-100 transition-colors group-hover:bg-gray-100/50">
                      <Users className="h-4 w-4 text-primary" />
                      <div>
                        <p className="text-[11px] font-black text-black leading-none">{course._count?.enrollments || 0}</p>
                        <p className="text-[8px] font-black text-gray-400 uppercase tracking-widest mt-0.5">Agents</p>
                      </div>
                    </div>
                    <div className="flex items-center gap-3 px-4 py-3 bg-gray-50 rounded-2xl border border-gray-100 transition-colors group-hover:bg-gray-100/50">
                      <Star className="h-4 w-4 text-orange-500" />
                      <div>
                        <p className="text-[11px] font-black text-black leading-none">4.9</p>
                        <p className="text-[8px] font-black text-gray-400 uppercase tracking-widest mt-0.5">Rating</p>
                      </div>
                    </div>
                  </div>
                </CardContent>
                
                <CardFooter className="p-8 pt-0 mt-auto">
                  <Link href={`/apply/${course.id}`} className="w-full">
                    <Button className="w-full h-12 bg-black hover:bg-primary text-white text-[11px] font-black uppercase tracking-[0.2em] rounded-2xl shadow-xl shadow-gray-200/50 transition-all gap-3 group/btn">
                      Initiate Application
                      <ChevronRight className="h-4 w-4 group-hover/btn:translate-x-1 transition-transform" />
                    </Button>
                  </Link>
                </CardFooter>
              </Card>
            ))}
          </div>

          {filteredCourses.length === 0 && (
            <div className="py-24 text-center">
              <div className="inline-flex h-20 w-20 items-center justify-center rounded-3xl bg-gray-50 mb-6">
                <BookOpen className="h-10 w-10 text-gray-200" />
              </div>
              <h3 className="text-xl font-black text-black mb-2 tracking-tight">Zero Academic Units Found</h3>
              <p className="text-[13px] font-bold text-gray-400 uppercase tracking-widest max-w-sm mx-auto">
                Your query did not synchronize with our institutional directory. Please refine your search parameters.
              </p>
            </div>
          )}
        </div>
      </main>
      <Footer />
    </div>
  );
}

"use client";

import React, { useState, useEffect } from "react";
import { 
  ShieldCheck, 
  Search, 
  Filter, 
  Clock, 
  User, 
  CheckCircle2, 
  AlertCircle,
  XCircle,
  Loader2,
  ExternalLink,
  ChevronRight,
  GraduationCap,
  FileBadge,
  MoreHorizontal,
  Mail,
  Phone,
  CheckSquare,
  Square,
  Trash2,
  ThumbsUp,
  ThumbsDown,
  Layers
} from "lucide-react";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Card, CardContent } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Avatar, AvatarFallback } from "@/components/ui/avatar";
import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs";
import { 
  Dialog, 
  DialogContent, 
  DialogHeader, 
  DialogTitle, 
  DialogDescription,
  DialogFooter
} from "@/components/ui/dialog";
import { Textarea } from "@/components/ui/textarea";
import { Checkbox } from "@/components/ui/checkbox";
import { toast } from "sonner";
import { cn } from "@/lib/utils";

export default function AdminAdmissionsPage() {
  const [applications, setApplications] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);
  const [searchTerm, setSearchTerm] = useState("");
  const [selectedApp, setSelectedApp] = useState<any>(null);
  const [isDetailsOpen, setIsDetailsOpen] = useState(false);
  const [isRejectOpen, setIsRejectOpen] = useState(false);
  const [rejectionReason, setRejectionReason] = useState("");
  const [processing, setProcessing] = useState(false);
  const [selectedIds, setSelectedIds] = useState<string[]>([]);
  const [activeTab, setActiveTab] = useState("PENDING");

  useEffect(() => {
    fetchApplications();
  }, []);

  const fetchApplications = async () => {
    setLoading(true);
    try {
      const res = await fetch("/api/admissions");
      const data = await res.json();
      setApplications(data || []);
    } catch (error) {
      toast.error("Failed to synchronize applications");
    } finally {
      setLoading(false);
    }
  };

  const handleReview = async (id: string, status: string, reason?: string) => {
    const previousApps = [...applications];
    setApplications(apps => apps.map(app => 
      app.id === id ? { ...app, status, rejectionReason: reason || null } : app
    ));

    try {
      setProcessing(true);
      const res = await fetch(`/api/admissions/${id}/review`, {
        method: "PATCH",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ status, rejectionReason: reason })
      });

      const data = await res.json();
      if (!res.ok) throw new Error(data.error || "Review failed");

      toast.success(status === "APPROVED" ? "Institutional Credentials Dispatched" : "Application Decoupled");
      setIsDetailsOpen(false);
      setIsRejectOpen(false);
      fetchApplications();
    } catch (error: any) {
      setApplications(previousApps);
      toast.error(error.message);
    } finally {
      setProcessing(false);
    }
  };

  const handleBulkAction = async (status: string) => {
    if (!selectedIds.length) return;
    
    setProcessing(true);
    let successCount = 0;
    
    try {
      for (const id of selectedIds) {
        const res = await fetch(`/api/admissions/${id}/review`, {
          method: "PATCH",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify({ status })
        });
        if (res.ok) successCount++;
      }
      toast.success(`Bulk Processing Complete: ${successCount} Synchronization(s) Successful`);
      setSelectedIds([]);
      fetchApplications();
    } catch (error) {
      toast.error("Bulk processing interrupted");
    } finally {
      setProcessing(false);
    }
  };

  const toggleSelect = (id: string) => {
    setSelectedIds(prev => 
      prev.includes(id) ? prev.filter(i => i !== id) : [...prev, id]
    );
  };

  const toggleSelectAll = () => {
    const currentTabApps = applications.filter(a => a.status === activeTab);
    if (selectedIds.length === currentTabApps.length && currentTabApps.length > 0) {
      setSelectedIds([]);
    } else {
      setSelectedIds(currentTabApps.map(a => a.id));
    }
  };

  const filteredApps = Array.isArray(applications) ? applications.filter(app => 
    app.fullName?.toLowerCase().includes(searchTerm.toLowerCase()) ||
    app.email?.toLowerCase().includes(searchTerm.toLowerCase()) ||
    app.course?.title?.toLowerCase().includes(searchTerm.toLowerCase())
  ) : [];

  const getStatusBadge = (status: string) => {
    switch (status) {
      case "PENDING": return <Badge className="bg-orange-50 text-orange-600 border border-orange-100 text-[9px] font-black uppercase px-3 py-1 rounded-lg gap-2"><Clock className="h-3 w-3" /> Awaiting Audit</Badge>;
      case "APPROVED": return <Badge className="bg-green-50 text-green-600 border border-green-100 text-[9px] font-black uppercase px-3 py-1 rounded-lg gap-2"><CheckCircle2 className="h-3 w-3" /> System Approved</Badge>;
      case "REJECTED": return <Badge className="bg-red-50 text-red-600 border border-red-100 text-[9px] font-black uppercase px-3 py-1 rounded-lg gap-2"><XCircle className="h-3 w-3" /> De-synchronized</Badge>;
      default: return null;
    }
  };

  if (loading) {
    return (
      <div className="flex h-[80vh] items-center justify-center">
        <Loader2 className="h-8 w-8 animate-spin text-primary" />
      </div>
    );
  }

  return (
    <div className="flex-1 flex flex-col p-6 lg:p-8 space-y-8 bg-[#fcfdfe] min-h-screen relative">
      {/* Institutional Header */}
      <header className="flex flex-col gap-4 sm:flex-row sm:items-center sm:justify-between border-b border-gray-100 pb-8">
        <div className="flex items-center gap-4">
          <div className="p-3 bg-primary/5 rounded-2xl">
            <ShieldCheck className="h-7 w-7 text-primary" />
          </div>
          <div>
            <h1 className="text-2xl font-black tracking-tight text-black">Admissions Ledger</h1>
            <p className="text-[11px] text-gray-500 font-bold uppercase tracking-[0.2em] mt-1 italic">
              Academic Unit Onboarding & Synchronization
            </p>
          </div>
        </div>
        <div className="flex items-center gap-4">
           <Badge className="bg-black text-white border-0 text-[10px] font-black uppercase px-5 py-2 rounded-xl shadow-lg shadow-gray-200">
             {applications.filter(a => a.status === "PENDING").length} Pending Audits
           </Badge>
        </div>
      </header>

      <Tabs defaultValue="PENDING" onValueChange={setActiveTab} className="w-full">
        <div className="flex flex-col sm:flex-row gap-6 items-center justify-between mb-8">
          <TabsList className="bg-gray-100/50 p-1 rounded-xl border border-gray-100 italic h-10">
            {[
              { id: "PENDING", label: "Pending" },
              { id: "APPROVED", label: "Approved" },
              { id: "REJECTED", label: "Rejected" }
            ].map((tab) => {
              const count = applications.filter(a => a.status === tab.id).length;
              return (
                <TabsTrigger 
                  key={tab.id} 
                  value={tab.id}
                  className="rounded-lg px-6 text-[10px] font-black uppercase tracking-widest transition-all data-[state=active]:bg-white data-[state=active]:text-primary data-[state=active]:shadow-sm h-full gap-2"
                >
                  {tab.label}
                  <span className={cn(
                    "ml-1 px-1.5 py-0.5 rounded-md text-[9px] font-bold border",
                    activeTab === tab.id 
                      ? "bg-primary/10 border-primary/20 text-primary" 
                      : "bg-gray-200/50 border-gray-300/30 text-gray-500"
                  )}>
                    {count}
                  </span>
                </TabsTrigger>
              );
            })}
          </TabsList>

          <div className="flex items-center gap-4 w-full sm:w-auto">
            <div className="relative w-full sm:w-80 group">
              <Search className="absolute left-4 top-1/2 -translate-y-1/2 h-3.5 w-3.5 text-gray-400 font-bold" />
              <Input 
                placeholder="Search candidate registry..." 
                className="pl-10 h-10 text-[12px] border-gray-100 bg-white shadow-none rounded-xl focus:border-primary/30 focus:ring-primary/5 transition-all font-medium"
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
              />
            </div>
            {activeTab === "PENDING" && (
              <Button 
                variant="outline" 
                onClick={toggleSelectAll}
                className="h-10 px-4 rounded-xl text-[10px] font-black uppercase tracking-widest border-gray-100 hover:bg-gray-50"
              >
                {selectedIds.length > 0 ? "De-select All" : "Select All"}
              </Button>
            )}
          </div>
        </div>

        {["PENDING", "APPROVED", "REJECTED"].map((status) => (
          <TabsContent key={status} value={status} className="mt-0 outline-none">
             <div className="grid gap-5">
               {filteredApps.filter(app => app.status === status).length > 0 ? (
                 filteredApps.filter(app => app.status === status).map((app) => (
                   <Card key={app.id} className={cn(
                     "border-none shadow-xl shadow-gray-200/40 bg-white rounded-[2rem] overflow-hidden transition-all group relative",
                     selectedIds.includes(app.id) && "ring-2 ring-primary ring-offset-2"
                   )}>
                     <CardContent className="p-0">
                       <div className="flex flex-col lg:flex-row lg:items-center p-6 gap-6">
                         {status === "PENDING" && (
                           <div className="flex items-center justify-center">
                             <Checkbox 
                               checked={selectedIds.includes(app.id)}
                               onCheckedChange={() => toggleSelect(app.id)}
                               className="h-5 w-5 rounded-lg data-[state=checked]:bg-primary data-[state=checked]:border-primary"
                             />
                           </div>
                         )}
                         
                         <div className="flex items-center gap-4 flex-1 min-w-0">
                           <Avatar className="h-12 w-12 rounded-2xl border border-gray-100 shadow-sm bg-gray-50 flex items-center justify-center shrink-0">
                             <AvatarFallback className="text-gray-400 font-black text-xs">
                               {(app.fullName || "??").split(" ").map((n: string) => n[0]).join("")}
                             </AvatarFallback>
                           </Avatar>
                           <div className="min-w-0">
                             <h3 className="text-[15px] font-black text-black truncate tracking-tight">{app.fullName}</h3>
                             <div className="flex items-center gap-2 mt-0.5">
                               <span className="text-[10px] font-bold text-gray-400 uppercase tracking-widest truncate">{app.email}</span>
                             </div>
                           </div>
                         </div>

                         <div className="flex items-center gap-8 px-8 border-l border-gray-50 flex-1">
                           <div className="flex flex-col">
                             <p className="text-[9px] font-black text-gray-400 uppercase tracking-[0.2em] mb-1">Target Academic Unit</p>
                             <span className="text-[12px] font-black text-black">{app.course?.title}</span>
                           </div>
                           <div className="hidden xl:flex flex-col">
                             <p className="text-[9px] font-black text-gray-400 uppercase tracking-[0.2em] mb-1">Sync Date</p>
                             <span className="text-[12px] font-black text-black">{new Date(app.createdAt).toLocaleDateString()}</span>
                           </div>
                         </div>

                         <div className="flex items-center justify-between lg:justify-end gap-4 flex-1">
                           {status === "PENDING" ? (
                             <>
                               <Button 
                                 size="sm"
                                 onClick={() => { setSelectedApp(app); setIsRejectOpen(true); }}
                                 className="h-10 w-10 p-0 text-red-500 hover:text-white bg-red-50 hover:bg-red-500 rounded-xl border-none transition-all"
                               >
                                 <ThumbsDown className="h-4 w-4" />
                               </Button>
                               <Button 
                                 size="sm"
                                 onClick={() => handleReview(app.id, "APPROVED")}
                                 className="h-10 w-10 p-0 text-green-600 hover:text-white bg-green-50 hover:bg-green-600 rounded-xl border-none transition-all"
                               >
                                 <ThumbsUp className="h-4 w-4" />
                               </Button>
                               <div className="h-8 w-px bg-gray-50 mx-2" />
                             </>
                           ) : (
                             <div className="mr-auto">{getStatusBadge(app.status)}</div>
                           )}
                           
                           <Button 
                             onClick={() => { setSelectedApp(app); setIsDetailsOpen(true); }}
                             variant="ghost"
                             className="h-10 px-5 text-[10px] font-black uppercase tracking-widest text-gray-400 hover:text-primary hover:bg-primary/5 rounded-xl transition-all gap-2"
                           >
                             View Audit <ChevronRight className="h-4 w-4" />
                           </Button>
                         </div>
                       </div>
                     </CardContent>
                   </Card>
                 ))
               ) : (
                 <div className="py-24 text-center bg-white rounded-[2rem] border-2 border-dashed border-gray-100">
                    <div className="h-16 w-16 rounded-3xl bg-gray-50 flex items-center justify-center mx-auto mb-6">
                      <Layers className="h-8 w-8 text-gray-200" />
                    </div>
                    <h3 className="text-lg font-black text-black mb-1 tracking-tight">Registry Empty</h3>
                    <p className="text-[11px] font-bold text-gray-400 uppercase tracking-widest max-w-sm mx-auto italic">
                      No candidate profiles detected in the {status.toLowerCase()} synchronization queue.
                    </p>
                 </div>
               )}
             </div>
          </TabsContent>
        ))}
      </Tabs>

      {/* Sticky Bulk Action Bar */}
      {selectedIds.length > 0 && (
        <div className="fixed bottom-8 left-1/2 -translate-x-1/2 z-50 animate-in slide-in-from-bottom-8 duration-500">
          <div className="bg-black text-white px-8 py-4 rounded-[1.5rem] shadow-2xl shadow-primary/20 flex items-center gap-8 border border-white/10 backdrop-blur-xl">
             <div className="flex items-center gap-3 border-r border-white/10 pr-8">
               <div className="h-7 w-7 rounded-lg bg-primary flex items-center justify-center font-black text-xs">
                 {selectedIds.length}
               </div>
               <span className="text-[10px] font-black uppercase tracking-widest">Candidates Selected</span>
             </div>
             <div className="flex items-center gap-4">
               <Button 
                 disabled={processing}
                 onClick={() => handleBulkAction("APPROVED")}
                 className="bg-white hover:bg-green-500 text-black hover:text-white h-10 px-6 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all gap-2"
               >
                 {processing ? <Loader2 className="h-3 w-3 animate-spin" /> : <ThumbsUp className="h-3 w-3" />}
                 Bulk Approve
               </Button>
               <Button 
                 variant="ghost"
                 disabled={processing}
                 onClick={() => { /* Bulk rejection would need a reason modal, keeping it simple for now or adding a default 'Bulk Rejected' */ handleBulkAction("REJECTED"); }}
                 className="h-10 px-6 rounded-xl text-[10px] font-black uppercase tracking-widest text-red-400 hover:text-red-500 hover:bg-red-500/10 transition-all gap-2"
               >
                 <ThumbsDown className="h-3 w-3" />
                 Bulk Reject
               </Button>
               <Button 
                 variant="ghost"
                 onClick={() => setSelectedIds([])}
                 className="h-10 px-4 rounded-xl text-[10px] font-black uppercase tracking-widest text-gray-400 hover:text-white transition-all ml-2"
               >
                 Cancel
               </Button>
             </div>
          </div>
        </div>
      )}

      {/* Audit Details Modal */}
      <Dialog open={isDetailsOpen} onOpenChange={setIsDetailsOpen}>
        <DialogContent className="sm:max-w-[700px] p-0 overflow-hidden border-none shadow-2xl rounded-[2rem] bg-[#fcfdfe]">
          <DialogHeader className="p-8 pb-4 bg-black text-white rounded-t-[2rem]">
            <div className="flex justify-between items-start">
              <div>
                <DialogTitle className="text-xl font-black tracking-tight">Audit Protocol: Profile Verification</DialogTitle>
                <DialogDescription className="text-gray-400 font-bold uppercase text-[9px] mt-1 tracking-widest italic">Institutional Archive Synchronization</DialogDescription>
              </div>
              {selectedApp && getStatusBadge(selectedApp.status)}
            </div>
          </DialogHeader>

          <div className="p-8 space-y-8 max-h-[70vh] overflow-y-auto custom-scrollbar">
             <div className="grid md:grid-cols-2 gap-8">
               <div className="space-y-6">
                 <div>
                   <h4 className="text-[10px] font-black uppercase text-gray-400 tracking-widest mb-3 border-b border-gray-100 pb-2 italic">Identity Synthesis</h4>
                   <div className="space-y-4">
                     <div>
                       <p className="text-[9px] font-bold text-gray-400 uppercase tracking-widest">Full Entity Name</p>
                       <p className="text-[13px] font-black text-black uppercase">{selectedApp?.fullName}</p>
                     </div>
                     <div className="flex gap-10">
                        <div>
                          <p className="text-[9px] font-bold text-gray-400 uppercase tracking-widest">Digital Route</p>
                          <p className="text-[12px] font-bold text-black">{selectedApp?.email}</p>
                        </div>
                        <div>
                          <p className="text-[9px] font-bold text-gray-400 uppercase tracking-widest">Comm Uplink</p>
                          <p className="text-[12px] font-bold text-black">{selectedApp?.phone}</p>
                        </div>
                     </div>
                   </div>
                 </div>

                 <div>
                   <h4 className="text-[10px] font-black uppercase text-gray-400 tracking-widest mb-3 border-b border-gray-100 pb-2 italic">Academic Heritage</h4>
                   <div className="space-y-4">
                     <div>
                       <p className="text-[9px] font-bold text-gray-400 uppercase tracking-widest">Preceding Institution</p>
                       <p className="text-[13px] font-black text-black uppercase">{selectedApp?.academicRecords?.school}</p>
                     </div>
                     <div>
                       <p className="text-[9px] font-bold text-gray-400 uppercase tracking-widest">Attained Certification</p>
                       <p className="text-[13px] font-black text-black uppercase">{selectedApp?.academicRecords?.qualification}</p>
                     </div>
                     <div>
                       <p className="text-[9px] font-bold text-gray-400 uppercase tracking-widest">Performance Metadata</p>
                       <p className="text-[12px] font-medium text-gray-600 leading-relaxed italic border-l-2 border-primary/20 pl-4 py-1">"{selectedApp?.academicRecords?.summary}"</p>
                     </div>
                   </div>
                 </div>
               </div>

               <div className="space-y-6">
                 <div>
                   <h4 className="text-[10px] font-black uppercase text-gray-400 tracking-widest mb-3 border-b border-gray-100 pb-2 italic">Institutional Artifacts</h4>
                   <div className="grid gap-3">
                     {selectedApp?.academicDocs?.map((doc: string, i: number) => (
                       <a 
                         key={i} 
                         href={`/api/r2/download?key=${doc}`} 
                         target="_blank" 
                         className="flex items-center justify-between p-4 bg-white rounded-xl border border-gray-100 hover:border-primary/30 hover:bg-primary/5 transition-all group"
                       >
                         <div className="flex items-center gap-3">
                            <div className="h-8 w-8 rounded-lg bg-gray-50 flex items-center justify-center group-hover:bg-white transition-colors">
                              <FileBadge className="h-4 w-4 text-gray-400 group-hover:text-primary" />
                            </div>
                            <span className="text-[10px] font-black text-gray-600 uppercase tracking-widest">Artifact_Sync_{i+1}</span>
                         </div>
                         <ExternalLink className="h-3 w-3 text-gray-300 group-hover:text-primary" />
                       </a>
                     ))}
                     {(!selectedApp?.academicDocs || selectedApp.academicDocs.length === 0) && (
                       <div className="p-8 text-center bg-gray-50 rounded-2xl border border-dashed border-gray-200">
                         <AlertCircle className="h-5 w-5 text-gray-300 mx-auto mb-2" />
                         <p className="text-[9px] font-black text-gray-400 uppercase tracking-[0.2em]">Zero Evidence Detected</p>
                       </div>
                     )}
                   </div>
                 </div>
                 
                 {selectedApp?.status === "REJECTED" && (
                   <div className="p-5 bg-red-50 rounded-2xl border border-red-100">
                     <p className="text-[9px] font-black text-red-600 uppercase tracking-widest mb-2 italic">De-sync Logic Exception</p>
                     <p className="text-[12px] font-bold text-red-800 leading-relaxed italic border-l-2 border-red-300 pl-4">{selectedApp.rejectionReason}</p>
                   </div>
                 )}
               </div>
             </div>
          </div>

          <DialogFooter className="p-6 bg-white border-t border-gray-100 rounded-b-[2rem] gap-4">
            {selectedApp?.status === "PENDING" && (
              <div className="flex items-center gap-3 w-full">
                <Button 
                  disabled={processing}
                  onClick={() => setIsRejectOpen(true)}
                  variant="ghost" 
                  className="h-11 px-6 text-[10px] font-black uppercase tracking-widest text-red-500 hover:bg-red-50 rounded-xl transition-all"
                >
                  Reject Candidate
                </Button>
                <Button 
                  disabled={processing}
                  onClick={() => handleReview(selectedApp.id, "APPROVED")}
                  className="h-11 px-8 bg-black hover:bg-green-600 text-white text-[10px] font-black uppercase tracking-widest rounded-xl shadow-xl shadow-gray-200 transition-all gap-2 flex-grow sm:flex-grow-0"
                >
                  {processing ? <Loader2 className="h-3 w-3 animate-spin" /> : <ThumbsUp className="h-3 w-3" />}
                  Approve Application
                </Button>
                <Button 
                  variant="outline" 
                  onClick={() => setIsDetailsOpen(false)}
                  className="h-11 px-6 text-[10px] font-black uppercase tracking-widest border-gray-100 rounded-xl transition-all ml-auto"
                >
                  Exit Audit
                </Button>
              </div>
            )}
            {selectedApp?.status !== "PENDING" && (
              <Button 
                variant="outline" 
                onClick={() => setIsDetailsOpen(false)}
                className="h-11 px-8 text-[10px] font-black uppercase tracking-widest border-gray-100 rounded-xl transition-all ml-auto"
              >
                Close Folder
              </Button>
            )}
          </DialogFooter>
        </DialogContent>
      </Dialog>

      {/* Rejection Dialog */}
      <Dialog open={isRejectOpen} onOpenChange={setIsRejectOpen}>
        <DialogContent className="sm:max-w-[400px] rounded-[2rem] p-8 border-none shadow-2xl bg-white">
          <DialogHeader>
            <DialogTitle className="text-xl font-black tracking-tight">Sync Exception Logic</DialogTitle>
            <DialogDescription className="text-[10px] font-black text-gray-400 uppercase tracking-[0.2em] mt-1 italic">Candidate Rejection Parameters</DialogDescription>
          </DialogHeader>
          <div className="py-6">
            <Label className="text-[9px] font-black uppercase text-gray-400 tracking-widest mb-3 block ml-1">Formal Audit Discrepancy</Label>
            <Textarea 
              className="min-h-[140px] rounded-2xl border-gray-100 focus:border-red-500 transition-all text-[13px] font-medium p-5 resize-none bg-gray-50/30"
              placeholder="e.g. Incomplete documentation artifacts detected..."
              value={rejectionReason}
              onChange={e => setRejectionReason(e.target.value)}
            />
          </div>
          <DialogFooter className="gap-3">
             <Button variant="ghost" onClick={() => setIsRejectOpen(false)} className="rounded-xl h-11 text-[10px] font-black uppercase transition-all">Cancel</Button>
             <Button 
               disabled={!rejectionReason || processing}
               onClick={() => handleReview(selectedApp.id, "REJECTED", rejectionReason)}
               className="bg-red-600 hover:bg-red-700 text-white rounded-xl h-11 px-8 text-[10px] font-black uppercase shadow-lg shadow-red-200 transition-all"
             >
               Finalize Exception
             </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>
    </div>
  );
}

"use client";

import { useState } from "react";
import { Button } from "@/components/ui/button";
