"use client";

import { useState, useEffect, useRef } from "react";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Avatar, AvatarFallback, AvatarImage } from "@/components/ui/avatar";
import { Send, Search, Check, CheckCheck, Loader2, Plus, X } from "lucide-react";
import { EmptyState } from "@/components/shared/EmptyState";
import { useConversations, useMessageThread, useSendMessage } from "@/hooks/useMessages";
import { useMe } from "@/hooks/useAuth";
import { useUserSearch } from "@/hooks/useUserSearch";
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogTrigger,
} from "@/components/ui/dialog";

export default function MessagesPage() {
  const [selectedPartnerId, setSelectedPartnerId] = useState<string | null>(null);
  const [message, setMessage] = useState("");
  const [searchTerm, setSearchTerm] = useState("");
  const [newMessageOpen, setNewMessageOpen] = useState(false);
  const [userSearchQuery, setUserSearchQuery] = useState("");
  const [selectedUserFromSearch, setSelectedUserFromSearch] = useState<any>(null);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  const { data: me } = useMe();
  const { data: conversations, isLoading: loadingConversations } = useConversations();
  const { data: messagesData, isLoading: loadingMessages, fetchNextPage, hasNextPage } = useMessageThread(selectedPartnerId || "");
  const sendMessageMutation = useSendMessage();
  const { data: searchResults, isLoading: searchingUsers } = useUserSearch(userSearchQuery);

  const messages = messagesData?.pages.flatMap(page => page.data) || [];

  // Get selected partner info - either from conversations or from search results
  const selectedConversation = conversations?.find((conv: any) => conv.partner.id === selectedPartnerId);
  const selectedPartner = selectedConversation?.partner || selectedUserFromSearch;

  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [messages]);

  const filteredConversations = conversations?.filter((conv: any) =>
    conv.partner.name.toLowerCase().includes(searchTerm.toLowerCase())
  ) || [];

  const handleSend = async () => {
    if (!message.trim() || !selectedPartnerId) return;

    try {
      await sendMessageMutation.mutateAsync({
        receiverId: selectedPartnerId,
        content: message.trim(),
      });
      setMessage("");
    } catch (error) {
      // Error handled by hook
    }
  };

  const handleSelectUser = (userId: string) => {
    const user = searchResults?.users.find((u: any) => u.id === userId);
    setSelectedPartnerId(userId);
    setSelectedUserFromSearch(user);
    setNewMessageOpen(false);
    setUserSearchQuery("");
  };

  const formatTime = (date: string) => {
    const messageDate = new Date(date);
    const now = new Date();
    const diffInHours = (now.getTime() - messageDate.getTime()) / (1000 * 60 * 60);

    if (diffInHours < 24) {
      return messageDate.toLocaleTimeString('en-US', { hour: '2-digit', minute: '2-digit' });
    }

    const diffInDays = Math.floor(diffInHours / 24);
    if (diffInDays === 1) return "Yesterday";
    if (diffInDays < 7) return `${diffInDays} days ago`;
    return messageDate.toLocaleDateString('en-US', { month: 'short', day: 'numeric' });
  };

  if (loadingConversations) {
    return (
      <div className="h-[calc(100vh-8rem)] flex items-center justify-center">
        <Loader2 className="h-8 w-8 animate-spin text-red-600" />
      </div>
    );
  }

  return (
    <div className="h-[calc(100vh-8rem)] flex flex-col min-w-0 p-4 md:p-8 space-y-6 bg-gray-50/30 min-h-screen">
      <div className="h-full flex bg-white rounded-xl border border-gray-100 shadow-none overflow-hidden">
        <div className="w-80 border-r border-gray-100 flex flex-col bg-white">
          <div className="p-4 border-b border-gray-50">
            <div className="flex items-center justify-between mb-3">
              <h2 className="text-sm font-bold text-black uppercase tracking-widest">Messages</h2>
              <Dialog open={newMessageOpen} onOpenChange={setNewMessageOpen}>
                <DialogTrigger asChild>
                  <Button size="sm" className="h-7 px-2 bg-red-600 hover:bg-red-700 text-white">
                    <Plus className="h-3.5 w-3.5 mr-1" />
                    New
                  </Button>
                </DialogTrigger>
                <DialogContent className="sm:max-w-md">
                  <DialogHeader>
                    <DialogTitle>New Message</DialogTitle>
                  </DialogHeader>
                  <div className="space-y-4">
                    <div className="relative">
                      <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 h-4 w-4 text-gray-400" />
                      <Input
                        placeholder="Search by name, email, or ID..."
                        className="pl-9"
                        value={userSearchQuery}
                        onChange={(e) => setUserSearchQuery(e.target.value)}
                        autoFocus
                      />
                    </div>
                    <div className="max-h-[400px] overflow-y-auto space-y-1">
                      {searchingUsers ? (
                        <div className="flex items-center justify-center py-8">
                          <Loader2 className="h-6 w-6 animate-spin text-red-600" />
                        </div>
                      ) : userSearchQuery.length < 2 ? (
                        <p className="text-xs text-gray-500 text-center py-8">
                          Type at least 2 characters to search
                        </p>
                      ) : searchResults?.users.length === 0 ? (
                        <p className="text-xs text-gray-500 text-center py-8">
                          No users found
                        </p>
                      ) : (
                        searchResults?.users.map((user: any) => (
                          <div
                            key={user.id}
                            className="flex items-center space-x-3 p-3 rounded-lg hover:bg-gray-50 cursor-pointer transition-colors"
                            onClick={() => handleSelectUser(user.id)}
                          >
                            <Avatar className="h-10 w-10 border border-gray-100">
                              <AvatarImage src={user.image} />
                              <AvatarFallback className="bg-red-50 text-red-700 font-bold text-xs">
                                {user.name.split(' ').map((n: string) => n[0]).join('').slice(0, 2)}
                              </AvatarFallback>
                            </Avatar>
                            <div className="flex-1 min-w-0">
                              <p className="text-sm font-semibold text-black truncate">
                                {user.name}
                              </p>
                              <p className="text-xs text-gray-500 truncate">
                                {user.email}
                              </p>
                              <div className="flex items-center gap-2 mt-0.5">
                                <span className="text-[10px] text-red-600 font-bold uppercase">
                                  {user.role}
                                </span>
                                {(user.registrationNumber || user.employeeId) && (
                                  <span className="text-[10px] text-gray-400">
                                    {user.registrationNumber || user.employeeId}
                                  </span>
                                )}
                              </div>
                            </div>
                          </div>
                        ))
                      )}
                    </div>
                  </div>
                </DialogContent>
              </Dialog>
            </div>
            <div className="relative">
              <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 h-4 w-4 text-gray-400 font-bold" />
              <Input 
                placeholder="Search conversations..." 
                className="pl-9 h-10 bg-gray-50/50 border-gray-100 focus:bg-white text-sm"
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
              />
            </div>
          </div>
          <div className="flex-1 overflow-y-auto">
            {filteredConversations.length === 0 ? (
              <div className="p-8 text-center">
                <p className="text-xs text-gray-500 font-medium">No conversations yet</p>
              </div>
            ) : (
              filteredConversations.map((conv: any) => (
                <div
                  key={conv.partner.id}
                  className={`p-4 border-b border-gray-50 cursor-pointer hover:bg-red-50/30 transition-colors ${
                    selectedPartnerId === conv.partner.id ? "bg-red-50/50 border-l-4 border-l-red-600" : ""
                  }`}
                  onClick={() => setSelectedPartnerId(conv.partner.id)}
                >
                  <div className="flex items-start space-x-3">
                    <Avatar className="h-10 w-10 border border-gray-100">
                      <AvatarImage src={conv.partner.image} />
                      <AvatarFallback className="bg-red-50 text-red-700 font-bold text-xs">
                        {conv.partner.name.split(' ').map((n: string) => n[0]).join('').slice(0, 2)}
                      </AvatarFallback>
                    </Avatar>
                    <div className="flex-1 min-w-0">
                      <div className="flex items-center justify-between mb-0.5">
                        <p className="text-xs font-bold text-black truncate">
                          {conv.partner.name}
                        </p>
                        <span className="text-[10px] text-gray-400 font-medium">
                          {formatTime(conv.lastMessage.sentAt)}
                        </span>
                      </div>
                      <div className="flex items-center justify-between">
                        <p className="text-[11px] text-gray-500 truncate flex-1 font-medium">
                          {conv.lastMessage.senderId === me?.id && "You: "}
                          {conv.lastMessage.content}
                        </p>
                        {conv.unreadCount > 0 && (
                          <div className="bg-red-600 text-white text-[10px] font-black rounded-full h-4 min-w-[16px] px-1 flex items-center justify-center ml-2 shadow-sm shadow-red-500/20">
                            {conv.unreadCount}
                          </div>
                        )}
                      </div>
                    </div>
                  </div>
                </div>
              ))
            )}
          </div>
        </div>

        <div className="flex-1 flex flex-col bg-gray-50/30">
          {!selectedPartnerId ? (
            <div className="flex-1 flex items-center justify-center">
              <EmptyState
                icon={Send}
                title="Your messages"
                description="Choose an existing conversation or start a new one to begin connecting"
              />
            </div>
          ) : (
            <>
              <div className="p-4 border-b border-gray-50 bg-white shadow-sm shadow-black/5">
                <div className="flex items-center space-x-3">
                  <Avatar className="h-9 w-9 border border-gray-100 shadow-sm">
                    <AvatarImage src={selectedPartner?.image} />
                    <AvatarFallback className="bg-red-50 text-red-700 font-bold text-xs">
                      {selectedPartner?.name.split(' ').map((n: string) => n[0]).join('').slice(0, 2)}
                    </AvatarFallback>
                  </Avatar>
                  <div>
                    <p className="text-sm font-bold text-black">{selectedPartner?.name}</p>
                    <p className="text-[10px] text-red-600 font-bold uppercase tracking-wider">{selectedPartner?.role}</p>
                  </div>
                </div>
              </div>

              <div className="flex-1 overflow-y-auto p-6 space-y-4">
                {loadingMessages ? (
                  <div className="flex items-center justify-center h-full">
                    <Loader2 className="h-6 w-6 animate-spin text-red-600" />
                  </div>
                ) : messages.length === 0 ? (
                  <div className="flex items-center justify-center h-full">
                    <p className="text-xs text-gray-400 font-medium">No messages yet. Start the conversation!</p>
                  </div>
                ) : (
                  <>
                    {hasNextPage && (
                      <div className="text-center pb-4">
                        <Button
                          variant="ghost"
                          size="sm"
                          onClick={() => fetchNextPage()}
                          className="text-red-600 font-bold text-[10px] uppercase hover:bg-red-50 transition-all"
                        >
                          Load older messages
                        </Button>
                      </div>
                    )}
                    {messages.map((msg: any) => {
                      const isMe = msg.senderId === me?.id;
                      return (
                        <div
                          key={msg.id}
                          className={`flex ${isMe ? "justify-end" : "justify-start"}`}
                        >
                          <div
                            className={`max-w-[70%] px-4 py-2.5 rounded-2xl shadow-sm border ${
                              isMe
                                ? "bg-red-600 text-white rounded-br-none border-red-500 shadow-red-500/10"
                                : "bg-white text-black rounded-bl-none border-gray-100"
                            }`}
                          >
                            <p className="text-xs font-medium whitespace-pre-wrap break-words leading-relaxed">{msg.content}</p>
                            <div className={`flex items-center justify-end gap-1.5 mt-1.5 ${
                              isMe ? "text-white/80" : "text-gray-400"
                            }`}>
                              <span className="text-[9px] font-bold">
                                {formatTime(msg.sentAt)}
                              </span>
                              {isMe && (
                                msg.isRead ? (
                                  <CheckCheck className="h-3 w-3" />
                                ) : (
                                  <Check className="h-3 w-3" />
                                )
                              )}
                            </div>
                          </div>
                        </div>
                      );
                    })}
                    <div ref={messagesEndRef} />
                  </>
                )}
              </div>

              <div className="p-4 bg-white border-t border-gray-50">
                <div className="flex items-center space-x-2 bg-gray-50/50 p-1 rounded-xl border border-gray-100">
                  <Input
                    placeholder="Type your message here..."
                    value={message}
                    onChange={(e) => setMessage(e.target.value)}
                    onKeyPress={(e) => e.key === "Enter" && !e.shiftKey && handleSend()}
                    className="flex-1 border-none bg-transparent focus-visible:ring-0 shadow-none text-sm h-10"
                    disabled={sendMessageMutation.isPending}
                  />
                  <Button 
                    onClick={handleSend} 
                    className="bg-red-600 hover:bg-red-700 h-9 w-9 p-0 rounded-lg shadow-lg shadow-red-500/20 transition-all"
                    disabled={!message.trim() || sendMessageMutation.isPending}
                  >
                    {sendMessageMutation.isPending ? (
                      <Loader2 className="h-4 w-4 animate-spin" />
                    ) : (
                      <Send className="h-4 w-4" />
                    )}
                  </Button>
                </div>
              </div>
            </>
          )}
        </div>
      </div>
    </div>
  );
}

"use client";

import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { Bell, CheckCheck, Loader2 } from "lucide-react";
import { EmptyState } from "@/components/shared/EmptyState";
import { useNotifications, useMarkNotificationRead, useMarkAllRead } from "@/hooks/useNotifications";
import { useRouter } from "next/navigation";

export default function NotificationsPage() {
  const router = useRouter();
  const { data, isLoading } = useNotifications();
  const markRead = useMarkNotificationRead();
  const markAllRead = useMarkAllRead();

  const notifications = data?.data || [];
  const unreadCount = notifications.filter((n: any) => !n.isRead).length;

  const handleMarkAllRead = async () => {
    await markAllRead.mutateAsync();
  };

  const handleNotificationClick = async (notification: any) => {
    if (!notification.isRead) {
      await markRead.mutateAsync(notification.id);
    }

    if (notification.metadata?.url) {
      router.push(notification.metadata.url);
    } else if (notification.type === "ASSIGNMENT_POSTED" && notification.metadata?.courseId) {
      router.push(`/dashboard/student/courses/${notification.metadata.courseId}`);
    } else if (notification.type === "LIVE_LECTURE" && notification.metadata?.courseId) {
      router.push(`/dashboard/student/courses/${notification.metadata.courseId}`);
    } else if (notification.type === "GRADE_PUBLISHED" && notification.metadata?.assignmentId) {
      router.push(`/dashboard/student/courses/${notification.metadata.courseId}`);
    }
  };

  const getNotificationIcon = (type: string) => {
    switch (type) {
      case "ASSIGNMENT_POSTED":
        return "📋";
      case "GRADE_PUBLISHED":
        return "✅";
      case "LIVE_LECTURE":
        return "🔴";
      case "COURSE_ENROLLED":
        return "📚";
      case "MESSAGE":
        return "💬";
      default:
        return "🔔";
    }
  };

  const formatTimeAgo = (date: string) => {
    const now = new Date();
    const notifDate = new Date(date);
    const diffInSeconds = Math.floor((now.getTime() - notifDate.getTime()) / 1000);

    if (diffInSeconds < 60) return "Just now";
    if (diffInSeconds < 3600) return `${Math.floor(diffInSeconds / 60)} minutes ago`;
    if (diffInSeconds < 86400) return `${Math.floor(diffInSeconds / 3600)} hours ago`;
    if (diffInSeconds < 604800) return `${Math.floor(diffInSeconds / 86400)} days ago`;
    return notifDate.toLocaleDateString('en-US', { month: 'short', day: 'numeric' });
  };

  if (isLoading) {
    return (
      <div className="flex-1 flex flex-col min-w-0 p-4 md:p-8 space-y-6 bg-gray-50/30 min-h-screen items-center justify-center">
        <Loader2 className="h-8 w-8 animate-spin text-red-600" />
      </div>
    );
  }

  return (
    <div className="flex-1 flex flex-col min-w-0 p-4 md:p-8 space-y-6 bg-gray-50/30 min-h-screen">
      <div className="flex justify-between items-center">
        <div>
          <h1 className="text-2xl font-bold tracking-tight text-black">Notifications</h1>
          <p className="text-sm text-gray-500 mt-1">
            {unreadCount > 0 ? (
              <>You have <span className="text-red-600 font-bold">{unreadCount}</span> unread alert{unreadCount > 1 ? 's' : ''}</>
            ) : 'You\'re all caught up!'}
          </p>
        </div>
        {unreadCount > 0 && (
          <Button 
            variant="ghost" 
            onClick={handleMarkAllRead} 
            className="flex items-center space-x-2 text-red-600 font-bold text-xs hover:bg-red-50 transition-all px-4"
            disabled={markAllRead.isPending}
          >
            {markAllRead.isPending ? (
              <Loader2 className="h-4 w-4 animate-spin" />
            ) : (
              <CheckCheck className="h-4 w-4" />
            )}
            <span>Mark all as read</span>
          </Button>
        )}
      </div>

      {notifications.length === 0 ? (
        <div className="py-20 bg-white rounded-2xl border border-gray-50 shadow-none">
          <EmptyState
            icon={Bell}
            title="Clean slate"
            description="We'll notify you here when there are new updates about your courses or account."
          />
        </div>
      ) : (
        <div className="bg-white rounded-xl border border-gray-100 shadow-none overflow-hidden divide-y divide-gray-50">
          {notifications.map((notification: any) => (
            <div
              key={notification.id}
              className={`p-5 hover:bg-red-50/30 cursor-pointer transition-colors relative ${
                !notification.isRead ? "bg-red-50/10" : ""
              }`}
              onClick={() => handleNotificationClick(notification)}
            >
              {!notification.isRead && (
                <div className="absolute left-0 top-0 bottom-0 w-1 bg-red-600" />
              )}
              <div className="flex items-start space-x-4">
                <div className="shrink-0">
                  <div className={`w-10 h-10 rounded-xl flex items-center justify-center text-xl shadow-sm border ${
                    !notification.isRead ? "bg-red-50 border-red-100" : "bg-gray-50 border-gray-100"
                  }`}>
                    {getNotificationIcon(notification.type)}
                  </div>
                </div>
                <div className="flex-1 min-w-0">
                  <div className="flex items-start justify-between gap-3">
                    <div className="flex-1">
                      <p className={`text-sm font-bold ${
                        !notification.isRead ? "text-black" : "text-gray-700"
                      }`}>
                        {notification.title}
                      </p>
                      <p className="text-xs text-gray-500 mt-1 font-medium leading-relaxed">
                        {notification.body}
                      </p>
                      <div className="flex items-center gap-3 mt-2.5">
                        <p className="text-[10px] text-gray-400 font-bold uppercase tracking-wider">
                          {formatTimeAgo(notification.createdAt)}
                        </p>
                        {!notification.isRead && (
                          <Badge className="bg-red-600 text-white text-[9px] font-black uppercase px-1.5 py-0 shadow-lg shadow-red-500/20 border-0">
                            New
                          </Badge>
                        )}
                      </div>
                    </div>
                    <div className="flex flex-col items-end gap-1.5">
                      <span className="text-[10px] text-gray-400 font-bold">
                        {new Date(notification.createdAt).toLocaleTimeString('en-US', { 
                          hour: '2-digit', 
                          minute: '2-digit' 
                        })}
                      </span>
                    </div>
                  </div>
                </div>
              </div>
            </div>
          ))}
        </div>
      )}
    </div>
  );
}

import { redirect } from "next/navigation";
import { auth } from "@/lib/auth";
import { headers } from "next/headers";

export default async function DashboardPage() {
  const session = await auth.api.getSession({ headers: await headers() });

  if (!session) {
    redirect("/auth/sign-in");
  }

  const user = session.user as any;

  // Role-based redirects
  if (user.role === "ADMIN") {
    redirect("/dashboard/admin/overview");
  }

  if (user.role === "LECTURER") {
    redirect("/dashboard/lecturer");
  }

  if (user.role === "STUDENT") {
    redirect("/dashboard/student");
  }

  // Default fallback
  redirect("/auth/sign-in");
}

