  const createFile = useCreateFile();
  const deleteFile = useDeleteFile();
  const deleteFileByUrl = useDeleteFileByUrl();

  useEffect(() => {
    clearExpiredImages();
  }, [clearExpiredImages]);

  // Restore from localStorage on mount
  useEffect(() => {
    if (valueArray.length === 0 && identifier) {
      if (isMultiple) {
        const persistedImages = getUploadedImageArray(identifier);
        if (persistedImages && persistedImages.length > 0) {
          const urls = persistedImages.map((img: any) => img.url);
          const uploadedFiles = persistedImages
            .map((img: any) => img.uploadedFile)
            .filter(Boolean) as UploadedFile[];

          onChange(urls, uploadedFiles.length > 0 ? uploadedFiles : undefined);

          const restoredData = persistedImages.map((img: any) => ({
            url: img.url,
            fileId: img.fileId || null,
            fileKey: img.fileKey,
            cloudflareId: img.cloudflareId,
            name: img.uploadedFile?.name,
            type: img.uploadedFile?.type,
          }));
          setFilesData(restoredData);
        }
      } else {
        const persistedImage = getUploadedImage(identifier);
        if (persistedImage) {
          onChange(persistedImage.url, persistedImage.uploadedFile);
          setFilesData([
            {
              url: persistedImage.url,
              fileId: persistedImage.fileId || null,
              fileKey: persistedImage.fileKey,
              cloudflareId: persistedImage.cloudflareId,
              name: persistedImage.uploadedFile?.name,
              type: persistedImage.uploadedFile?.type,
            },
          ]);
        }
      }
    }
  }, [identifier, getUploadedImage, getUploadedImageArray, isMultiple]);

  // Initialize files data from existing values
  useEffect(() => {
    if (valueArray.length > 0 && filesData.length === 0) {
      const newFilesData = valueArray.map((url, index) => ({
        url,
        fileId: Array.isArray(existingFileId)
          ? existingFileId[index] || null
          : existingFileId || null,
        fileKey: Array.isArray(existingFileKey)
          ? existingFileKey[index]
          : existingFileKey,
      }));
      setFilesData(newFilesData);
    }
  }, [valueArray.length]);

  // Persist to localStorage whenever filesData changes
  useEffect(() => {
    if (filesData.length > 0 && identifier) {
      const completedFiles = filesData.filter((f) => !f.uploading);

      if (completedFiles.length > 0) {
        if (isMultiple) {
          const imageDataArray: UploadedImageData[] = completedFiles.map(
            (f) => ({
              url: f.url,
              fileId: f.fileId || undefined,
              fileKey: f.fileKey,
              cloudflareId: f.cloudflareId,
              uploadedFile: f.fileId
                ? {
                    url: f.url,
                    name: f.name || "",
                    type: f.type || "",
                    key: f.fileKey || "",
                    size: 0,
                  }
                : undefined,
              timestamp: Date.now(),
            })
          );
          setUploadedImageArray(identifier, imageDataArray);
        } else if (completedFiles[0]) {
          const imageData: UploadedImageData = {
            url: completedFiles[0].url,
            fileId: completedFiles[0].fileId || undefined,
            fileKey: completedFiles[0].fileKey,
            cloudflareId: completedFiles[0].cloudflareId,
            uploadedFile: {
              url: completedFiles[0].url,
              name: completedFiles[0].name || "",
              type: completedFiles[0].type || "",
              key: completedFiles[0].fileKey || "",
              size: 0,
            },
            timestamp: Date.now(),
          };
          setUploadedImage(identifier, imageData);
        }
      }
    } else if (filesData.length === 0 && identifier) {
      if (isMultiple) {
        removeUploadedImageArray(identifier);
      } else {
        removeUploadedImage(identifier);
      }
    }
  }, [
    filesData,
    identifier,
    isMultiple,
    setUploadedImage,
    removeUploadedImage,
    setUploadedImageArray,
    removeUploadedImageArray,
  ]);

  // Cleanup object URLs on unmount
  useEffect(() => {
    return () => {
      filesData.forEach((file) => {
        if (file.objectUrl) {
          URL.revokeObjectURL(file.objectUrl);
        }
      });
    };
  }, [filesData]);

  const handleRemove = useCallback(
    async (index: number) => {
      if (deletingIndex !== null) return;

      setDeletingIndex(index);
      const fileData = filesData[index];

      if (fileData.objectUrl) {
        URL.revokeObjectURL(fileData.objectUrl);
      }

      try {
        if (fileData.cloudflareId) {
          await fetch(`${baseUrl}/api/images/delete`, {
            method: "POST",
            headers: { "Content-Type": "application/json" },
            body: JSON.stringify({ imageId: fileData.cloudflareId }),
          });
        }

        if (fileData.fileKey) {
          await fetch("/api/r2/delete", {
            method: "DELETE",
            headers: { "Content-Type": "application/json" },
            body: JSON.stringify({ key: fileData.fileKey }),
          });
        }

        if (fileData.fileId && fileData.fileKey) {
          await deleteFile.mutateAsync({
            fileId: fileData.fileId,
            key: fileData.fileKey,
          });
        } else if (fileData.url) {
          await deleteFileByUrl.mutateAsync(fileData.url);
        }

        const newFilesData = filesData.filter((_, i) => i !== index);
        const newUrls = newFilesData
          .filter((f) => !f.uploading)
          .map((f) => f.url);

        setFilesData(newFilesData);

        if (isMultiple) {
          onChange(newUrls);
        } else {
          onChange("");
        }

        toast.success("File deleted successfully");
      } catch (error) {
        console.error("Failed to delete file:", error);
        toast.error("Removed from UI, but backend deletion failed");

        const newFilesData = filesData.filter((_, i) => i !== index);
        const newUrls = newFilesData
          .filter((f) => !f.uploading)
          .map((f) => f.url);
        setFilesData(newFilesData);

        if (isMultiple) {
          onChange(newUrls);
        } else {
          onChange("");
        }
      } finally {
        setDeletingIndex(null);
      }
    },
    [
      filesData,
      deletingIndex,
      deleteFile,
      deleteFileByUrl,
      onChange,
      isMultiple,
    ]
  );

  const handleFileSelect = async (files: File[]) => {
    let isValid = (file: File) => true;

    if (category === FileCategory.DOCUMENT) {
      isValid = (file: File) => {
        const docTypes = [
          "application/pdf",
          "application/msword",
          "application/vnd.openxmlformats-officedocument.wordprocessingml.document",
          "application/vnd.ms-excel",
          "application/vnd.openxmlformats-officedocument.spreadsheetml.sheet",
          "application/vnd.ms-powerpoint",
          "application/vnd.openxmlformats-officedocument.presentationml.presentation",
          "text/plain",
          "text/csv",
        ];
        return (
          docTypes.includes(file.type) || file.type.startsWith("application/")
        );
      };
    } else if (acceptedTypes === "image/*") {
      isValid = (file: File) => file.type.startsWith("image/");
    }

    const validFiles = files.filter(isValid);

    if (validFiles.length === 0) {
      toast.error("Please select valid files");
      return;
    }

    if (isMultiple && filesData.length + validFiles.length > maxFiles) {
      toast.error(`Maximum ${maxFiles} files allowed`);
      return;
    }

    const filesToProcess = isMultiple ? validFiles : [validFiles[0]];

    setIsUploading(true);
    setTotalToUpload(filesToProcess.length);
    setUploadingCount(0);

    const tempFilesData: FileData[] = filesToProcess.map((file) => ({
      url: "",
      fileId: null,
      fileKey: undefined,
      name: file.name,
      type: file.type,
      objectUrl: URL.createObjectURL(file),
      uploading: true,
      progress: 0,
    }));

    setFilesData((prev) => [...prev, ...tempFilesData]);

    for (let i = 0; i < filesToProcess.length; i++) {
        const file = filesToProcess[i];
        const tempIndex = filesData.length + i;

        setUploadingCount(i + 1);

        try {
            if (file.size > 10 * 1024 * 1024) {
                toast.error(`${file.name}: File must be less than 10MB`);
                setFilesData((prev) => prev.filter((_, idx) => idx !== tempIndex));
                continue;
            }

            const presignedResponse = await fetch("/api/r2/upload", {
                method: "POST",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify({
                    filename: file.name,
                    contentType: file.type,
                    size: file.size,
                }),
            });

            if (!presignedResponse.ok) throw new Error("Presigned URL failed");

            const { presignedUrl, key, publicUrl } = await presignedResponse.json();

            await new Promise<void>((resolve, reject) => {
                const xhr = new XMLHttpRequest();
                xhr.upload.onprogress = (event) => {
                    if (event.lengthComputable) {
                        const percentComplete = Math.round((event.loaded / event.total) * 100);
                        setFilesData((prev) =>
                            prev.map((f, idx) => idx === tempIndex ? { ...f, progress: percentComplete } : f)
                        );
                    }
                };
                xhr.onload = () => (xhr.status === 200 || xhr.status === 204 ? resolve() : reject());
                xhr.onerror = () => reject();
                xhr.open("PUT", presignedUrl);
                xhr.setRequestHeader("Content-Type", file.type);
                xhr.send(file);
            });

            const result = await createFile.mutateAsync({
                url: publicUrl,
                fileKey: key,
                size: file.size,
                metadata: {
                    mediaType: file.type || MediaType.IMAGE_JPEG,
                    originalName: file.name,
                    uploadedAt: new Date().toISOString(),
                    category,
                },
            });

            setFilesData((prev) =>
                prev.map((f, idx) =>
                    idx === tempIndex
                        ? {
                            ...f,
                            url: publicUrl,
                            fileId: result.success && result.data ? result.data.id : null,
                            fileKey: key,
                            uploading: false,
                            progress: 100,
                        }
                        : f
                )
            );

            setTimeout(() => {
                setFilesData((prev) =>
                    prev.map((f, idx) => {
                        if (idx === tempIndex && f.objectUrl) {
                            URL.revokeObjectURL(f.objectUrl);
                            return { ...f, objectUrl: undefined };
                        }
                        return f;
                    })
                );
            }, 1000);
        } catch (error) {
            console.error("Upload error:", error);
            toast.error(`Failed to upload ${file.name}`);
            setFilesData((prev) => prev.filter((_, idx) => idx !== tempIndex));
        }
    }

    setTimeout(() => {
        setFilesData((prev) => {
            const completedFiles = prev.filter((f) => !f.uploading);
            const newUrls = completedFiles.map((f) => f.url);
            if (isMultiple) onChange(newUrls);
            else onChange(newUrls[0] || "");
            return prev;
        });
    }, 500);

    setIsUploading(false);
    setUploadComplete(true);
    setTimeout(() => setUploadComplete(false), 2000);
  };

  const handleFileChange = (event: React.ChangeEvent<HTMLInputElement>) => {
    const files = event.target.files ? Array.from(event.target.files) : [];
    if (files.length > 0) handleFileSelect(files);
    event.target.value = "";
  };

  const handleDragOver = (e: React.DragEvent) => {
    e.preventDefault();
    if (!isUploading) setIsDragging(true);
  };

  const handleDragLeave = (e: React.DragEvent) => {
    e.preventDefault();
    setIsDragging(false);
  };

  const handleDrop = (e: React.DragEvent) => {
    e.preventDefault();
    setIsDragging(false);
    if (!isUploading) {
        const files = Array.from(e.dataTransfer.files);
        if (files.length > 0) handleFileSelect(files);
    }
  };

  const handleClick = () => {
    if (!isUploading) document.getElementById(`file-upload-${identifier}`)?.click();
  };

  const getFileIcon = () => {
    switch (category) {
      case FileCategory.DOCUMENT: return FileText;
      case FileCategory.VIDEO: return Video;
      case FileCategory.AUDIO: return Music;
      case FileCategory.IMAGE:
      case FileCategory.GALLERY:
      case FileCategory.PROFILE: return FileImage;
      default: return File;
    }
  };

  const isImageFile = (url: string | undefined, type?: string) => {
    if (!url && !type) return false;
    if (type) return type.startsWith("image/");
    const exts = [".jpg", ".jpeg", ".png", ".gif", ".webp", ".svg", ".bmp"];
    return exts.some((ext) => url!.toLowerCase().endsWith(ext));
  };

  const renderFilePreview = (fileData: FileData, size: "small" | "medium" | "large" = "medium") => {
    const Icon = getFileIcon();
    const sCls = { small: "w-4 h-4", medium: "w-6 h-6", large: "w-8 h-8" };
    const pUrl = fileData.objectUrl || fileData.url;
    const isImg = isImageFile(pUrl, fileData.type);

    if (isImg && pUrl) {
      return (
        <>
          <img src={pUrl} alt="Preview" className="absolute inset-0 w-full h-full object-cover" />
          {fileData.uploading && (
            <div className="absolute inset-0 bg-black/60 flex items-center justify-center">
              <div className="text-center">
                <Loader2 className="w-8 h-8 text-white animate-spin mx-auto mb-2" />
                <div className="text-white font-semibold text-sm">{fileData.progress}%</div>
              </div>
            </div>
          )}
        </>
      );
    }

    return (
      <div className="absolute inset-0 flex flex-col items-center justify-center bg-gray-100">
        {fileData.uploading ? (
          <>
            <Loader2 className={cn(sCls[size], "text-primary animate-spin mb-2")} />
            <p className="text-xs text-gray-600 font-medium">{fileData.progress}%</p>
          </>
        ) : (
          <>
            <Icon className={cn(sCls[size], "text-gray-600 mb-1")} />
            <p className="text-[10px] text-gray-500 font-bold uppercase">{category}</p>
          </>
        )}
      </div>
    );
  };

  if (variant === "compact") {
    return (
      <div className={cn("space-y-4", className)}>
        {label && <h3 className="text-[10px] font-black uppercase text-gray-400 tracking-[0.2em] px-1">{label}</h3>}
        <div className="flex flex-wrap gap-4 items-center">
          {filesData.map((f, i) => (
            <div key={i} className="relative group">
              <div className="relative w-20 h-20 rounded-2xl overflow-hidden border border-gray-100 bg-gray-50/50 shadow-sm transition-transform group-hover:scale-[1.02]">
                {renderFilePreview(f, "small")}
                {uploadComplete && !f.uploading && (
                  <div className="absolute inset-0 bg-green-500/20 backdrop-blur-[1px] flex items-center justify-center animate-in fade-in zoom-in duration-300">
                    <div className="h-6 w-6 bg-white rounded-full flex items-center justify-center shadow-lg">
                      <Check className="w-3 h-3 text-green-600" />
                    </div>
                  </div>
                )}
              </div>
              <button
                type="button"
                onClick={() => handleRemove(i)}
                disabled={deletingIndex === i || isUploading || f.uploading}
                className="absolute -top-2 -right-2 w-6 h-6 rounded-full bg-white border border-gray-100 text-gray-400 hover:text-red-500 hover:border-red-100 flex items-center justify-center shadow-xl transition-all z-10 opacity-0 group-hover:opacity-100 scale-90 group-hover:scale-100"
              >
                {deletingIndex === i ? <Loader2 className="w-3 h-3 animate-spin" /> : <X className="w-3 h-3" />}
              </button>
            </div>
          ))}
          {(!isMultiple && filesData.length > 0) ? null : (
            <>
              <input type="file" accept={acceptedTypes} onChange={handleFileChange} disabled={isUploading} multiple={isMultiple} className="hidden" id={`file-upload-${identifier}`} />
              <button type="button" onClick={handleClick} onDragOver={handleDragOver} onDragLeave={handleDragLeave} onDrop={handleDrop} disabled={isUploading} className={cn("relative w-20 h-20 rounded-2xl border-2 border-dashed transition-all flex flex-col items-center justify-center gap-1 group", isDragging ? "border-red-500 bg-red-50/50" : "border-gray-200 hover:border-red-400 hover:bg-gray-50", isUploading && "opacity-50 cursor-not-allowed border-gray-100")}>
                {isUploading ? <Loader2 className="w-5 h-5 text-red-500 animate-spin" /> : (
                  <div className="h-8 w-8 rounded-xl bg-gray-50 flex items-center justify-center group-hover:bg-red-50 group-hover:text-red-600 transition-colors text-gray-400">
                    <Plus className="w-4 h-4" />
                  </div>
                )}
                <span className="text-[9px] font-bold text-gray-400 uppercase tracking-tighter">{isUploading ? "..." : "Add"}</span>
              </button>
            </>
          )}
        </div>
        {description && <p className="text-[10px] text-gray-400 italic px-1">{description}</p>}
      </div>
    );
  }

  if (variant === "minimal") {
    return (
      <div className={cn("space-y-2", className)}>
        <div className="flex items-center gap-2 flex-wrap">
          {filesData.map((f, i) => (
            <div key={i} className="relative">
              <div className="relative w-14 h-14 rounded-lg overflow-hidden border-2 border-gray-200">{renderFilePreview(f, "small")}</div>
              <button type="button" onClick={() => handleRemove(i)} className="absolute -top-1 -right-1 w-4 h-4 rounded-full bg-red-500 text-white flex items-center justify-center shadow-lg">
                <X className="w-2 h-2" />
              </button>
            </div>
          ))}
          <div>
            <input type="file" accept={acceptedTypes} onChange={handleFileChange} disabled={isUploading} multiple={isMultiple} className="hidden" id={`file-upload-${identifier}`} />
            <button type="button" onClick={handleClick} disabled={isUploading} className="inline-flex items-center px-3 py-1.5 bg-primary text-white text-xs font-medium rounded-md shadow-sm">
                {isUploading ? <Loader2 className="w-3 h-3 mr-1.5 animate-spin" /> : <Upload className="w-3 h-3 mr-1.5" />}
                {filesData.length > 0 ? "More" : "Upload"}
            </button>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className={cn("space-y-4", className)}>
      {label && (
        <label className="text-xs font-bold uppercase text-gray-400 tracking-wider flex items-center gap-2 px-1">
            <div className="h-1.5 w-1.5 rounded-full bg-red-600" /> {label}
        </label>
      )}
      <div onDragOver={handleDragOver} onDragLeave={handleDragLeave} onDrop={handleDrop} className={cn("group relative border-2 border-dashed rounded-[1.5rem] p-1 transition-all duration-300", isDragging ? "border-red-500 bg-red-50/50 scale-[0.99]" : "border-gray-200 hover:border-red-400 hover:bg-gray-50/30", isUploading && "opacity-80 scale-[0.98]")}>
        <input type="file" accept={acceptedTypes} onChange={handleFileChange} disabled={isUploading} multiple={isMultiple} className="hidden" id={`file-upload-${identifier}`} />
        {filesData.length > 0 ? (
          <div className="p-4 bg-white/50 rounded-[1.25rem]">
            <div className={cn("grid gap-4", isMultiple ? "grid-cols-2 sm:grid-cols-3 md:grid-cols-4 lg:grid-cols-5" : "grid-cols-1")}>
              {filesData.map((f, i) => (
                <div key={i} className="relative aspect-square rounded-2xl overflow-hidden border border-gray-100 bg-gray-50 group/item transition-all hover:shadow-xl">
                  {renderFilePreview(f, "large")}
                  <div className="absolute inset-x-0 bottom-0 p-2 bg-gradient-to-t from-black/60 to-transparent flex justify-end opacity-0 group-hover/item:opacity-100 transition-opacity">
                    <button type="button" onClick={() => handleRemove(i)} className="h-8 w-8 rounded-xl bg-red-500 text-white flex items-center justify-center shadow-lg">
                      <Trash2 className="h-4 w-4" />
                    </button>
                  </div>
                  {f.uploading && (
                    <div className="absolute inset-0 bg-white/80 backdrop-blur-sm flex flex-col items-center justify-center p-4">
                      <div className="relative h-12 w-12 flex items-center justify-center mb-2">
                        <Loader2 className="h-6 w-6 text-red-600 animate-spin" />
                        <span className="absolute text-[9px] font-black text-red-600">{f.progress}%</span>
                      </div>
                      <span className="text-[9px] font-bold text-gray-400 uppercase tracking-widest">Uploading</span>
                    </div>
                  )}
                </div>
              ))}
              {isMultiple && filesData.length < maxFiles && (
                <button type="button" onClick={handleClick} className="relative aspect-square rounded-2xl border-2 border-dashed border-gray-200 hover:border-red-400 hover:bg-red-50 transition-all flex flex-col items-center justify-center gap-2 group/add">
                  <div className="h-10 w-10 rounded-2xl bg-gray-50 flex items-center justify-center group-hover/add:bg-red-600 group-hover/add:text-white transition-all"><Plus className="h-5 w-5" /></div>
                  <span className="text-[10px] font-bold text-gray-400 uppercase tracking-widest group-hover/add:text-red-600">Add Media</span>
                </button>
              )}
            </div>
          </div>
        ) : (
          <div onClick={handleClick} className="cursor-pointer py-10 flex flex-col items-center justify-center text-center space-y-4">
            <div className="h-16 w-16 rounded-[1.5rem] bg-red-50 flex items-center justify-center group-hover:scale-110 transition-all shadow-xl shadow-red-500/10">
                {isUploading ? <Loader2 className="h-8 w-8 text-red-600 animate-spin" /> : <CloudUpload className="h-8 w-8 text-red-600" />}
            </div>
            <div className="space-y-1">
              <h4 className="text-sm font-bold text-black group-hover:text-red-600 transition-colors">{isUploading ? "Uploading Data Assets..." : "Upload Campus Media"}</h4>
              <p className="text-[11px] text-gray-400 font-medium px-4 max-w-sm mx-auto leading-relaxed">Drag and drop assets here, or <span className="text-red-600 font-bold underline underline-offset-4">browse files</span>.</p>
            </div>
          </div>
        )}
      </div>
      {description && <p className="text-[10px] text-gray-400 italic text-center px-4">{description}</p>}
    </div>
  );
}

'use client'

import { useState, useEffect } from 'react'
import Link from 'next/link'
import { useForm } from 'react-hook-form'
import { zodResolver } from '@hookform/resolvers/zod'
import { z } from 'zod'
import {
  Form,
  FormControl,
  FormField,
  FormItem,
  FormLabel,
  FormMessage,
} from '@/components/ui/form'
import { Input } from '@/components/ui/input'
import { Button } from '@/components/ui/button'
import {
  InputOTP,
  InputOTPGroup,
  InputOTPSlot,
} from "@/components/ui/input-otp"

import { AppLogoIcon } from '@/components/icons'
import { authClient } from '@/lib/auth-client'
import { useRouter } from 'next/navigation'
import { toast } from 'sonner'
import { Eye, EyeOff } from 'lucide-react'

const resetPasswordOtpSchema = z.object({
  otp: z.string().min(6, "Please enter the 6-digit code"),
  password: z.string().min(8, "Password must be at least 8 characters"),
  confirmPassword: z.string(),
}).refine((data) => data.password === data.confirmPassword, {
  message: "Passwords don't match",
  path: ["confirmPassword"],
})

type ResetPasswordOtpInput = z.infer<typeof resetPasswordOtpSchema>

export function ResetPassword() {
  const router = useRouter()
  const [isLoading, setIsLoading] = useState(false)
  const [showPassword, setShowPassword] = useState(false)
  const [showConfirmPassword, setShowConfirmPassword] = useState(false)
  const [email, setEmail] = useState<string | null>(null)

  useEffect(() => {
    const storedEmail = sessionStorage.getItem("reset_email")
    if (storedEmail) {
      setEmail(storedEmail)
    }
  }, [])

  const form = useForm<ResetPasswordOtpInput>({
    resolver: zodResolver(resetPasswordOtpSchema),
    defaultValues: {
      otp: '',
      password: '',
      confirmPassword: '',
    },
  })

  async function onSubmit(data: ResetPasswordOtpInput) {
    if (!email) {
      toast.error("Email not found. Please go back and request a new reset code.")
      return
    }

    setIsLoading(true)
    await authClient.emailOtp.resetPassword({
      email: email,
      otp: data.otp,
      password: data.password,
    }, {
      onSuccess: () => {
        toast.success("Password reset successfully! Please log in.")
        sessionStorage.removeItem("reset_email")
        router.push("/auth/sign-in")
      },
      onError: (ctx) => {
        form.setError('root', {
          message: ctx.error.message,
        })
        toast.error(ctx.error.message)
        setIsLoading(false)
      }
    })
    setIsLoading(false)
  }

  async function handleResendOtp() {
    if (!email) {
