"use client";

import { usePathname } from "next/navigation";
import Link from "next/link";
import { motion } from "framer-motion";
import {
  LayoutDashboard,
  BookOpen,
  MessageSquare,
  Bell,
  User,
  Library,
  GraduationCap,
  Users,
} from "lucide-react";
import { Badge } from "@/components/ui/badge";

interface MobileBottomNavProps {
  role: string;
  unreadNotifications?: number;
  unreadMessages?: number;
}

export function MobileBottomNav({ role, unreadNotifications = 0, unreadMessages = 0 }: MobileBottomNavProps) {
  const pathname = usePathname();

  const getNavItems = () => {
    const baseItems: Array<{ icon: any; label: string; href: string; badge?: number }> = [
      {
        icon: LayoutDashboard,
        label: "Home",
        href: "/dashboard",
      },
    ];

    if (role === "ADMIN") {
      return [
        ...baseItems,
        { icon: Users, label: "Users", href: "/dashboard/admin/users/students" },
        { icon: BookOpen, label: "Courses", href: "/dashboard/admin/courses" },
        { icon: MessageSquare, label: "Messages", href: "/dashboard/messages", badge: unreadMessages },
        { icon: Bell, label: "Alerts", href: "/dashboard/notifications", badge: unreadNotifications },
      ];
    }

    if (role === "LECTURER") {
      return [
        ...baseItems,
        { icon: BookOpen, label: "Courses", href: "/dashboard/lecturer/my-courses" },
        { icon: Library, label: "Library", href: "/dashboard/library" },
        { icon: MessageSquare, label: "Messages", href: "/dashboard/messages", badge: unreadMessages },
        { icon: User, label: "Profile", href: "/dashboard/profile" },
      ];
    }

    // STUDENT
    return [
      ...baseItems,
      { icon: BookOpen, label: "Courses", href: "/dashboard/student/courses" },
      { icon: Library, label: "Library", href: "/dashboard/library" },
      { icon: MessageSquare, label: "Messages", href: "/dashboard/messages", badge: unreadMessages },
      { icon: Bell, label: "Alerts", href: "/dashboard/notifications", badge: unreadNotifications },
    ];
  };

  const navItems = getNavItems();

  return (
    <div className="lg:hidden fixed bottom-0 left-0 right-0 z-50 bg-white border-t border-gray-200 shadow-lg">
      <nav className="flex items-center justify-around h-16 px-2">
        {navItems.map((item) => {
          const isActive = pathname === item.href || pathname.startsWith(item.href + "/");
          const Icon = item.icon;

          return (
            <Link
              key={item.href}
              href={item.href}
              className="relative flex flex-col items-center justify-center flex-1 h-full group"
            >
              <div className="relative">
                <motion.div
                  whileTap={{ scale: 0.9 }}
                  className={`p-2 rounded-xl transition-colors ${
                    isActive
                      ? "bg-red-600 text-white"
                      : "text-gray-600 group-hover:bg-gray-100"
                  }`}
                >
                  <Icon className="h-5 w-5" />
                </motion.div>
                {item.badge && item.badge > 0 && (
                  <Badge className="absolute -top-1 -right-1 h-5 min-w-[20px] px-1 text-xs bg-red-500 border-2 border-white">
                    {item.badge > 99 ? "99+" : item.badge}
                  </Badge>
                )}
              </div>
              <span
                className={`text-xs mt-1 font-medium ${
                  isActive ? "text-red-600" : "text-gray-600"
                }`}
              >
                {item.label}
              </span>
            </Link>
          );
        })}
      </nav>
    </div>
  );
}

"use client";

import * as React from "react";
import { Bell, Search } from "lucide-react";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Badge } from "@/components/ui/badge";
import { Avatar, AvatarFallback, AvatarImage } from "@/components/ui/avatar";
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuLabel,
  DropdownMenuSeparator,
  DropdownMenuTrigger,
} from "@/components/ui/dropdown-menu";
import { useRouter } from "next/navigation";
import { useNotifications } from "@/hooks/useNotifications";

interface NavbarProps {
  onSearch?: (query: string) => void;
  searchResults?: any[];
  user: any;
}

export function Navbar({ onSearch, searchResults = [], user }: NavbarProps) {
  const [searchQuery, setSearchQuery] = React.useState("");
  const router = useRouter();
  const { data: notifications } = useNotifications({ unreadOnly: true });

  const unreadCount = notifications?.data?.length || 0;

  const handleSearchChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const value = e.target.value;
    setSearchQuery(value);
    if (onSearch) {
      onSearch(value);
    }
  };

  return (
    <header className="flex h-16 items-center gap-4 px-6">
      <div className="relative flex-1 max-w-md">
        <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 w-4 h-4 text-gray-400" />
        <Input
          placeholder="Search students, courses..."
          value={searchQuery}
          onChange={handleSearchChange}
          className="pl-10 bg-gray-50 border-gray-200 text-black placeholder:text-gray-400"
        />
      </div>

      <div className="flex items-center gap-2">
        <DropdownMenu>
          <DropdownMenuTrigger asChild>
            <Button variant="ghost" size="icon" className="relative">
              <Bell className="h-5 w-5" />
              {unreadCount > 0 && (
                <Badge
                  variant="destructive"
                  className="absolute -top-1 -right-1 h-5 w-5 p-0 flex items-center justify-center text-xs bg-red-500"
                >
                  {unreadCount}
                </Badge>
              )}
            </Button>
          </DropdownMenuTrigger>
          <DropdownMenuContent align="end" className="w-80">
            <DropdownMenuLabel>Notifications</DropdownMenuLabel>
            <DropdownMenuSeparator />
            {notifications?.data?.slice(0, 5).map((notification: any) => (
              <DropdownMenuItem
                key={notification.id}
                onClick={() => router.push("/dashboard/notifications")}
              >
                <div className="flex flex-col gap-1">
                  <p className="text-sm font-medium">{notification.title}</p>
                  <p className="text-xs text-gray-500">{notification.body}</p>
                </div>
              </DropdownMenuItem>
            ))}
            {unreadCount === 0 && (
              <div className="p-4 text-center text-sm text-gray-500">
                No new notifications
              </div>
            )}
            <DropdownMenuSeparator />
            <DropdownMenuItem
              onClick={() => router.push("/dashboard/notifications")}
            >
              View all notifications
            </DropdownMenuItem>
          </DropdownMenuContent>
        </DropdownMenu>

        <DropdownMenu>
          <DropdownMenuTrigger asChild>
            <Button variant="ghost" className="relative h-10 w-10 rounded-full">
              <Avatar className="h-10 w-10">
                <AvatarImage src={user?.image} alt={user?.name} />
                <AvatarFallback>
                  {user?.name
                    ?.split(" ")
                    .map((n: string) => n[0])
                    .join("")}
                </AvatarFallback>
              </Avatar>
            </Button>
          </DropdownMenuTrigger>
          <DropdownMenuContent align="end">
            <DropdownMenuLabel>
              <div className="flex flex-col space-y-1">
                <p className="text-sm font-medium">{user?.name}</p>
                <p className="text-xs text-gray-500">{user?.email}</p>
              </div>
            </DropdownMenuLabel>
            <DropdownMenuSeparator />
            <DropdownMenuItem onClick={() => router.push("/dashboard/profile")}>
              Profile
            </DropdownMenuItem>
            <DropdownMenuItem onClick={() => router.push("/dashboard/settings")}>
              Settings
            </DropdownMenuItem>
            <DropdownMenuSeparator />
            <DropdownMenuItem onClick={() => router.push("/auth/sign-in")}>
              Log out
            </DropdownMenuItem>
          </DropdownMenuContent>
        </DropdownMenu>
      </div>
    </header>
  );
}

"use client";

import * as React from "react";
