"use client";

import React, { useState, useEffect } from "react";

const userAvatar =
  "https://images.unsplash.com/photo-1494790108377-be9c29b29330?w=400&h=400&fit=crop";
const aiAvatar =
  "https://images.unsplash.com/photo-1507003211169-0a1dd7228f2d?w=400&h=400&fit=crop";

interface Message {
  id: number;
  type: "user" | "ai";
  text: string;
  button?: {
    text: string;
    icon?: boolean;
  };
}

const messageSequence: Message[] = [
  {
    id: 1,
    type: "ai",
    text: "Hi! Ready to boost your semester grades? 🎓",
  },
  {
    id: 2,
    type: "user",
    text: "Yes, how do I find past papers?",
  },
  {
    id: 3,
    type: "ai",
    text: "I can help with that! Found 15+ verified papers for you.",
    button: {
      text: "View Resources",
      icon: true,
    },
  },
];

const MessageBubble: React.FC<{ message: Message; isVisible: boolean }> = ({
  message,
  isVisible,
}) => {
  return (
    <div
      className={`transition-all duration-500 ${
        isVisible ? "opacity-100 scale-100" : "opacity-0 scale-95"
      }`}
    >
      {message.type === "ai" ? (
        <div className="flex justify-start items-end gap-3">
          <img
            src={aiAvatar}
            alt="AI Avatar"
            className="w-8 h-8 rounded-full object-cover flex-shrink-0"
          />
          <div className="bg-[#283593] text-white px-6 py-4 rounded-3xl rounded-tl-sm shadow-xl max-w-xs flex flex-col gap-3 border border-white/10">
            <div className="text-sm font-medium leading-snug">
              {message.text}
            </div>
            {message.button && (
              <button className="bg-[#d946ef] text-gray-300 px-5 py-2.5 rounded-xl text-sm font-bold hover:bg-white transition-all duration-300 flex items-center justify-center gap-2 w-full">
                {message.button.text}
                {message.button.icon && (
                  <svg
                    className="w-4 h-4"
                    fill="none"
                    viewBox="0 0 24 24"
                    stroke="currentColor"
                  >
                    <path
                      strokeLinecap="round"
                      strokeLinejoin="round"
                      strokeWidth={2.5}
                      d="M9 5l7 7-7 7"
                    />
                  </svg>
                )}
              </button>
            )}
          </div>
        </div>
      ) : (
        <div className="flex justify-end items-end gap-3">
          <div className="bg-white/10 backdrop-blur-md border border-white/20 text-white px-6 py-3 rounded-3xl rounded-tr-sm shadow-xl max-w-xs">
            <div className="text-sm font-medium leading-snug">
              {message.text}
            </div>
          </div>
          <img
            src={userAvatar}
            alt="User Avatar"
            className="w-8 h-8 rounded-full object-cover flex-shrink-0"
          />
        </div>
      )}
    </div>
  );
};

const ChatUI: React.FC = () => {
  const [displayedMessages, setDisplayedMessages] = useState<Message[]>([]);
  const [currentCycle, setCurrentCycle] = useState(0);

  useEffect(() => {
    const totalMessages = messageSequence.length;
    const interval = setInterval(() => {
      setCurrentCycle((prev) => {
        const next = (prev + 1) % totalMessages;
        return next;
      });
    }, 1200);

    return () => clearInterval(interval);
  }, []);

  useEffect(() => {
    if (currentCycle === 0) {
      setDisplayedMessages([messageSequence[0]]);
    } else {
      setDisplayedMessages(messageSequence.slice(0, currentCycle + 1));
    }
  }, [currentCycle]);

  return (
    <div className="relative z-10 w-full max-w-sm h-[500px] flex flex-col rounded-2xl p-6 overflow-hidden">
      {/* Chat Messages Container */}
      <div className="flex-1 overflow-y-auto flex flex-col gap-4 justify-end scrollbar-hide">
        {displayedMessages.map((message, index) => (
          <div
            key={`${currentCycle}-${message.id}`}
            className="animate-fade-in"
          >
            <MessageBubble message={message} isVisible={true} />
          </div>
        ))}
      </div>

      <style jsx>{`
        @keyframes fadeIn {
          from {
            opacity: 0;
            transform: translateY(10px);
          }
          to {
            opacity: 1;
            transform: translateY(0);
          }
        }

        .animate-fade-in {
          animation: fadeIn 0.4s ease-out;
        }

        .scrollbar-hide {
          -ms-overflow-style: none;
          scrollbar-width: none;
        }

        .scrollbar-hide::-webkit-scrollbar {
          display: none;
        }
      `}</style>
    </div>
  );
};

export default ChatUI;

"use client";

import { Button } from "@/components/ui/button";
import { cn } from "@/lib/utils";
import { 
  ChevronLeft, 
  ChevronRight, 
  ChevronsLeft, 
  ChevronsRight 
} from "lucide-react";

interface PaginationProps {
  currentPage: number;
  totalPages: number;
  onPageChange: (page: number) => void;
  totalItems?: number;
  itemsPerPage?: number;
  itemName?: string;
  className?: string;
}

export function Pagination({
  currentPage,
  totalPages,
  onPageChange,
  totalItems,
  itemsPerPage,
  itemName = "items",
  className,
}: PaginationProps) {
  if (totalPages <= 1 && !totalItems) return null;

  const getPageNumbers = () => {
    const pages = [];
    const maxVisiblePages = 5;
    
    if (totalPages <= maxVisiblePages) {
      for (let i = 1; i <= totalPages; i++) {
        pages.push(i);
      }
    } else {
      let start = Math.max(1, currentPage - 2);
      let end = Math.min(totalPages, start + maxVisiblePages - 1);
      
      if (end === totalPages) {
        start = Math.max(1, end - maxVisiblePages + 1);
      }
      
      for (let i = start; i <= end; i++) {
        pages.push(i);
      }
    }
    return pages;
  };

  return (
    <div className={cn("flex flex-col sm:flex-row items-center justify-between px-6 py-4 bg-gray-50/30 border-t border-gray-100 gap-4", className)}>
      <div className="text-xs text-gray-500 font-medium order-2 sm:order-1 text-center sm:text-left">
        {totalItems ? (
          <>
            Showing <span className="text-black font-bold">{Math.min(itemsPerPage || 0, totalItems)}</span> of <span className="text-black font-bold">{totalItems}</span> {itemName}
          </>
        ) : (
          `Page ${currentPage} of ${totalPages}`
        )}
      </div>
      
      <div className="flex items-center gap-1 order-1 sm:order-2">
        <Button
          variant="outline"
          size="icon"
          onClick={() => onPageChange(1)}
          disabled={currentPage === 1}
          className="h-8 w-8 border-gray-200 text-gray-600 hover:bg-white disabled:opacity-30"
          title="First Page"
        >
          <ChevronsLeft className="h-4 w-4" />
        </Button>
        <Button
          variant="outline"
          size="icon"
          onClick={() => onPageChange(currentPage - 1)}
          disabled={currentPage === 1}
          className="h-8 w-8 border-gray-200 text-gray-600 hover:bg-white disabled:opacity-30"
          title="Previous Page"
        >
          <ChevronLeft className="h-4 w-4" />
        </Button>

        <div className="flex items-center gap-1 mx-1">
          {getPageNumbers().map((pageNum) => (
            <Button
              key={pageNum}
              variant={currentPage === pageNum ? "default" : "outline"}
              size="sm"
              onClick={() => onPageChange(pageNum)}
              className={cn(
                "h-8 w-8 p-0 text-[11px] font-bold transition-all shadow-none border-gray-200",
                currentPage === pageNum 
                  ? "bg-red-600 hover:bg-red-700 text-white shadow-lg shadow-red-500/20 border-0" 
                  : "text-gray-600 hover:bg-white"
              )}
            >
              {pageNum}
            </Button>
          ))}
          {totalPages > 5 && getPageNumbers()[getPageNumbers().length - 1] < totalPages && (
             <span className="text-gray-400 text-xs px-1">...</span>
          )}
        </div>

        <Button
          variant="outline"
          size="icon"
          onClick={() => onPageChange(currentPage + 1)}
          disabled={currentPage === totalPages}
          className="h-8 w-8 border-gray-200 text-gray-600 hover:bg-white disabled:opacity-30"
          title="Next Page"
        >
          <ChevronRight className="h-4 w-4" />
        </Button>
        <Button
          variant="outline"
          size="icon"
          onClick={() => onPageChange(totalPages)}
          disabled={currentPage === totalPages}
          className="h-8 w-8 border-gray-200 text-gray-600 hover:bg-white disabled:opacity-30"
          title="Last Page"
        >
          <ChevronsRight className="h-4 w-4" />
        </Button>
      </div>
    </div>
  );
}

