"use client";

import { useState, useEffect } from "react";
import { useForm, Controller } from "react-hook-form";
import { zodResolver } from "@hookform/resolvers/zod";
import * as z from "zod";
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogFooter,
} from "@/components/ui/dialog";
import { ScrollArea } from "@/components/ui/scroll-area";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Textarea } from "@/components/ui/textarea";
import {
  useUploadBook,
  useUpdateBook,
  useUploadPastPaper,
  useUpdatePastPaper,
  useSubmitJournal,
  useUpdateJournal,
} from "@/hooks/useLibrary";
import { R2ImageUpload } from "@/components/FormInputs/R2ImageUpload";
import { FileCategory } from "@/types/files";
import { Loader2, Plus, X } from "lucide-react";
import { toast } from "sonner";

const bookSchema = z.object({
  title: z.string().min(1, "Title is required"),
  author: z.string().min(1, "Author is required"),
  category: z.string().min(1, "Category is required"),
  description: z.string().optional(),
  coverImage: z.string().optional(),
  fileKey: z.string().min(1, "File is required"),
});

const paperSchema = z.object({
  title: z.string().min(1, "Title is required"),
  subject: z.string().min(1, "Subject is required"),
  courseUnit: z.string().min(1, "Course unit is required"),
  year: z.coerce.number().int().min(2000),
  fileKey: z.string().min(1, "File is required"),
});

const journalSchema = z.object({
  title: z.string().min(1, "Title is required"),
  abstract: z.string().min(1, "Abstract is required"),
  authors: z.array(z.string()).min(1, "At least one author is required"),
  fileKey: z.string().min(1, "File is required"),
});


interface LibraryAssetModalProps {
  open: boolean;
  onOpenChange: (open: boolean) => void;
  type: "book" | "paper" | "journal";
  asset?: any; // If editing
}

export function LibraryAssetModal({
  open,
  onOpenChange,
  type,
  asset,
}: LibraryAssetModalProps) {
  const isEditing = !!asset;
  const [newAuthor, setNewAuthor] = useState("");

  const uploadBook = useUploadBook();
  const updateBook = useUpdateBook();
  const uploadPaper = useUploadPastPaper();
  const updatePaper = useUpdatePastPaper();
  const uploadJournal = useSubmitJournal(); // Admin POST automatically approves
  const updateJournal = useUpdateJournal();

  const getSchema = () => {
    switch (type) {
      case "book": return bookSchema;
      case "paper": return paperSchema;
      case "journal": return journalSchema;
      default: return bookSchema;
    }
  };

  const {
    control,
    handleSubmit,
    reset,
    watch,
    setValue,
    formState: { errors },
  } = useForm({
    resolver: zodResolver(getSchema()),
    defaultValues: {
      title: "",
      author: "",
      category: "",
      description: "",
      coverImage: "",
      subject: "",
      courseUnit: "",
      year: new Date().getFullYear(),
      abstract: "",
      authors: [] as string[],
      fileKey: "",
    },
  });

  useEffect(() => {
    if (asset) {
      const formattedAsset = { ...asset };
      reset(formattedAsset);
    } else {
      reset({
        title: "",
        author: "",
        category: "",
        description: "",
        coverImage: "",
        subject: "",
        courseUnit: "",
        year: new Date().getFullYear(),
        abstract: "",
        authors: [] as string[],
        fileKey: "",
      });
    }
  }, [asset, open, type, reset]);

  const onSubmit = async (data: any) => {
    try {
      if (type === "book") {
        isEditing ? await updateBook.mutateAsync({ id: asset.id, ...data }) : await uploadBook.mutateAsync(data);
      } else if (type === "paper") {
        isEditing ? await updatePaper.mutateAsync({ id: asset.id, ...data }) : await uploadPaper.mutateAsync(data);
      } else if (type === "journal") {
        isEditing ? await updateJournal.mutateAsync({ id: asset.id, ...data }) : await uploadJournal.mutateAsync(data);
      }
      onOpenChange(false);
    } catch (err) {
      // toast handled in hook
    }
  };

  const authors = watch("authors");

  const addAuthor = () => {
    if (newAuthor.trim()) {
      setValue("authors", [...authors, newAuthor.trim()]);
      setNewAuthor("");
    }
  };

  const removeAuthor = (index: number) => {
    setValue("authors", authors.filter((_, i) => i !== index));
  };

  const isLoading = 
    uploadBook.isPending || updateBook.isPending || 
    uploadPaper.isPending || updatePaper.isPending ||
    uploadJournal.isPending || updateJournal.isPending;

  return (
    <Dialog open={open} onOpenChange={onOpenChange}>
      <DialogContent className="max-w-2xl max-h-[90vh] overflow-y-auto bg-white rounded-2xl border-none shadow-2xl p-0">
        <DialogHeader className="p-8 pb-4">
          <DialogTitle className="text-xl font-bold text-black">
            {isEditing ? "Update" : "Add New"} {type.charAt(0).toUpperCase() + type.slice(1)}
          </DialogTitle>
        </DialogHeader>

        <ScrollArea className="max-h-[80vh]">
          <form onSubmit={handleSubmit(onSubmit)} className="px-8 pb-8 space-y-6">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              {/* Common File Upload */}
              <div className="md:col-span-2 space-y-2">
                <Label className="text-xs font-bold uppercase text-gray-500 tracking-wider">Resource File</Label>
                <Controller
                  name="fileKey"
                  control={control}
                  render={({ field }) => (
                    <R2ImageUpload
                      value={field.value}
                      onChange={field.onChange}
                      category={FileCategory.DOCUMENT}
                      identifier="library-asset-resource"
                      multiple={false}
                    />
                  )}
                />
                {errors.fileKey && <p className="text-xs text-red-500">{errors.fileKey.message as string}</p>}
              </div>

              {/* Type Specific Fields */}
              {type === "book" && (
                <>
                  <div className="space-y-2">
                    <Label className="text-xs font-bold uppercase text-gray-400 tracking-wider">Book Title</Label>
                    <Input {...control.register("title")} placeholder="e.g. Modern Physics" className="h-11 border-gray-100 rounded-xl" />
                  </div>
                  <div className="space-y-2">
                    <Label className="text-xs font-bold uppercase text-gray-400 tracking-wider">Author</Label>
                    <Input {...control.register("author")} placeholder="Name of author" className="h-11 border-gray-100 rounded-xl" />
                  </div>
                  <div className="space-y-2">
                    <Label className="text-xs font-bold uppercase text-gray-400 tracking-wider">Category</Label>
                    <Input {...control.register("category")} placeholder="e.g. Science" className="h-11 border-gray-100 rounded-xl" />
                  </div>
                  <div className="md:col-span-2 space-y-2">
                    <Label className="text-xs font-bold uppercase text-gray-400 tracking-wider">Description</Label>
                    <Textarea {...control.register("description")} placeholder="Short summary of the book" className="min-h-[100px] border-gray-100 rounded-xl resize-none" />
                  </div>
                  <div className="md:col-span-2 space-y-2">
                    <Label className="text-xs font-bold uppercase text-gray-400 tracking-wider">Cover Image (Optional)</Label>
                    <Controller
                      name="coverImage"
                      control={control}
                      render={({ field }) => (
                        <R2ImageUpload
                          value={(field.value as string) || ""}
                          onChange={field.onChange}
                          category={FileCategory.GALLERY}
                          identifier="library-book-cover"
                          multiple={false}
                          variant="compact"
                        />
                      )}
                    />
                  </div>
                </>
              )}

              {type === "paper" && (
                <>
                  <div className="space-y-2">
                    <Label className="text-xs font-bold uppercase text-gray-400 tracking-wider">Paper Title</Label>
                    <Input {...control.register("title")} placeholder="e.g. End of Semester Exam 2024" className="h-11 border-gray-100 rounded-xl" />
                  </div>
                  <div className="space-y-2">
                    <Label className="text-xs font-bold uppercase text-gray-400 tracking-wider">Subject</Label>
                    <Input {...control.register("subject")} placeholder="e.g. Software Engineering" className="h-11 border-gray-100 rounded-xl" />
                  </div>
                  <div className="space-y-2">
                    <Label className="text-xs font-bold uppercase text-gray-400 tracking-wider">Course Unit Code</Label>
                    <Input {...control.register("courseUnit")} placeholder="e.g. CS101" className="h-11 border-gray-100 rounded-xl font-mono" />
                  </div>
                  <div className="space-y-2">
                    <Label className="text-xs font-bold uppercase text-gray-400 tracking-wider">Academic Year</Label>
                    <Input type="number" {...control.register("year")} className="h-11 border-gray-100 rounded-xl" />
                  </div>
                </>
              )}

              {type === "journal" && (
                <>
                  <div className="md:col-span-2 space-y-2">
                    <Label className="text-xs font-bold uppercase text-gray-400 tracking-wider">Journal Title</Label>
                    <Input {...control.register("title")} placeholder="Scholarly publication title" className="h-11 border-gray-100 rounded-xl" />
                  </div>
                  <div className="md:col-span-2 space-y-2">
                    <Label className="text-xs font-bold uppercase text-gray-400 tracking-wider">Abstract</Label>
                    <Textarea {...control.register("abstract")} placeholder="Executive summary" className="min-h-[120px] border-gray-100 rounded-xl resize-none" />
                  </div>
                  <div className="md:col-span-2 space-y-2">
                    <Label className="text-xs font-bold uppercase text-gray-400 tracking-wider">Authors</Label>
                    <div className="flex gap-2">
                      <Input 
                        value={newAuthor} 
                        onChange={(e) => setNewAuthor(e.target.value)} 
                        placeholder="Add an author"
                        className="h-11 border-gray-100 rounded-xl"
                        onKeyDown={(e) => { if(e.key === 'Enter') { e.preventDefault(); addAuthor(); }}}
                      />
                      <Button type="button" onClick={addAuthor} variant="secondary" className="h-11 rounded-xl">Add</Button>
                    </div>
                    <div className="flex flex-wrap gap-2 mt-2">
                      {authors.map((author: string, i: number) => (
                        <div key={i} className="bg-red-50 text-red-700 px-3 py-1.5 rounded-full text-[10px] font-bold flex items-center gap-2 border border-red-100">
                          {author}
                          <button type="button" onClick={() => removeAuthor(i)} className="hover:text-red-500 transition-colors">
                            <X className="h-3 w-3" />
                          </button>
                        </div>
                      ))}
                    </div>
                  </div>
                </>
              )}

            </div>

            <DialogFooter className="pt-8 border-t border-gray-50 flex items-center justify-end gap-3 mt-8">
              <Button 
                type="button" 
                variant="ghost" 
                onClick={() => onOpenChange(false)}
                className="h-11 rounded-xl font-bold text-gray-500 px-6 hover:bg-gray-50 transition-all"
              >
                Discard
              </Button>
              <Button 
                type="submit" 
                disabled={isLoading}
                className="bg-red-600 hover:bg-red-700 text-white font-bold h-11 px-8 rounded-xl transition-all shadow-lg shadow-red-100 flex items-center gap-2"
              >
                {isLoading && <Loader2 className="h-4 w-4 animate-spin" />}
                {isEditing ? "Update Resource" : "Publish to Library"}
              </Button>
            </DialogFooter>
          </form>
        </ScrollArea>
      </DialogContent>
    </Dialog>
  );
}

"use client";

import { useState } from "react";
import { useForm, Controller } from "react-hook-form";
import { zodResolver } from "@hookform/resolvers/zod";
import * as z from "zod";
import { Dialog, DialogContent, DialogHeader, DialogTitle } from "@/components/ui/dialog";
import { ScrollArea } from "@/components/ui/scroll-area";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { useStartLecture } from "@/hooks/useLiveLectures";
import { useMyCoursesLecturer } from "@/hooks/useCourses";
import { SelectInput } from "@/components/shared/SelectInput";
import { Video, Loader2, Sparkles, AlertCircle } from "lucide-react";
import { cn } from "@/lib/utils";

const lectureSchema = z.object({
  courseId: z.string().min(1, "Please select a course"),
  meetingUrl: z.string().url("Invalid meeting URL").optional().or(z.literal("")),
});

type LectureFormValues = z.infer<typeof lectureSchema>;

interface LiveLectureModalProps {
  open: boolean;
  onOpenChange: (open: boolean) => void;
}

export function LiveLectureModal({ open, onOpenChange }: LiveLectureModalProps) {
  const [isLoading, setIsLoading] = useState(false);
  const startLecture = useStartLecture();
  const { data: myCourses } = useMyCoursesLecturer();

  const courseOptions = (myCourses || []).map((c: any) => ({
    value: c.id,
    label: c.title,
    description: c.unitCode
  }));

  const { handleSubmit, control, formState: { errors }, reset, setValue } = useForm<LectureFormValues>({
    resolver: zodResolver(lectureSchema),
    defaultValues: {
      courseId: "",
      meetingUrl: "",
    }
  });

  const onSubmit = async (data: LectureFormValues) => {
    try {
      setIsLoading(true);
      // If no meeting URL provided, we could generate a mock one or a Jitsi/Zoom one
      const finalUrl = data.meetingUrl || `https://meet.elearning.edu/${Math.random().toString(36).substring(7)}`;
      
      await startLecture.mutateAsync({
        courseId: data.courseId,
        meetingUrl: finalUrl
      });
      reset();
      onOpenChange(false);
    } catch (error) {
      // Error handled by hook
    } finally {
      setIsLoading(false);
    }
  };

  const generateAutoUrl = () => {
    const randomId = Math.random().toString(36).substring(7);
    setValue("meetingUrl", `https://meet.elearning.edu/${randomId}`);
  };

  return (
    <Dialog open={open} onOpenChange={(val) => {
      if (!val) reset();
      onOpenChange(val);
    }}>
      <DialogContent className="sm:max-w-[450px] p-0 overflow-hidden border-none shadow-2xl">
        <div className="bg-slate-900 p-6 text-white relative overflow-hidden">
          <div className="absolute top-0 right-0 w-32 h-32 bg-red-500/10 rounded-full blur-3xl -mr-16 -mt-16" />
          <DialogHeader>
            <DialogTitle className="text-xl font-bold flex items-center gap-2">
              <div className="bg-red-500/20 p-2 rounded-lg">
                <Video className="h-5 w-5 text-red-400" />
              </div>
              Start Live Session
            </DialogTitle>
          </DialogHeader>
          <p className="text-white/60 text-xs mt-2 font-medium">
            Broadcast to all enrolled students instantly.
          </p>
        </div>

        <ScrollArea className="max-h-[80vh]">
          <form onSubmit={handleSubmit(onSubmit)} className="p-8 bg-white space-y-6">
            <div className="space-y-5">
              <div className="grid gap-2">
                <Label className="text-xs font-bold uppercase text-gray-400 tracking-wider">Select Course</Label>
                <Controller
                  name="courseId"
                  control={control}
                  render={({ field }) => (
                    <SelectInput
                      label="Course"
                      options={courseOptions}
                      value={field.value}
                      onValueChange={field.onChange}
                      placeholder="Choose course to go live..."
                      showDescription
                    />
                  )}
                />
                {errors.courseId && <p className="text-[11px] text-red-500 font-medium">{errors.courseId.message}</p>}
              </div>

              <div className="grid gap-2">
                <div className="flex items-center justify-between">
                  <Label htmlFor="meetingUrl" className="text-xs font-bold uppercase text-gray-400 tracking-wider">Session URL</Label>
                  <button 
                    type="button" 
                    onClick={generateAutoUrl}
                    className="text-[10px] font-bold text-red-600 hover:text-red-700 flex items-center gap-1 transition-colors"
                  >
                    <Sparkles className="h-3 w-3" />
                    Auto-generate
                  </button>
                </div>
                <Controller
                  name="meetingUrl"
                  control={control}
                  render={({ field }) => (
                    <div className="relative">
                       <Input 
                        {...field}
                        placeholder="e.g. https://zoom.us/j/..." 
                        className="h-11 border-gray-100 focus:border-red-500 transition-all rounded-xl text-sm"
                      />
                    </div>
                  )}
                />
                {errors.meetingUrl && <p className="text-[11px] text-red-500 font-medium">{errors.meetingUrl.message}</p>}
                <p className="text-[10px] text-gray-400 italic">Leave empty to use institutional platform.</p>
              </div>

              <div className="p-4 bg-red-50 border border-red-100 rounded-xl">
                <div className="flex gap-3">
                  <AlertCircle className="h-4 w-4 text-red-500 shrink-0 mt-0.5" />
                  <p className="text-[10px] text-red-700 leading-relaxed font-medium">
                    Starting this session will send a real-time notification to all enrolled students.
                  </p>
                </div>
              </div>
            </div>

            <Button 
              type="submit" 
              disabled={isLoading} 
              className="w-full h-12 bg-slate-900 hover:bg-slate-800 text-white rounded-xl font-bold shadow-lg shadow-slate-200 transition-all flex items-center justify-center gap-2 group"
            >
              {isLoading ? (
                <>
                  <Loader2 className="h-4 w-4 animate-spin" />
                  Setting up broadcast...
                </>
              ) : (
                <>
                  <Video className="h-4 w-4 text-red-400 group-hover:scale-110 transition-transform" />
                  Go Live Now
                </>
              )}
            </Button>
          </form>
        </ScrollArea>
      </DialogContent>
    </Dialog>
  );
}

"use client";

import { useState } from "react";
import { useForm, Controller } from "react-hook-form";
import { zodResolver } from "@hookform/resolvers/zod";
import * as z from "zod";
import { Dialog, DialogContent, DialogHeader, DialogTitle } from "@/components/ui/dialog";
import { Button } from "@/components/ui/button";
import { Label } from "@/components/ui/label";
import { useSubmitAssignment } from "@/hooks/useAssignments";
import { ScrollArea } from "@/components/ui/scroll-area";
import { R2ImageUpload } from "@/components/FormInputs/R2ImageUpload";
import { FileCategory } from "@/types/files";
import { Upload, Check, Loader2, FileText, AlertCircle } from "lucide-react";
import { cn } from "@/lib/utils";

const submissionSchema = z.object({
  fileKey: z.string().min(1, "Please upload your work before submitting"),
});

type SubmissionFormValues = z.infer<typeof submissionSchema>;

interface SubmitAssignmentModalProps {
  open: boolean;
  onOpenChange: (open: boolean) => void;
  assignment: {
    id: string;
    title: string;
    courseTitle?: string;
    dueDate?: string;
  };
}

export function SubmitAssignmentModal({ open, onOpenChange, assignment }: SubmitAssignmentModalProps) {
  const [isLoading, setIsLoading] = useState(false);
  const submitAssignment = useSubmitAssignment();

  // Check if deadline has passed
  const isDeadlinePassed = assignment.dueDate ? new Date() > new Date(assignment.dueDate) : false;

  const { handleSubmit, control, formState: { errors }, reset, setValue } = useForm<SubmissionFormValues>({
    resolver: zodResolver(submissionSchema),
    defaultValues: {
      fileKey: "",
    }
  });

  const onSubmit = async (data: SubmissionFormValues) => {
    if (isDeadlinePassed) return;
    try {
      setIsLoading(true);
      await submitAssignment.mutateAsync({
        assignmentId: assignment.id,
        fileKey: data.fileKey,
      });
      reset();
      onOpenChange(false);
    } catch (error) {
      // Error handled by hook
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <Dialog open={open} onOpenChange={(val) => {
      if (!val) reset();
      onOpenChange(val);
    }}>
      <DialogContent className="sm:max-w-[450px] p-0 overflow-hidden border-none shadow-2xl">
        <div className={cn(
          "p-6 text-white text-center transition-colors",
          isDeadlinePassed ? "bg-red-600" : "bg-red-600"
        )}>
          <DialogHeader className="items-center">
            <div className="bg-white/20 p-3 rounded-2xl mb-3 w-fit mx-auto">
              {isDeadlinePassed ? <AlertCircle className="h-6 w-6" /> : <Upload className="h-6 w-6" />}
            </div>
            <DialogTitle className="text-xl font-bold">
              {isDeadlinePassed ? "Submission Closed" : "Submit Your Work"}
            </DialogTitle>
            <p className={cn("text-sm mt-1", isDeadlinePassed ? "text-red-100" : "text-red-100")}>
              {assignment.title}
            </p>
          </DialogHeader>
        </div>

        <ScrollArea className="max-h-[80vh]">
          <form onSubmit={handleSubmit(onSubmit)} className="p-8 bg-white space-y-6">
            {isDeadlinePassed ? (
              <div className="bg-red-50 p-4 rounded-2xl flex items-start gap-3 border border-red-100">
                 <AlertCircle className="h-5 w-5 text-red-600 shrink-0 mt-0.5" />
                 <p className="text-xs text-red-800 leading-relaxed font-bold">
                    The deadline for this assignment was {new Date(assignment.dueDate!).toLocaleString()}. 
                    Submissions are no longer accepted for this task.
                 </p>
              </div>
            ) : (
              <div className="bg-red-50 p-4 rounded-2xl flex items-start gap-3 border border-red-100">
                 <AlertCircle className="h-5 w-5 text-red-600 shrink-0 mt-0.5" />
                 <p className="text-xs text-red-800 leading-relaxed font-medium">
                    Ensure your file is in PDF or Word format and does not exceed 10MB. 
                    You can resubmit before the deadline to overwrite your previous submission.
                 </p>
              </div>
            )}

            <div className={cn("grid gap-4", isDeadlinePassed && "opacity-50 pointer-events-none")}>
              <Label className="text-xs font-bold uppercase text-gray-400 tracking-wider">Upload Assignment File</Label>
              <Controller
                name="fileKey"
                control={control}
                render={({ field }) => (
                  <R2ImageUpload
                    value={field.value || ""}
                    onChange={(url, file: any) => {
                       if (file) {
                          setValue("fileKey", file.key);
                       } else {
                          setValue("fileKey", "");
                       }
                    }}
                    identifier={`submission-${assignment.id}`}
                    category={FileCategory.SUBMISSION}
                    variant="default"
                    acceptedTypes="application/pdf,application/msword,application/vnd.openxmlformats-officedocument.wordprocessingml.document"
                  />
                )}
              />
              {errors.fileKey && <p className="text-[11px] text-red-500 font-bold text-center">{errors.fileKey.message}</p>}
            </div>

            <div className="flex flex-col gap-3 pt-4">
               <Button 
                  type="submit" 
                  disabled={isLoading || isDeadlinePassed} 
                  className="h-12 bg-red-600 hover:bg-red-700 text-white rounded-2xl font-bold shadow-lg shadow-red-200 transition-all flex items-center justify-center text-base"
                >
                  {isLoading ? (
                    <>
                      <Loader2 className="mr-2 h-5 w-5 animate-spin" />
                      Submitting...
                    </>
                  ) : (
                    <>
                      <Check className="mr-2 h-5 w-5" />
                      {isDeadlinePassed ? "Submission Closed" : "Complete Submission"}
                    </>
                  )}
                </Button>
                <Button
                 type="button"
                 variant="ghost"
                 onClick={() => onOpenChange(false)}
                 className="h-10 rounded-xl font-bold text-gray-400 hover:text-gray-600 transition-all"
               >
                 Cancel
               </Button>
            </div>
          </form>
        </ScrollArea>
      </DialogContent>
    </Dialog>
  );
}

"use client";

import { useState, useEffect } from "react";
import { useForm, Controller } from "react-hook-form";
import { zodResolver } from "@hookform/resolvers/zod";
import * as z from "zod";
import { 
  Dialog, 
  DialogContent, 
  DialogHeader, 
  DialogTitle, 
  DialogDescription,
} from "@/components/ui/dialog";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { useUpdateLecturer } from "@/hooks/useAdminLecturers";
import { R2ImageUpload } from "@/components/FormInputs/R2ImageUpload";
import { SelectInput } from "@/components/shared/SelectInput";
import { ScrollArea } from "@/components/ui/scroll-area";
import { motion, AnimatePresence } from "framer-motion";
import { User, Mail, Building, Briefcase, ShieldCheck, Camera, Check, X, Loader2, Edit } from "lucide-react";
import { Lecturer } from "@/types/admin";

const lecturerSchema = z.object({
  name: z.string().min(2, "Name must be at least 2 characters"),
  email: z.string().email("Invalid email address"),
  department: z.string().min(1, "Department is required"),
  specialization: z.string().optional(),
  employeeId: z.string().optional(),
  image: z.string().optional(),
});

type LecturerFormValues = z.infer<typeof lecturerSchema>;

interface UpdateLecturerModalProps {
  open: boolean;
  onOpenChange: (open: boolean) => void;
  lecturer: Lecturer | null;
}

const DEPARTMENTS = [
  { value: "Computer Science", label: "Computer Science" },
  { value: "Information Technology", label: "Information Technology" },
  { value: "Business Administration", label: "Business Administration" },
  { value: "Engineering", label: "Engineering" },
  { value: "Medicine", label: "Medicine" },
  { value: "Law", label: "Law" },
  { value: "Education", label: "Education" },
  { value: "Arts & Humanities", label: "Arts & Humanities" },
];

export function UpdateLecturerModal({
  open,
  onOpenChange,
  lecturer,
}: UpdateLecturerModalProps) {
  const [isLoading, setIsLoading] = useState(false);
  const updateLecturer = useUpdateLecturer();

  const {
    register,
    handleSubmit,
    control,
    formState: { errors },
    reset,
  } = useForm<LecturerFormValues>({
    resolver: zodResolver(lecturerSchema),
  });

  useEffect(() => {
    if (lecturer) {
      reset({
        name: lecturer.name,
        email: lecturer.email,
        department: lecturer.department,
        specialization: lecturer.specialization || "",
        employeeId: lecturer.employeeId || "",
        image: lecturer.image || "",
      });
    }
  }, [lecturer, reset]);

  const onSubmit = async (data: LecturerFormValues) => {
    if (!lecturer) return;
    try {
      setIsLoading(true);
      await updateLecturer.mutateAsync({ id: lecturer.id, ...data });
      onOpenChange(false);
    } catch (error) {
      // Error handled by hook
    } finally {
      setIsLoading(false);
    }
  };

  if (!lecturer) return null;

  return (
    <Dialog open={open} onOpenChange={onOpenChange}>
      <DialogContent className="sm:max-w-[550px] p-0 overflow-hidden rounded-[2rem] border-none shadow-2xl bg-white">
        <div className="bg-gradient-to-br from-indigo-600 to-red-700 p-8 text-white relative overflow-hidden">
            <div className="absolute top-0 right-0 p-8 opacity-10 rotate-12 pointer-events-none">
                <Edit className="h-32 w-32" />
            </div>
            <DialogHeader className="relative z-10 text-center">
                <DialogTitle className="text-2xl font-bold flex items-center justify-center gap-3">
                    <div className="bg-white/20 p-2 rounded-xl backdrop-blur-md">
                        <User className="h-6 w-6 text-white" />
                    </div>
                    Update Academic Profile
                </DialogTitle>
                <DialogDescription className="text-red-50 mt-2 opacity-90">
                    Modifying profile for <span className="font-bold text-white underline decoration-white/30 underline-offset-4">{lecturer.name}</span>
                </DialogDescription>
            </DialogHeader>
        </div>

        <ScrollArea className="max-h-[80vh]">
          <form onSubmit={handleSubmit(onSubmit)} className="p-10 space-y-8">
            <div className="flex flex-col items-center gap-4">
              <Controller
                name="image"
                control={control}
                render={({ field }) => (
                  <div className="relative group">
                    <div className="p-1.5 bg-gradient-to-tr from-red-100 to-indigo-100 rounded-3xl shadow-inner scale-110">
                      <R2ImageUpload
                        identifier={`lecturer-update-${lecturer.id}`}
                        value={field.value || ""}
                        onChange={(url) => field.onChange(url)}
                        variant="compact"
                        className="w-24 h-24 rounded-2xl overflow-hidden"
                        label=""
                      />
                    </div>
                    {field.value && (
                      <div className="absolute -bottom-2 -right-2 bg-green-500 text-white p-1.5 rounded-full shadow-lg border-4 border-white">
                        <Check className="h-3 w-3" />
                      </div>
                    )}
                  </div>
                )}
              />
              <span className="text-[10px] font-black uppercase text-gray-400 tracking-[0.2em]">Update Identity</span>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              <div className="space-y-2.5">
                <Label htmlFor="name" className="text-[10px] font-bold uppercase text-gray-400 tracking-wider flex items-center gap-2 px-1">
                  <User className="h-3 w-3 text-red-500" /> Full Name
                </Label>
                <Input 
                  id="name" 
                  {...register("name")} 
                  placeholder="e.g. Dr. Jane M. Smith" 
                  className="h-12 border-gray-100 rounded-2xl focus:ring-4 focus:ring-red-50/50 bg-gray-50/30 transition-all font-medium" 
                />
                {errors.name && <p className="text-[10px] text-red-500 font-bold px-1">{errors.name.message}</p>}
              </div>

              <div className="space-y-2.5">
                <Label htmlFor="email" className="text-[10px] font-bold uppercase text-gray-400 tracking-wider flex items-center gap-2 px-1">
                  <Mail className="h-3 w-3 text-red-500" /> Professional Email
                </Label>
                <Input 
                  id="email" 
                  type="email" 
                  {...register("email")} 
                  placeholder="jane.smith@ayii.edu" 
                  className="h-12 border-gray-100 rounded-2xl focus:ring-4 focus:ring-red-50/50 bg-gray-50/30 transition-all font-medium" 
                />
                {errors.email && <p className="text-[10px] text-red-500 font-bold px-1">{errors.email.message}</p>}
              </div>
            </div>

            <div className="space-y-2.5">
              <Controller
                name="department"
                control={control}
                render={({ field }) => (
                  <SelectInput
                    label="Academic Department"
                    options={DEPARTMENTS}
                    value={field.value}
                    onValueChange={field.onChange}
                    placeholder="Select primary faculty..."
                    className="h-12 rounded-2xl"
                  />
                )}
              />
              {errors.department && <p className="text-[10px] text-red-500 font-bold px-1">{errors.department.message}</p>}
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              <div className="space-y-2.5">
                <Label htmlFor="specialization" className="text-[10px] font-bold uppercase text-gray-400 tracking-wider flex items-center gap-2 px-1">
                  <Briefcase className="h-3 w-3 text-red-500" /> Expertise Area
                </Label>
                <Input 
                  id="specialization" 
                  {...register("specialization")} 
                  placeholder="Machine Learning" 
                  className="h-12 border-gray-100 rounded-2xl bg-gray-50/30 font-medium" 
                />
              </div>

              <div className="space-y-2.5">
                <Label htmlFor="employeeId" className="text-[10px] font-bold uppercase text-gray-400 tracking-wider flex items-center gap-2 px-1">
                  <ShieldCheck className="h-3 w-3 text-red-500" /> Employee ID
                </Label>
                <Input 
                  id="employeeId" 
                  {...register("employeeId")} 
                  placeholder="EMP-2026-L42" 
                  className="h-12 border-gray-100 rounded-2xl bg-gray-50/30 font-mono text-sm" 
                />
              </div>
            </div>

            <div className="flex items-center justify-between pt-8 border-t border-gray-50 gap-4">
              <Button 
                type="button" 
                variant="ghost" 
                onClick={() => onOpenChange(false)} 
                className="h-12 px-8 rounded-2xl text-gray-400 font-bold hover:bg-gray-50 hover:text-gray-600 transition-all border border-transparent hover:border-gray-100"
              >
                Discard Changes
              </Button>
              <Button 
                type="submit" 
                disabled={isLoading} 
                className="h-12 px-10 bg-red-600 hover:bg-red-700 text-white rounded-2xl font-bold shadow-xl shadow-red-500/20 transition-all flex items-center gap-2 group"
              >
                {isLoading ? (
                  <Loader2 className="h-4 w-4 animate-spin" />
                ) : (
                  <>
                    <span>Save Changes</span>
                    <Check className="h-4 w-4 group-hover:scale-110 transition-transform" />
                  </>
                )}
              </Button>
            </div>
          </form>
        </ScrollArea>
      </DialogContent>
    </Dialog>
  );
}

"use client";

import { useState, useEffect } from "react";
import { useForm } from "react-hook-form";
import { zodResolver } from "@hookform/resolvers/zod";
import * as z from "zod";
import { Dialog, DialogContent, DialogHeader, DialogTitle } from "@/components/ui/dialog";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { useUpdateStudent } from "@/hooks/useAdminStudents";
import { User, Mail, Building2, GraduationCap, Loader2, Check, UserCircle } from "lucide-react";
import { cn } from "@/lib/utils";
import { R2ImageUpload } from "@/components/FormInputs/R2ImageUpload";
import { ScrollArea } from "@/components/ui/scroll-area";
import { FileCategory } from "@/types/files";

const studentSchema = z.object({
  name: z.string().min(2, "Name must be at least 2 characters"),
  email: z.string().email("Invalid email address"),
  department: z.string().min(2, "Department is required"),
  program: z.string().optional(),
  image: z.string().optional(),
});

type StudentFormValues = z.infer<typeof studentSchema>;

interface UpdateStudentModalProps {
  open: boolean;
  onOpenChange: (open: boolean) => void;
  student: any; // The student object to edit
}

export function UpdateStudentModal({ open, onOpenChange, student }: UpdateStudentModalProps) {
  const [isLoading, setIsLoading] = useState(false);
  const updateStudent = useUpdateStudent();

  const { register, handleSubmit, formState: { errors }, reset, setValue, watch } = useForm<StudentFormValues>({
    resolver: zodResolver(studentSchema),
    defaultValues: {
      name: "",
      email: "",
      department: "",
      program: "",
      image: "",
    }
  });

  const image = watch("image");

  useEffect(() => {
    if (student) {
      reset({
        name: student.name || "",
        email: student.email || "",
        department: student.department || "",
        program: student.program || "",
        image: student.image || "",
      });
    }
  }, [student, reset]);

  const onSubmit = async (data: StudentFormValues) => {
    try {
      setIsLoading(true);
      await updateStudent.mutateAsync({
        id: student.id,
        ...data
      });
      onOpenChange(false);
    } catch (error) {
      // Handled by hook
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <Dialog open={open} onOpenChange={onOpenChange}>
      <DialogContent className="sm:max-w-[500px] p-0 overflow-hidden border-none shadow-2xl">
