              Edit Student Profile
            </DialogTitle>
            <p className="text-red-100 text-sm mt-1">Update global profile and institutional records</p>
          </DialogHeader>
        </div>

        <ScrollArea className="max-h-[80vh]">
          <form onSubmit={handleSubmit(onSubmit)} className="p-8 bg-white space-y-6">
            <div className="flex justify-center -mt-16 relative z-20">
              <div className="p-1 bg-white rounded-2xl shadow-xl">
                <R2ImageUpload
                  identifier={`student-avatar-${student?.id}`}
                  value={image || ""}
                  onChange={(url) => setValue("image", url as string)}
                  category={FileCategory.PROFILE}
                  variant="minimal"
                  className="w-24 h-24"
                />
              </div>
            </div>

            <div className="space-y-5">
               {/* Read-only ID Section */}
               <div className="p-4 bg-gray-50 border border-gray-100 rounded-2xl flex items-center justify-between">
                  <div className="flex flex-col">
                     <span className="text-[10px] font-bold text-gray-400 uppercase tracking-widest">Institutional Identity</span>
                     <span className="text-lg font-black text-red-600 font-mono tracking-tighter">{student?.registrationNumber}</span>
                  </div>
                  <div className="h-10 w-10 rounded-full bg-red-100/50 flex items-center justify-center">
                     <Check className="h-5 w-5 text-red-600" />
                  </div>
               </div>

              <div className="grid gap-2">
                <Label htmlFor="name" className="text-xs font-bold uppercase text-gray-400 tracking-wider">Full Legal Name</Label>
                <div className="relative">
                  <User className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-gray-400" />
                  <Input 
                    id="name" 
                    {...register("name")} 
                    className="pl-10 h-11 border-gray-100 focus:border-red-500 transition-all rounded-xl"
                  />
                </div>
                {errors.name && <p className="text-[11px] text-red-500 font-medium">{errors.name.message}</p>}
              </div>

              <div className="grid grid-cols-2 gap-4">
                <div className="grid gap-2">
                  <Label htmlFor="email" className="text-xs font-bold uppercase text-gray-400 tracking-wider">Email Address</Label>
                  <div className="relative">
                    <Mail className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-gray-400" />
                    <Input 
                      id="email" 
                      {...register("email")} 
                      className="pl-10 h-11 border-gray-100 focus:border-red-500 transition-all rounded-xl text-sm"
                    />
                  </div>
                  {errors.email && <p className="text-[11px] text-red-500 font-medium">{errors.email.message}</p>}
                </div>

                <div className="grid gap-2">
                  <Label htmlFor="department" className="text-xs font-bold uppercase text-gray-400 tracking-wider">Faculty/Dept</Label>
                  <div className="relative">
                    <Building2 className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-gray-400" />
                    <Input 
                      id="department" 
                      {...register("department")} 
                      className="pl-10 h-11 border-gray-100 focus:border-red-500 transition-all rounded-xl text-sm"
                    />
                  </div>
                  {errors.department && <p className="text-[11px] text-red-500 font-medium">{errors.department.message}</p>}
                </div>
              </div>

              <div className="grid gap-2">
                <Label htmlFor="program" className="text-xs font-bold uppercase text-gray-400 tracking-wider">Academic Program</Label>
                <div className="relative">
                  <GraduationCap className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-gray-400" />
                  <Input 
                    id="program" 
                    {...register("program")} 
                    placeholder="e.g. BSc. Computer Science"
                    className="pl-10 h-11 border-gray-100 focus:border-red-500 transition-all rounded-xl"
                  />
                </div>
              </div>
            </div>

            <div className="flex items-center gap-3 pt-4">
               <Button
                 type="button"
                 variant="ghost"
                 onClick={() => onOpenChange(false)}
                 className="h-11 flex-1 rounded-xl font-semibold transition-all hover:bg-gray-50"
               >
                 Discard
               </Button>
               <Button 
                  type="submit" 
                  disabled={isLoading} 
                  className="h-11 flex-[2] bg-red-600 hover:bg-red-700 text-white rounded-xl font-bold shadow-lg shadow-red-200 transition-all flex items-center justify-center gap-2"
                >
                  {isLoading ? (
                    <>
                      <Loader2 className="h-4 w-4 animate-spin" />
                      Saving Changes...
                    </>
                  ) : (
                    <>
                      <Check className="h-4 w-4" />
                      Update Profile
                    </>
                  )}
                </Button>
            </div>
          </form>
        </ScrollArea>
      </DialogContent>
    </Dialog>
  );
}

"use client";

import { useState } from "react";
import { Dialog, DialogContent, DialogHeader, DialogTitle } from "@/components/ui/dialog";
import { ScrollArea } from "@/components/ui/scroll-area";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Textarea } from "@/components/ui/textarea";
import { useSubmissions, useGradeSubmission } from "@/hooks/useAssignments";
import { Avatar, AvatarFallback, AvatarImage } from "@/components/ui/avatar";
import { Badge } from "@/components/ui/badge";
import { 
  Users, 
  Download, 
  CheckCircle2, 
  Clock, 
  AlertCircle,
  Loader2,
  ExternalLink,
  Search,
  Check
} from "lucide-react";
import { cn } from "@/lib/utils";
import { Separator } from "@/components/ui/separator";

interface ViewSubmissionsModalProps {
  open: boolean;
  onOpenChange: (open: boolean) => void;
  assignment: {
    id: string;
    title: string;
  };
}

export function ViewSubmissionsModal({ open, onOpenChange, assignment }: ViewSubmissionsModalProps) {
  const { data: submissions, isLoading } = useSubmissions(assignment.id);
  const gradeSubmission = useGradeSubmission();
  const [selectedSubmissionId, setSelectedSubmissionId] = useState<string | null>(null);
  const [grade, setGrade] = useState("");
  const [feedback, setFeedback] = useState("");
  const [search, setSearch] = useState("");

  const filteredSubmissions = (submissions || []).filter((s: any) => 
    s.student.name?.toLowerCase().includes(search.toLowerCase()) ||
    s.student.registrationNumber?.toLowerCase().includes(search.toLowerCase())
  );

  const selectedSubmission = submissions?.find((s: any) => s.id === selectedSubmissionId);

  const handleGrade = async () => {
    if (!selectedSubmissionId) return;
    try {
      await gradeSubmission.mutateAsync({
        submissionId: selectedSubmissionId,
        assignmentId: assignment.id,
        grade,
        feedback,
      });
      setSelectedSubmissionId(null);
      setGrade("");
      setFeedback("");
    } catch (error) {
       // Handled by hook
    }
  };

  const handleOpenGrade = (sub: any) => {
    setSelectedSubmissionId(sub.id);
    setGrade(sub.grade || "");
    setFeedback(sub.feedback || "");
  };

  return (
    <Dialog open={open} onOpenChange={onOpenChange}>
      <DialogContent className="sm:max-w-[700px] p-0 overflow-hidden border-none shadow-2xl h-[600px] flex flex-col">
        <div className="bg-slate-900 p-6 text-white shrink-0">
          <DialogHeader>
            <DialogTitle className="text-xl font-bold flex items-center gap-3">
              <div className="bg-primary/20 p-2 rounded-lg">
                <Users className="h-5 w-5 text-primary" />
              </div>
              <div className="flex flex-col">
                <span>Assignment Submissions</span>
                <span className="text-xs text-slate-400 font-medium">Viewing results for: {assignment.title}</span>
              </div>
            </DialogTitle>
          </DialogHeader>
        </div>

        <div className="flex-1 overflow-hidden flex flex-col bg-white">
          <div className="p-4 border-b border-slate-50 flex items-center gap-4 bg-slate-50/50">
            <div className="relative flex-1">
               <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-slate-400" />
               <Input 
                placeholder="Search student by name or ID..." 
                value={search}
                onChange={(e) => setSearch(e.target.value)}
                className="pl-10 h-10 border-slate-200 focus:border-primary rounded-xl text-sm"
               />
            </div>
            <div className="flex items-center gap-2">
               <Badge className="bg-primary/10 text-primary border-none text-[10px] uppercase font-bold px-2 py-0.5">
                  {submissions?.length || 0} Total
               </Badge>
            </div>
          </div>

          <ScrollArea className="flex-1">
            <div className="p-4 space-y-3">
              {isLoading ? (
                <div className="flex h-40 items-center justify-center">
                  <Loader2 className="h-8 w-8 animate-spin text-primary" />
                </div>
              ) : filteredSubmissions.length === 0 ? (
                <div className="flex flex-col items-center justify-center h-40 text-slate-400 space-y-2">
                  <AlertCircle className="h-10 w-10 opacity-20" />
                  <p className="text-sm font-medium">No submissions found.</p>
                </div>
              ) : (
                filteredSubmissions.map((sub: any) => (
                  <div key={sub.id} className="p-4 rounded-2xl border border-slate-100 hover:border-primary/20 hover:shadow-sm transition-all group flex items-center justify-between">
                    <div className="flex items-center gap-3">
                      <Avatar className="h-10 w-10 border-2 border-slate-50">
                        <AvatarImage src={sub.student.image} />
                        <AvatarFallback className="bg-primary/5 text-primary text-xs font-bold">
                           {sub.student.name?.substring(0, 2).toUpperCase()}
                        </AvatarFallback>
                      </Avatar>
                      <div className="flex flex-col">
                        <span className="text-sm font-bold text-slate-900 leading-none mb-1">{sub.student.name}</span>
                        <span className="text-[10px] font-bold text-slate-400 uppercase tracking-tighter">
                          {sub.student.registrationNumber || "N/A"} • Submitted {new Date(sub.submittedAt).toLocaleDateString()}
                        </span>
                      </div>
                    </div>

                    <div className="flex items-center gap-2">
                      {sub.grade ? (
                         <Badge className="bg-green-50 text-green-600 border-none text-[10px] font-bold h-7 px-3 flex items-center gap-1.5">
                            <CheckCircle2 className="h-3 w-3" />
                            Grade: {sub.grade}
                         </Badge>
                      ) : (
                         <Badge className="bg-orange-50 text-orange-600 border-none text-[10px] font-bold h-7 px-3 flex items-center gap-1.5">
                            <Clock className="h-3 w-3" />
                            Pending
                         </Badge>
                      )}
                      <Separator orientation="vertical" className="h-8 mx-1 opacity-20" />
                      <Button 
                          size="sm" 
                          variant="ghost" 
                          className="h-9 w-9 p-0 rounded-xl hover:bg-primary/5 text-primary"
                          asChild
                      >
                          <a href={`/api/r2/download?key=${sub.fileKey}`} download>
                             <Download className="h-4 w-4" />
                          </a>
                      </Button>
                      <Button 
                          size="sm" 
                          onClick={() => handleOpenGrade(sub)}
                          className="h-9 px-4 rounded-xl bg-slate-900 hover:bg-slate-800 text-white font-bold text-xs"
                      >
                          {sub.grade ? "Update Grade" : "Grade"}
                      </Button>
                    </div>
                  </div>
                ))
              )}
            </div>
          </ScrollArea>
        </div>

        {/* Grading Overlay */}
        {selectedSubmissionId && (
          <div className="absolute inset-0 bg-white z-50 flex flex-col animate-in slide-in-from-bottom duration-300">
             <div className="p-6 border-b border-slate-50 flex items-center justify-between">
                <div className="flex items-center gap-3">
                   <div className="bg-slate-900 p-2 rounded-lg">
                      <CheckCircle2 className="h-5 w-5 text-white" />
                   </div>
                   <div>
                      <h4 className="font-bold text-slate-900">Grading {selectedSubmission?.student.name}</h4>
                      <p className="text-xs text-slate-400">Assignment: {assignment.title}</p>
                   </div>
                </div>
                <Button variant="ghost" onClick={() => setSelectedSubmissionId(null)} className="rounded-full h-8 w-8 p-0">
                   <AlertCircle className="h-5 w-5 rotate-45" />
                </Button>
             </div>
             <div className="p-8 space-y-6 flex-1">
                <div className="grid gap-2">
                   <Label className="text-xs font-bold uppercase text-slate-400">Score / Grade</Label>
                   <Input 
                    placeholder="e.g. A, 85/100, Pass..." 
                    value={grade}
                    onChange={(e) => setGrade(e.target.value)}
                    className="h-12 border-slate-200 focus:border-primary rounded-xl"
                   />
                </div>
                <div className="grid gap-2">
                   <Label className="text-xs font-bold uppercase text-slate-400">Review Feedback</Label>
                   <Textarea 
                    placeholder="Write constructive feedback for the student..." 
                    value={feedback}
                    onChange={(e) => setFeedback(e.target.value)}
                    className="min-h-[160px] border-slate-200 focus:border-primary rounded-2xl resize-none p-4"
                   />
                </div>
             </div>
             <div className="p-6 border-t border-slate-50 flex items-center gap-3">
                <Button variant="ghost" onClick={() => setSelectedSubmissionId(null)} className="h-12 flex-1 rounded-2xl font-bold">
                   Cancel
                </Button>
                <Button 
                    onClick={handleGrade} 
                    disabled={!grade || gradeSubmission.isPending}
                    className="h-12 flex-[2] bg-primary hover:bg-primary/90 text-white rounded-2xl font-bold shadow-lg shadow-primary/20"
                >
                   {gradeSubmission.isPending ? <Loader2 className="animate-spin h-5 w-5" /> : <Check className="h-5 w-5 mr-2" />}
                   Save Grade & Feedback
                </Button>
             </div>
          </div>
        )}
      </DialogContent>
    </Dialog>
  );
}

"use client"

import * as React from "react"
import * as RechartsPrimitive from "recharts"

import { cn } from "@/lib/utils"

// Format: { [key: string]: { label: string; color?: string } }
export type ChartConfig = {
  [k: string]: {
    label: React.ReactNode
    icon?: React.ComponentType
  } & (
    | { color?: string; theme?: never }
    | { color?: never; theme: Record<string, string> }
  )
}

type ChartContextProps = {
  config: ChartConfig
}

const ChartContext = React.createContext<ChartContextProps | null>(null)

function useChart() {
  const context = React.useContext(ChartContext)

  if (!context) {
    throw new Error("useChart must be used within a ChartContainer.")
  }

  return context
}

const ChartContainer = React.forwardRef<
  HTMLDivElement,
  React.ComponentProps<"div"> & {
    config: ChartConfig
    children: React.ComponentProps<typeof RechartsPrimitive.ResponsiveContainer>["children"]
  }
>(({ id, className, config, children, ...props }, ref) => {
  const uniqueId = React.useId()
  const chartId = `chart-${id || uniqueId.replace(/:/g, "")}`

  return (
    <ChartContext.Provider value={{ config }}>
      <div
        ref={ref}
        data-chart={chartId}
        className={cn(
          "flex aspect-video justify-center text-xs [&_.recharts-cartesian-axis-tick_text]:fill-muted-foreground [&_.recharts-cartesian-grid_line[stroke='#ccc']]:stroke-border/50 [&_.recharts-curve.recharts-tooltip-cursor]:stroke-border [&_.recharts-dot[stroke='#fff']]:stroke-transparent [&_.recharts-layer]:outline-none [&_.recharts-polar-grid_[stroke='#ccc']]:stroke-border [&_.recharts-radar-cursor]:fill-muted [&_.recharts-rectangle.recharts-tooltip-cursor]:fill-muted [&_.recharts-reference-line_[stroke='#ccc']]:stroke-border [&_.recharts-sector[stroke='#fff']]:stroke-transparent [&_.recharts-sector]:outline-none [&_.recharts-surface]:outline-none",
          className
        )}
        {...props}
      >
        <ChartStyle id={chartId} config={config} />
        <RechartsPrimitive.ResponsiveContainer>
          {children}
        </RechartsPrimitive.ResponsiveContainer>
      </div>
    </ChartContext.Provider>
  )
})
ChartContainer.displayName = "Chart"

const ChartStyle = ({ id, config }: { id: string; config: ChartConfig }) => {
  const colorConfig = Object.entries(config).filter(
    ([_, config]) => config.theme || config.color
  )

  if (!colorConfig.length) {
    return null
  }

  return (
    <style
      dangerouslySetInnerHTML={{
        __html: Object.entries(config).map(([key, item]) => {
          const color = item.color || item.theme?.light
          return `
            [data-chart="${id}"] {
              --color-${key}: ${color};
            }
          `
        }).join(""),
      }}
    />
  )
}

const ChartTooltip = RechartsPrimitive.Tooltip

const ChartTooltipContent = React.forwardRef<
  HTMLDivElement,
  React.ComponentProps<typeof RechartsPrimitive.Tooltip> &
    React.ComponentProps<"div"> & {
      hideLabel?: boolean
      hideIndicator?: boolean
      indicator?: "line" | "dot" | "dashed"
      nameKey?: string
      labelKey?: string
    }
>(
  (
    {
      hideLabel = false,
      hideIndicator = false,
      labelFormatter,
      labelClassName,
      formatter,
      color,
      nameKey,
      labelKey,
      ...props
    },
    ref
  ) => {
    const { config } = useChart()
    const payload = (props as any).payload
    const label = (props as any).label
    const active = (props as any).active
    const indicator = (props as any).indicator || "dot"
    const className = (props as any).className

    const tooltipLabel = React.useMemo(() => {
      if (hideLabel || !payload?.length) {
        return null
      }

      const [item] = payload
      const key = `${labelKey || item.dataKey || item.name || "value"}`
      const itemConfig = getPayloadConfigFromCustomKey(config, item, key)
      const value =
        !labelKey && typeof label === "string"
          ? config[label as keyof typeof config]?.label || label
          : itemConfig?.label

      if (labelFormatter) {
        return (
          <div className={cn("font-medium", labelClassName)}>
            {labelFormatter(value, payload)}
          </div>
        )
      }

      if (!value) {
        return null
      }

      return <div className={cn("font-medium", labelClassName)}>{value}</div>
    }, [
      label,
      labelFormatter,
      payload,
      hideLabel,
      labelClassName,
      config,
      labelKey,
    ])

    if (!active || !payload?.length) {
      return null
    }

    const nestLabel = payload.length === 1 && indicator !== "dot"

    return (
      <div
        ref={ref}
        className={cn(
          "grid min-w-[8rem] items-start gap-1.5 rounded-lg border bg-background px-2.5 py-1.5 text-xs shadow-xl",
          className
        )}
      >
        {!nestLabel ? tooltipLabel : null}
        <div className="grid gap-1.5">
          {payload.map((item: any, index: number) => {
            const key = `${nameKey || item.name || item.dataKey || "value"}`
            const itemConfig = getPayloadConfigFromCustomKey(config, item, key)
            const indicatorColor = color || item.payload.fill || item.color

            return (
              <div
                key={item.dataKey}
                className={cn(
                  "flex w-full flex-wrap items-stretch gap-2 [&>svg]:h-2.5 [&>svg]:w-2.5 [&>svg]:text-muted-foreground",
                  indicator === "dot" && "items-center"
                )}
              >
                {formatter && item?.value !== undefined && item.name ? (
                  formatter(item.value, item.name, item, index, payload)
                ) : (
                  <>
                    {itemConfig?.icon ? (
                      <itemConfig.icon />
                    ) : (
                      !hideIndicator && (
                        <div
                          className={cn(
                            "shrink-0 rounded-[2px] border-[--color-border] bg-[--color-bg]",
                            {
                              "h-2.5 w-2.5": indicator === "dot",
                              "w-1": indicator === "line",
                              "w-0 border-l-2 border-dashed bg-transparent":
                                indicator === "dashed",
                              "nest-label": nestLabel && indicator === "dashed",
                            }
                          )}
                          style={
                            {
                              "--color-bg": indicatorColor,
                              "--color-border": indicatorColor,
                            } as React.CSSProperties
                          }
                        />
                      )
                    )}
                    <div
                      className={cn(
                        "flex flex-1 justify-between leading-none",
                        nestLabel ? "items-end" : "items-center"
                      )}
                    >
                      <div className="grid gap-1.5">
                        {nestLabel ? tooltipLabel : null}
                        <span className="text-muted-foreground">
                          {itemConfig?.label || item.name}
                        </span>
                      </div>
                      {item.value && (
                        <span className="font-mono font-medium tabular-nums text-foreground">
                          {item.value.toLocaleString()}
                        </span>
                      )}
                    </div>
                  </>
                )}
              </div>
            )
          })}
        </div>
      </div>
    )
  }
)
ChartTooltipContent.displayName = "ChartTooltip"

const ChartLegend = RechartsPrimitive.Legend

const ChartLegendContent = React.forwardRef<
  HTMLDivElement,
  React.ComponentProps<"div"> &
    Pick<any, "payload" | "verticalAlign"> & {
      hideIcon?: boolean
      nameKey?: string
    }
>(({ className, hideIcon = false, payload, verticalAlign = "bottom", nameKey }, ref) => {
  const { config } = useChart()

  const safePayload = payload as any[]
  if (!safePayload?.length) {
    return null
  }

  return (
    <div
      ref={ref}
      className={cn(
        "flex items-center justify-center gap-4",
        verticalAlign === "top" ? "pb-3" : "pt-3",
        className
      )}
    >
      {safePayload.map((item: any) => {
        const key = `${nameKey || item.dataKey || "value"}`
        const itemConfig = getPayloadConfigFromCustomKey(config, item, key)

        return (
          <div
            key={item.value}
            className={cn(
              "flex items-center gap-1.5 [&>svg]:h-3 [&>svg]:w-3 [&>svg]:text-muted-foreground"
            )}
          >
            {itemConfig?.icon && !hideIcon ? (
              <itemConfig.icon />
            ) : (
              <div
                className="h-2 w-2 shrink-0 rounded-[2px]"
                style={{
                  backgroundColor: item.color,
                }}
              />
            )}
            {itemConfig?.label}
          </div>
        )
      })}
    </div>
  )
})
ChartLegendContent.displayName = "ChartLegend"

// Helper to extract item config from a payload.
function getPayloadConfigFromCustomKey(
  config: ChartConfig,
  payload: unknown,
  key: string
) {
  if (typeof payload !== "object" || payload === null) {
    return undefined
  }

  const payloadPayload =
    "payload" in payload &&
    typeof payload.payload === "object" &&
    payload.payload !== null
      ? payload.payload
      : undefined

  let configLabelKey: string = key

  if (
    key in payload &&
    typeof payload[key as keyof typeof payload] === "string"
  ) {
    configLabelKey = payload[key as keyof typeof payload] as string
  } else if (
    payloadPayload &&
    key in payloadPayload &&
    typeof payloadPayload[key as keyof typeof payloadPayload] === "string"
  ) {
    configLabelKey = payloadPayload[key as keyof typeof payloadPayload] as string
  }

  return configLabelKey in config
    ? config[configLabelKey]
    : config[key as keyof typeof config]
}

export {
  ChartContainer,
  ChartTooltip,
  ChartTooltipContent,
  ChartLegend,
  ChartLegendContent,
  ChartStyle,
}

"use client";

import {
  File,
  Image as ImageIcon,
  Loader2,
  Trash2,
  Upload,
  X,
} from "lucide-react";
import { useCallback, useEffect, useState } from "react";
import type { FileRejection } from "react-dropzone";
import { useDropzone } from "react-dropzone";
import { toast } from "sonner";
import { v4 as uuidv4 } from "uuid";

import { Button } from "@/components/ui/button";
import { Card, CardContent } from "@/components/ui/card";
import { cn } from "@/lib/utils";

export interface FileWithMetadata {
  id: string;
  file: File;
  uploading: boolean;
  progress: number;
  key?: string;
  provider?: string;
  publicUrl?: string;
  isDeleting: boolean;
  error: boolean;
  objectUrl?: string;
}

interface DropzoneProps {
  provider: "aws" | "cloudflare";
  variant?: "default" | "compact" | "minimal" | "avatar" | "inline";
  accept?: Record<string, string[]>;
  maxFiles?: number;
  maxSize?: number;
  onFilesChange?: (files: FileWithMetadata[]) => void;
  className?: string;
  disabled?: boolean;
  helperText?: string;
}

/**
 * Extract key from S3/R2 public URL
 * Example: https://bucket.s3.region.amazonaws.com/key.png -> key.png
 */
export function extractKeyFromUrl(url: string): string | null {
  if (!url) return null;
  try {
    const urlObj = new URL(url);
    // Remove leading slash and return the path
    return urlObj.pathname.substring(1);
  } catch (error) {
    console.error("Error extracting key from URL:", error);
    return null;
  }
}

export function Dropzone({
  provider,
  variant = "default",
  accept = {
    "image/*": [],
    "application/pdf": [],
    "application/msword": [],
    "application/vnd.openxmlformats-officedocument.wordprocessingml.document":
      [],
    "application/zip": [],
  },
  maxFiles = 5,
  maxSize = 1024 * 1024 * 10, // 10MB
  onFilesChange,
  className,
  disabled = false,
  helperText,
}: DropzoneProps) {
  const [files, setFiles] = useState<FileWithMetadata[]>([]);

  useEffect(() => {
    onFilesChange?.(files);
  }, [files, onFilesChange]);

  const removeFile = async (fileId: string) => {
    try {
      const fileToRemove = files.find((f) => f.id === fileId);
      if (!fileToRemove) return;

      if (fileToRemove.objectUrl) {
        URL.revokeObjectURL(fileToRemove.objectUrl);
      }

      setFiles((prevFiles) =>
        prevFiles.map((f) => (f.id === fileId ? { ...f, isDeleting: true } : f))
      );

      // Only attempt to delete from server if the file was successfully uploaded
      if (fileToRemove.key && fileToRemove.publicUrl) {
        const endpoint =
          provider === "aws" ? "/api/s3/delete" : "/api/r2/delete";
        const response = await fetch(endpoint, {
          method: "DELETE",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify({ key: fileToRemove.key }),
        });

        if (!response.ok) {
          toast.error("Failed to delete file from server");
          setFiles((prevFiles) =>
            prevFiles.map((f) =>
              f.id === fileId ? { ...f, isDeleting: false, error: true } : f
            )
          );
          return;
        }
      }

      setFiles((prevFiles) => prevFiles.filter((f) => f.id !== fileId));
      toast.success("File removed successfully");
    } catch (error) {
      console.log(error);
      toast.error("Failed to delete file");
      setFiles((prevFiles) =>
        prevFiles.map((f) =>
          f.id === fileId ? { ...f, isDeleting: false, error: true } : f
        )
      );
    }
  };

  const uploadFile = async (file: File) => {
    setFiles((prevFiles) =>
      prevFiles.map((f) => (f.file === file ? { ...f, uploading: true } : f))
    );

    try {
      const endpoint = provider === "aws" ? "/api/s3/upload" : "/api/r2/upload";
      const presignedResponse = await fetch(endpoint, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          filename: file.name,
          contentType: file.type,
          size: file.size,
        }),
      });

      if (!presignedResponse.ok) {
        toast.error("Failed to get presigned URL");
        setFiles((prevFiles) =>
          prevFiles.map((f) =>
            f.file === file
              ? { ...f, uploading: false, progress: 0, error: true }
              : f
          )
        );
        return;
      }

      const { presignedUrl, key, publicUrl } = await presignedResponse.json();

      await new Promise<void>((resolve, reject) => {
        const xhr = new XMLHttpRequest();

        xhr.upload.onprogress = (event) => {
          if (event.lengthComputable) {
            const percentComplete = (event.loaded / event.total) * 100;
            setFiles((prevFiles) =>
              prevFiles.map((f) =>
                f.file === file
                  ? {
                      ...f,
                      progress: Math.round(percentComplete),
                      key: key,
                      publicUrl: publicUrl,
                      provider: provider,
                    }
                  : f
              )
            );
          }
        };

        xhr.onload = () => {
          if (xhr.status === 200 || xhr.status === 204) {
            setFiles((prevFiles) =>
              prevFiles.map((f) =>
                f.file === file
                  ? { ...f, progress: 100, uploading: false, error: false }
                  : f
              )
            );
            toast.success("File uploaded successfully");
            resolve();
          } else {
            reject(new Error(`Upload failed with status: ${xhr.status}`));
          }
        };

        xhr.onerror = () => {
          reject(new Error("Upload failed"));
        };

        xhr.open("PUT", presignedUrl);
        xhr.setRequestHeader("Content-Type", file.type);
        xhr.send(file);
      });
    } catch (error) {
      console.log(error);
      toast.error("Upload failed");
      setFiles((prevFiles) =>
        prevFiles.map((f) =>
          f.file === file
            ? { ...f, uploading: false, progress: 0, error: true }
            : f
        )
      );
    }
  };

  const onDrop = useCallback((acceptedFiles: File[]) => {
    if (acceptedFiles.length) {
      setFiles((prevFiles) => [
        ...prevFiles,
        ...acceptedFiles.map((file) => ({
          id: uuidv4(),
          file,
          uploading: false,
          progress: 0,
          isDeleting: false,
          error: false,
          objectUrl: URL.createObjectURL(file),
        })),
      ]);

      acceptedFiles.forEach(uploadFile);
    }
  }, []);

  const onDropRejected = useCallback(
    (fileRejections: FileRejection[]) => {
      if (fileRejections.length) {
        const tooManyFiles = fileRejections.find(
          (rejection) => rejection.errors[0].code === "too-many-files"
        );
        const fileTooLarge = fileRejections.find(
          (rejection) => rejection.errors[0].code === "file-too-large"
        );

        if (tooManyFiles) {
          toast.error(`Too many files. Maximum ${maxFiles} files allowed.`);
        }
        if (fileTooLarge) {
          toast.error(
            `File too large. Maximum ${maxSize / (1024 * 1024)}MB allowed.`
          );
        }
      }
    },
    [maxFiles, maxSize]
  );

  const { getRootProps, getInputProps, isDragActive } = useDropzone({
    onDrop,
    onDropRejected,
    maxFiles,
    maxSize,
    accept,
    disabled,
  });

  // Render variants
  if (variant === "avatar") {
    const currentFile = files[0];
    return (
      <div className={cn("relative", className)}>
        <div
          {...getRootProps()}
          className={cn(
            "relative h-32 w-32 cursor-pointer overflow-hidden rounded-full border-2 border-dashed transition-colors",
            isDragActive
              ? "border-primary bg-primary/10"
              : "border-border hover:border-primary",
            disabled && "cursor-not-allowed opacity-50"
          )}
        >
          <input {...getInputProps()} />
          {currentFile?.objectUrl ? (
            <img
              src={currentFile.objectUrl}
              alt="Avatar"
              className="h-full w-full object-cover"
            />
          ) : (
            <div className="flex h-full w-full items-center justify-center bg-muted">
              <ImageIcon className="h-8 w-8 text-muted-foreground" />
            </div>
          )}
          {currentFile?.uploading && (
            <div className="absolute inset-0 flex items-center justify-center bg-black/50">
              <div className="font-medium text-white">
                {currentFile.progress}%
              </div>
            </div>
          )}
        </div>
        {currentFile && (
          <Button
            size="icon"
            variant="destructive"
            className="absolute -top-2 -right-2 h-8 w-8 rounded-full"
            onClick={() => removeFile(currentFile.id)}
            disabled={currentFile.isDeleting || currentFile.uploading}
          >
            {currentFile.isDeleting ? (
              <Loader2 className="h-4 w-4 animate-spin" />
            ) : (
              <X className="h-4 w-4" />
            )}
          </Button>
        )}
      </div>
    );
  }

  if (variant === "minimal") {
    return (
      <div className={cn("space-y-2", className)}>
        <div {...getRootProps()}>
          <input {...getInputProps()} />
          <Button
            type="button"
            variant="outline"
            className="w-full"
            disabled={disabled}
          >
            <Upload className="mr-2 h-4 w-4" />
            Upload Files
          </Button>
        </div>
        {helperText && (
          <p className="text-xs text-muted-foreground">{helperText}</p>
        )}
        {files.length > 0 && (
          <div className="space-y-2">
            {files.map((file) => (
              <div
                key={file.id}
                className="flex items-center justify-between rounded-md border p-2"
              >
                <div className="flex min-w-0 flex-1 items-center gap-2">
                  <File className="h-4 w-4 flex-shrink-0 text-muted-foreground" />
                  <span className="truncate text-sm">{file.file.name}</span>
                  {file.uploading && (
                    <span className="text-xs text-muted-foreground">
                      {file.progress}%
                    </span>
                  )}
                </div>
                <Button
                  size="icon"
                  variant="ghost"
                  className="h-8 w-8 flex-shrink-0"
                  onClick={() => removeFile(file.id)}
                  disabled={file.isDeleting || file.uploading}
                >
                  {file.isDeleting ? (
                    <Loader2 className="h-3 w-3 animate-spin" />
                  ) : (
                    <Trash2 className="h-3 w-3" />
                  )}
                </Button>
              </div>
            ))}
          </div>
        )}
      </div>
    );
  }

  if (variant === "inline") {
    return (
      <div className={cn("flex items-center gap-2", className)}>
        <div {...getRootProps()} className="flex-1">
          <input {...getInputProps()} />
          <Button
            type="button"
            variant="outline"
            size="sm"
            className="w-full"
            disabled={disabled}
          >
            <Upload className="mr-2 h-3 w-3" />
            Choose File
          </Button>
        </div>
        {files.length > 0 && (
          <div className="flex items-center gap-2">
            <span className="max-w-[150px] truncate text-sm text-muted-foreground">
              {files[0].file.name}
            </span>
            <Button
              size="icon"
              variant="ghost"
              className="h-8 w-8"
              onClick={() => removeFile(files[0].id)}
              disabled={files[0].isDeleting || files[0].uploading}
            >
              {files[0].isDeleting ? (
                <Loader2 className="h-3 w-3 animate-spin" />
              ) : (
                <Trash2 className="h-3 w-3" />
              )}
            </Button>
          </div>
        )}
      </div>
    );
  }

  const isCompact = variant === "compact";

  return (
    <div className={cn("w-full", className)}>
      <Card
        {...getRootProps()}
        className={cn(
          "relative cursor-pointer border-2 border-dashed transition-colors duration-200 ease-in-out",
          isCompact ? "h-32" : "h-64",
          isDragActive
            ? "border-solid border-primary bg-primary/10"
            : "border-border hover:border-primary",
          disabled && "cursor-not-allowed opacity-50"
        )}
      >
        <CardContent className="flex h-full w-full items-center justify-center p-4">
          <input {...getInputProps()} />
          {isDragActive ? (
            <div className="flex flex-col items-center gap-2">
              <Upload className="h-8 w-8 text-[#283593]" />
              <p className="text-center text-sm">Drop the files here...</p>
            </div>
          ) : (
            <div className="flex flex-col items-center gap-3">
              <div className="flex gap-2">
                <ImageIcon className="h-6 w-6 text-muted-foreground" />
                <File className="h-6 w-6 text-muted-foreground" />
              </div>
              <p className="text-center text-sm text-muted-foreground">
                Drag & drop files here, or click to select
              </p>
              <Button size={isCompact ? "sm" : "default"} type="button">
                Select Files
              </Button>
              {helperText && (
                <p className="text-center text-xs text-muted-foreground">
                  {helperText}
                </p>
              )}
            </div>
          )}
        </CardContent>
      </Card>

      {files.length > 0 && (
        <div className="mt-6 grid grid-cols-2 gap-4 sm:grid-cols-3 md:grid-cols-4">
          {files.map(
            ({
              id,
              file,
              uploading,
              progress,
              isDeleting,
              error,
              objectUrl,
            }) => {
              const isImage = file.type.startsWith("image/");

              return (
                <div key={id} className="flex flex-col gap-1">
                  <div className="relative aspect-square overflow-hidden rounded-lg border">
                    {isImage ? (
                      <img
                        src={objectUrl}
                        alt={file.name}
                        className="h-full w-full object-cover"
                      />
                    ) : (
                      <div className="flex h-full w-full items-center justify-center bg-muted">
                        <File className="h-12 w-12 text-muted-foreground" />
                      </div>
                    )}

                    <Button
                      variant="destructive"
                      size="icon"
                      className="absolute top-2 right-2 h-6 w-6"
                      onClick={(e) => {
                        e.stopPropagation();
                        removeFile(id);
                      }}
                      disabled={isDeleting || uploading}
                      type="button"
                    >
                      {isDeleting ? (
                        <Loader2 className="h-3 w-3 animate-spin" />
                      ) : (
                        <Trash2 className="h-3 w-3" />
                      )}
                    </Button>

                    {uploading && !isDeleting && (
                      <div className="absolute inset-0 flex items-center justify-center bg-black/50">
                        <div className="text-lg font-medium text-white">
                          {progress}%
                        </div>
                      </div>
                    )}

                    {error && (
                      <div className="absolute inset-0 flex items-center justify-center bg-red-500/50">
                        <div className="font-medium text-white">Error</div>
                      </div>
                    )}
                  </div>
                  <p className="truncate px-1 text-xs text-muted-foreground">
                    {file.name}
                  </p>
                </div>
              );
            }
          )}
        </div>
      )}
    </div>
  );
}

// Cleanup hook on unmount
export function useDropzoneCleanup(files: FileWithMetadata[]) {
  useEffect(() => {
    return () => {
      files.forEach((file) => {
        if (file.objectUrl) {
          URL.revokeObjectURL(file.objectUrl);
        }
      });
    };
  }, [files]);
}

