export function useNotifications(
  filters: { page?: number; unreadOnly?: boolean } = {},
) {
  const params = new URLSearchParams();
  if (filters.page) params.set("page", String(filters.page));
  if (filters.unreadOnly) params.set("unreadOnly", "true");

  return useQuery({
    queryKey: queryKeys.notifications.all(filters),
    queryFn: async () => {
      const { data } = await apiClient.get(
        `/notifications?${params.toString()}`,
      );
      return data;
    },
    staleTime: 30 * 1000,
  });
}

export function useUnreadCount() {
  return useQuery({
    queryKey: queryKeys.notifications.unreadCount,
    queryFn: async () => {
      const { data } = await apiClient.get(
        "/notifications?unreadOnly=true&limit=1",
      );
      return data.unreadCount as number;
    },
    staleTime: 30 * 1000,
    refetchInterval: 60 * 1000, // fallback poll
  });
}

export function useMarkNotificationRead() {
  const queryClient = useQueryClient();

  return useMutation({
    mutationFn: async (id: string) => {
      await apiClient.patch(`/notifications/${id}/read`);
      return id;
    },
    onMutate: async (id) => {
      // Optimistic: mark as read in cache
      queryClient.setQueriesData(
        { queryKey: ["notifications"] },
        (old: any) => {
          if (!old?.data) return old;
          return {
            ...old,
            data: old.data.map((n: any) =>
              n.id === id ? { ...n, isRead: true } : n,
            ),
            unreadCount: Math.max(0, (old.unreadCount ?? 0) - 1),
          };
        },
      );
      queryClient.setQueryData<number>(
        queryKeys.notifications.unreadCount,
        (old = 0) => Math.max(0, old - 1),
      );
    },
    onError: (error) => {
      queryClient.invalidateQueries({ queryKey: ["notifications"] });
      toast.error("Failed to mark as read", {
        description: getErrorMessage(error),
      });
    },
  });
}

export function useMarkAllRead() {
  const queryClient = useQueryClient();

  return useMutation({
    mutationFn: async () => {
      await apiClient.patch("/notifications/read-all");
    },
    onMutate: () => {
      queryClient.setQueriesData(
        { queryKey: ["notifications"] },
        (old: any) => {
          if (!old?.data) return old;
          return {
            ...old,
            data: old.data.map((n: any) => ({ ...n, isRead: true })),
            unreadCount: 0,
          };
        },
      );
      queryClient.setQueryData(queryKeys.notifications.unreadCount, 0);
    },
    onSuccess: () => toast.success("All notifications marked as read"),
    onError: () => {
      queryClient.invalidateQueries({ queryKey: ["notifications"] });
      toast.error("Failed to mark all as read");
    },
  });
}

"use client";

import { useEffect, useRef, useState, useCallback } from "react";
import { io, Socket } from "socket.io-client";
import { useQueryClient } from "@tanstack/react-query";
import { queryKeys } from "@/lib/queryKeys";
import { toast } from "sonner";

const SOCKET_URL =
  process.env.NEXT_PUBLIC_SOCKET_URL || "http://localhost:3000";

interface OnlineUser {
  userId: string;
  name: string;
  role: string;
  online: boolean;
}

export function useSocket() {
  const socketRef = useRef<Socket | null>(null);
  const [isConnected, setIsConnected] = useState(false);
  const [onlineUsers, setOnlineUsers] = useState<Map<string, OnlineUser>>(
    new Map(),
  );
  const queryClient = useQueryClient();

  useEffect(() => {
    const socket = io(SOCKET_URL, {
      withCredentials: true,
      transports: ["websocket", "polling"],
      reconnectionAttempts: 5,
      reconnectionDelay: 2000,
    });

    socketRef.current = socket;

    socket.on("connect", () => setIsConnected(true));
    socket.on("disconnect", () => setIsConnected(false));

    // ── Notifications ─────────────────────────
    socket.on("notification:new", (notification) => {
      // Update notifications cache directly
      queryClient.setQueryData<any>(
        queryKeys.notifications.all(),
        (old: any) => {
          if (!old) return old;
          return {
            ...old,
            pages: old.pages?.map((page: any, i: number) =>
              i === 0
                ? {
                    ...page,
                    data: [notification, ...page.data],
                    unreadCount: (page.unreadCount ?? 0) + 1,
                  }
                : page,
            ),
          };
        },
      );

      // Increment unread badge
      queryClient.setQueryData<number>(
        queryKeys.notifications.unreadCount,
        (old = 0) => old + 1,
      );

      // Show toast for high-priority notifications
      if (notification.type === "LIVE_LECTURE") {
        toast("🔴 Live Lecture Started!", {
          description: notification.body,
          duration: 8000,
          action: {
            label: "Join Now",
            onClick: () => {
              if (notification.metadata?.meetingUrl) {
                window.open(notification.metadata.meetingUrl, "_blank");
              }
            },
          },
        });
      } else if (notification.type === "ASSIGNMENT_POSTED") {
        toast("📋 New Assignment", {
          description: notification.body,
          duration: 5000,
        });
      }
    });

    // ── Messages ──────────────────────────────
    socket.on("message:new", (message) => {
      const partnerId = message.senderId;

      // Add to thread cache
      queryClient.setQueryData<any>(
        queryKeys.messages.thread(partnerId),
        (old: any) => {
          if (!old) return old;
          const lastPage = old.pages[old.pages.length - 1];
          return {
            ...old,
            pages: [
              ...old.pages.slice(0, -1),
              { ...lastPage, data: [...lastPage.data, message] },
            ],
          };
        },
      );

      // Refresh conversations list
      queryClient.invalidateQueries({
        queryKey: queryKeys.messages.conversations,
      });

      // Increment unread badge
      queryClient.setQueryData<number>(
        queryKeys.notifications.unreadCount,
        (old = 0) => old + 1,
      );
    });

    // ── Live Lecture ──────────────────────────
    socket.on("lecture:started", (data) => {
      queryClient.setQueryData(
        queryKeys.liveLecture.byCourse(data.courseId),
        data,
      );
    });

    socket.on("lecture:ended", (data) => {
      queryClient.setQueryData(
        queryKeys.liveLecture.byCourse(data.courseId),
        null,
      );
    });

    // ── Assignment posted ─────────────────────
    socket.on("assignment:posted", () => {
      // Invalidate relevant queries
      queryClient.invalidateQueries({ queryKey: ["assignments"] });
    });

    // ── Online users (admin) ──────────────────
    socket.on("user:status", (data: OnlineUser) => {
      setOnlineUsers((prev) => {
        const next = new Map(prev);
        if (data.online) {
          next.set(data.userId, data);
        } else {
          next.delete(data.userId);
        }
        return next;
      });
    });

    // ── Account suspended ─────────────────────
    socket.on("account:suspended", (data: { reason: string }) => {
      toast.error("Account Suspended", {
        description: data.reason || "Your account has been suspended.",
        duration: Infinity,
      });
      setTimeout(() => {
        window.location.href = "/login?suspended=true";
      }, 3000);
    });

    return () => {
      socket.disconnect();
      socketRef.current = null;
    };
  }, [queryClient]);

  // Actions
  const joinCourse = useCallback((courseId: string) => {
    socketRef.current?.emit("course:join", { courseId });
  }, []);

  const leaveCourse = useCallback((courseId: string) => {
    socketRef.current?.emit("course:leave", { courseId });
  }, []);

  const sendTypingStart = useCallback((receiverId: string) => {
    socketRef.current?.emit("typing:start", { receiverId });
  }, []);

  const sendTypingStop = useCallback((receiverId: string) => {
    socketRef.current?.emit("typing:stop", { receiverId });
  }, []);

  return {
    socket: socketRef.current,
    isConnected,
    onlineUsers,
    joinCourse,
    leaveCourse,
    sendTypingStart,
    sendTypingStop,
  };
}

// Typing indicator hook
export function useTypingIndicator(
  partnerId: string,
  sendTypingStart: (id: string) => void,
  sendTypingStop: (id: string) => void,
) {
  const typingTimeout = useRef<NodeJS.Timeout | null>(null);

  const onType = useCallback(() => {
    sendTypingStart(partnerId);
    if (typingTimeout.current) {
      clearTimeout(typingTimeout.current);
    }
    typingTimeout.current = setTimeout(() => sendTypingStop(partnerId), 2000);
  }, [partnerId, sendTypingStart, sendTypingStop]);

  useEffect(() => {
    return () => {
      if (typingTimeout.current) {
        clearTimeout(typingTimeout.current);
      }
    };
  }, []);

  return { onType };
}

import { auth } from "@/lib/auth";
import { headers } from "next/headers";
import { NextResponse } from "next/server";
import { ZodSchema } from "zod";
import { UserRole, UserStatus } from "@/lib/generated/prisma";

export async function getSession() {
  return auth.api.getSession({ headers: await headers() });
}

export async function requireAuth(allowedRoles?: UserRole[]) {
  const session = await getSession();
  if (!session) {
    return {
      error: NextResponse.json({ error: "Unauthorized" }, { status: 401 }),
      session: null,
    };
  }
  const user = session.user as any;
  if (user.status === UserStatus.SUSPENDED) {
    return {
      error: NextResponse.json({ error: "Account suspended" }, { status: 403 }),
      session: null,
    };
  }
  if (allowedRoles && !allowedRoles.includes(user.role)) {
    return {
      error: NextResponse.json({ error: "Forbidden" }, { status: 403 }),
      session: null,
    };
  }
  return { error: null, session };
}

export async function validateBody<T>(
  req: Request,
  schema: ZodSchema<T>,
): Promise<{ data: T } | { validationError: NextResponse }> {
  const body = await req.json().catch(() => ({}));
  const result = schema.safeParse(body);
  if (!result.success) {
    return {
      validationError: NextResponse.json(
        {
          error: "Validation failed",
          issues: result.error.flatten().fieldErrors,
        },
        { status: 422 },
      ),
    };
  }
  return { data: result.data };
}

export function generateTempPassword(length = 10): string {
  const chars = "ABCDEFGHJKLMNPQRSTUVWXYZabcdefghjkmnpqrstuvwxyz23456789";
  return Array.from(crypto.getRandomValues(new Uint32Array(length)))
    .map((x) => chars[x % chars.length])
    .join("");
}

